describe('sway-motion 姣忓抚閽╁瓙', () => {
    beforeEach(resetAll);

    it('enable 鍚庢敞鍐屽抚閽╁瓙锛泀uarter 鍛ㄦ湡鍐欏叆宄板€?yaw', () => {
        const m = makeModel('sway-q');
        data.mockModelRegistry.set('sway-q', m);
        const sway = createSwayMotionModule('sway-q');
        sway.enable();

        // 閽╁瓙宸叉敞鍐孿n        expect(data.registerFrameHookSpy).toHaveBeenCalledTimes(1);
        // bake 鍒濆鍐欏叆闈欐€佸嘲鍊硷紙amplitude=5锛夛紝娓呯┖鍚庡崟鐙獙璇侀挬瀛愭晥鏋淺n        data.setBoneOverrideSpy.mockClear();

        const hook = data.frameHooks[0];
        const freq = 0.5;
        const t = 0.25 / freq; // quarter 鍛ㄦ湡 鈫?sin=1
        hook(t, 'sway-q');

        // yaw = 5*(1-0.3)*1 = 3.5
        expect(data.setBoneOverrideSpy).toHaveBeenCalledWith(
            '銈汇兂銈裤兗',
            [0, 3.5, 0],
            1,
            true,
            'sway-q'
        );
    });

    it('frequency/decay 鏀瑰彉鐢遍挬瀛愬疄鏃跺弽鏄狅紙t=0 鈫?yaw=0锛?, () => {
        const m = makeModel('sway-t0');
        data.mockModelRegistry.set('sway-t0', m);
        const sway = createSwayMotionModule('sway-t0');
        sway.enable();
        data.setBoneOverrideSpy.mockClear();

        data.frameHooks[0](0, 'sway-t0');
        expect(data.setBoneOverrideSpy).toHaveBeenCalledWith(
            '銈汇兂銈裤兗',
            [0, 0, 0],
            1,
            true,
            'sway-t0'
        );
    });

    it('position-offset 鍗犵敤 銈汇兂銈裤兗 鏃?sway 璁╀綅锛堥挬瀛愪笉鍐欏叆锛屼笉浜夋姠锛?, () => {
        const m = makeModel('sway-yield');
        data.mockModelRegistry.set('sway-yield', m);
        // 鍏堝惎鐢?position-offset锛堜紭鍏堢骇 1锛屾姠鍗?銈汇兂銈裤兗锛塡n        const pos = createPositionOffsetModule('sway-yield');
        pos.enable();
        data.frameHooks.length = 0; // 娓呮帀鏃犲叧閽╁瓙锛坧osition-offset 鏃犻挬瀛愶紝鏈氨绌猴級

        const sway = createSwayMotionModule('sway-yield');
        sway.enable(); // 浠嶄細娉ㄥ唽閽╁瓙锛屼絾 should yield
        data.setBoneOverrideSpy.mockClear();

        // 璋冪敤 sway 閽╁瓙锛屽簲璁╀綅锛坕sBoneOwnedByOther 鍛戒腑锛塡n        data.frameHooks[0](0.5, 'sway-yield');

        // 涓嶅簲鍐欏叆 銈汇兂銈裤兗锛堣浣嶏級
        const wroteCenter = data.setBoneOverrideSpy.mock.calls.some((c) => c[0] === '銈汇兂銈裤兗');
        expect(wroteCenter).toBe(false);
    });
});

