/**
 * 瀹夊叏閲婃斁瀵硅薄骞剁疆绌恒€俓n * @param obj 寰呴噴鏀惧璞★紙鍙负 null锛塡n * @param args 閫忎紶缁?`obj.dispose(...args)` 鐨勫弬鏁帮紙濡?mesh.dispose(true) 鐨?recursive锛塡n * @returns null锛堣皟鐢ㄦ柟搴斿皢鍘熷紩鐢ㄨ祴鍊间负姝よ繑鍥炲€间互瀹屾垚缃┖锛塡n */
export function safeDispose<T extends { dispose(...args: any[]): void }>(
    obj: T | null,
    ...args: any[]
): null {
    obj?.dispose(...args);
    return null;
}

