// handler 浠?any 鎺ユ敹锛歸rapper 鏃犳硶澶嶅埢 DOM addEventListener 鐨勪簨浠跺悕閲嶈浇
// 锛坘eyof WindowEventMap锛夛紝闆嗕腑璞佸厤鍗曠偣锛岄伩鍏嶇粰 17 澶勮皟鐢ㄩ€愪竴琛ヤ簨浠剁被鍨嬫敞瑙ｃ€俓nfunction _reg(
    target: EventTarget,
    event: string,
    handler: (evt: any) => void,
    options?: AddEventListenerOptions
): void {
    _eventDisposables.push(addDisposableListener(target, event, handler, options));
}
export function disposeEventHandlers(): void {
    for (const d of _eventDisposables) {
        d.dispose();
    }
    _eventDisposables.length = 0;
    // 娓呯悊鍙兘娈嬬暀鐨勯暱鎸夊畾鏃跺櫒
