// ======== Register all DOM/window event listeners ========
export function registerEventHandlers(): void {
    // Play/Pause 鈥?only toggles play state, does NOT touch autoLoop
    _reg(dom.btnPlayPause, 'click', async () => {
        if (!mmdRuntime) {
            return;
        }
        if (isPlaying) {
            mmdRuntime.pauseAnimation();
            setIsPlaying(false);
        } else {
            await mmdRuntime.playAnimation();
            setIsPlaying(true);
        }
        updatePlaybackUI();
    });

    // Loop toggle
    _reg(dom.btnLoopToggle, 'click', () => {
        setAutoLoop(!autoLoop);
        updatePlaybackUI();
        setStatus(t('status.loop', { state: autoLoop ? t('common.on') : t('common.off') }), true);
    });

    // ======== Ctrl shortcuts hint ========
    _reg(window, 'keydown', (e) => {
        if (e.key === 'Control' && !e.repeat) {
            document.body.classList.add('shortcuts-visible');
        }
    });
    _reg(window, 'keyup', (e) => {
        if (e.key === 'Control') {
            document.body.classList.remove('shortcuts-visible');
        }
    });
    _reg(window, 'blur', () => document.body.classList.remove('shortcuts-visible'));

    // ======== Freefly WASD (only respond in freefly mode) ========
    _reg(window, 'keydown', (e) => {
        if (getCameraMode() === 'freefly') {
            if (e.code === 'KeyW') {
                freeflyInput.forward = true;
                e.preventDefault();
            } else if (e.code === 'KeyS') {
                freeflyInput.backward = true;
                e.preventDefault();
            } else if (e.code === 'KeyA') {
                freeflyInput.left = true;
                e.preventDefault();
            } else if (e.code === 'KeyD') {
                freeflyInput.right = true;
                e.preventDefault();
            } else if (e.code === 'KeyQ') {
                freeflyInput.up = true;
                e.preventDefault();
            } else if (e.code === 'KeyE') {
                freeflyInput.down = true;
                e.preventDefault();
            }
        }
    });

    // Freefly WASD release
    _reg(window, 'keyup', (e) => {
        if (getCameraMode() !== 'freefly') {
            return;
        }
        const t = e.target as HTMLElement;
        if (t && (t.tagName === 'INPUT' || t.tagName === 'TEXTAREA' || t.isContentEditable)) {
            return;
        }
        if (e.code === 'KeyW') {
            freeflyInput.forward = false;
            e.preventDefault();
        } else if (e.code === 'KeyS') {
            freeflyInput.backward = false;
            e.preventDefault();
        } else if (e.code === 'KeyA') {
            freeflyInput.left = false;
            e.preventDefault();
        } else if (e.code === 'KeyD') {
            freeflyInput.right = false;
            e.preventDefault();
        } else if (e.code === 'KeyQ') {
            freeflyInput.up = false;
            e.preventDefault();
        } else if (e.code === 'KeyE') {
            freeflyInput.down = false;
            e.preventDefault();
        }
    });

    // ======== ADR-153: 3D camera keyboard orbit (canvas focused) ========
    _reg(window, 'keydown', (e) => {
        if (document.activeElement !== dom.canvas) {
            return;
        }
        const t = e.target as HTMLElement;
        if (t && (t.tagName === 'INPUT' || t.tagName === 'TEXTAREA' || t.isContentEditable)) {
            return;
        }
        const cam = getCurrentCamera();
        if (!cam || !(cam instanceof ArcRotateCamera)) {
            return;
        }
        const shift = e.shiftKey ? 3 : 1;
        const yawStep = ((5 * Math.PI) / 180) * shift; // 5掳 per press
        const pitchStep = ((5 * Math.PI) / 180) * shift;
        const zoomFactor = shift > 1 ? 0.7 : 0.9; // 30% vs 10% per press

        switch (e.code) {
            case 'ArrowLeft':
                cam.alpha -= yawStep;
                e.preventDefault();
                break;
            case 'ArrowRight':
                cam.alpha += yawStep;
                e.preventDefault();
                break;
            case 'ArrowUp':
                cam.beta = clamp(cam.beta - pitchStep, 0.1, Math.PI - 0.1);
                e.preventDefault();
                break;
            case 'ArrowDown':
                cam.beta = clamp(cam.beta + pitchStep, 0.1, Math.PI - 0.1);
                e.preventDefault();
                break;
            case 'Equal':
            case 'NumpadAdd':
                cam.radius *= zoomFactor;
                e.preventDefault();
                break;
            case 'Minus':
            case 'NumpadSubtract':
                cam.radius /= zoomFactor;
                e.preventDefault();
                break;
        }
    });

    // Seek bar
    _reg(dom.seekBar, 'pointerdown', (e) => {
        setSeekDragging(true);
        seekWasPlaying = isPlaying;
        if (isPlaying && mmdRuntime) {
            mmdRuntime.pauseAnimation();
            setIsPlaying(false);
        }
        seekFromEvent(e);
        dom.seekBar.setPointerCapture(e.pointerId);
    });
    _reg(window, 'pointermove', (e) => {
        if (seekDragging) {
            seekFromEvent(e);
        }
    });
    _reg(window, 'pointerup', async () => {
        if (!seekDragging) {
            return;
        }
        setSeekDragging(false);
        if (seekWasPlaying && mmdRuntime && focusedMmdModel()) {
            await mmdRuntime.playAnimation();
            setIsPlaying(true);
            updatePlaybackUI();
        }
    });

    // ======== Click canvas to toggle overlays ========
    _reg(window, 'pointerdown', (e) => {
        _pointerDownPos = { x: e.clientX, y: e.clientY };
        // 闀挎寜妫€娴嬶細500ms 鍚庡脊鍑烘ā鍨嬮潰鏉縗n        _longPressTimer = setTimeout(() => {
            if (!dom.canvas.contains(e.target as Node)) {
                return;
            }
            const id = focusedModelId;
            if (!id) {
                return;
            }
            // 鎵撳紑妯″瀷寮圭獥骞?push 妯″瀷灞傜骇
            showModelPopup();
            import('../menus/model-detail').then(({ buildModelLevel }) => {
                if (stackRegistry?.modelStack) {
                    stackRegistry.modelStack.push(buildModelLevel(id));
                }
            });
            _longPressTimer = null;
        }, 500);
    });

    _reg(window, 'pointerup', (e) => {
        if (_longPressTimer) {
            clearTimeout(_longPressTimer);
            _longPressTimer = null;
        }
        const dx = e.clientX - _pointerDownPos.x;
        const dy = e.clientY - _pointerDownPos.y;
        if (Math.sqrt(dx * dx + dy * dy) > 5) {
            return;
        }

        // Only toggle when clicking on the 3D canvas
        if (!dom.canvas.contains(e.target as Node)) {
            return;
        }

        // 鍙屽嚮鑱氱劍锛?00ms 鍐呬袱娆＄偣鍑诲悓涓€浣嶇疆 鈫?鑷姩鏋勫浘鑱氱劍妯″瀷
        const now = Date.now();
        if (now - _lastTapTime < 300 && focusedModelId) {
            focusModel(focusedModelId);
            _lastTapTime = 0;
            return;
        }
        _lastTapTime = now;

        _toggleOverlays();
    });

    _reg(window, 'pointermove', (e) => {
        if (_longPressTimer) {
            const dx = e.clientX - _pointerDownPos.x;
            const dy = e.clientY - _pointerDownPos.y;
            if (Math.sqrt(dx * dx + dy * dy) > 10) {
                clearTimeout(_longPressTimer);
                _longPressTimer = null;
            }
        }
    });
}

// ======== Build nav shortcut maps ========
export function buildNavMaps(): void {
    const shortcuts = getAllShortcuts();
    document.querySelectorAll<HTMLElement>('[data-shortcut]').forEach((el) => {
        const key = el.dataset.shortcut || '';
        const k = parseInt(key, 10);
        if (k >= 1 && k <= 9) {
            navLabels[k] = el.title || '';
        }
        // Sync badge text from data-shortcut
        const badge = el.querySelector<HTMLElement>('.shortcut-badge');
        if (badge) {
            badge.textContent = key;
        }
        // Sync data-hint shortcut suffix from data-shortcut
        const hint = el.getAttribute('data-hint');
        if (hint) {
            const clean = hint.replace(/\s*路\s*Ctrl\+\d+$/, '');
            el.setAttribute('data-hint', `${clean} 路 Ctrl+${key}`);
        }
        // ADR-153: aria-keyshortcuts for screen readers
        const shortcutId = `toggle:${el.dataset.popupType || ''}`;
        const def = shortcuts.find((s) => s.id === shortcutId);
        if (def) {
            el.setAttribute('aria-keyshortcuts', getAriaKeyshortcuts(def));
        }
    });
}

// ======== Update Notification ========
export function showUpdateToast(latest: string, url: string): void {
    const toast = document.getElementById('updateToast');
    if (!toast) {
        return;
    }
    const fileEl = toast.querySelector<HTMLElement>('.toast-file');
    if (fileEl) {
        fileEl.textContent = t('main.versionAvailable', { version: latest });
    }
    const btn = toast.querySelector<HTMLButtonElement>('.toast-import-btn');
    if (btn) {
        btn.onclick = () => {
            if (!openExternalURL(url)) {
                Browser.OpenURL(url);
            }
            toast.classList.remove('visible');
        };
    }
    const ignoreBtn = toast.querySelector<HTMLButtonElement>('.toast-ignore-btn');
    if (ignoreBtn) {
        ignoreBtn.onclick = () => toast.classList.remove('visible');
    }
    toast.classList.add('visible');
}

// ======== Drag & Drop Import ========
function hideDropOverlay(): void {
    document.getElementById('dropOverlay')!.classList.remove('visible');
}

async function handleDropFile(path: string): Promise<void> {
    const lower = path.toLowerCase();
    if (lower.endsWith('.zip')) {
        setStatus(t('main.importingZip'), false);
        try {
            await ImportZip(path);
            setStatus(t('main.zipImported'), true);
            await safeCallAsync('events', 'refresh after drop', () => refreshLibrary());
        } catch (err) {
            setStatus(t('main.importFailedDetail') + formatError(err), false);
            console.error('ImportZip failed:', err);
        }
    } else if (lower.endsWith('.pmx')) {
        setStatus(t('main.loadingModel'), false);
        try {
            await loadManager.load({ kind: 'actor', path });
        } catch (err) {
            setStatus(t('main.modelLoadFailed') + formatError(err), false);
            console.error('loadManager actor failed:', err);
        }
    } else if (lower.endsWith('.vmd')) {
        setStatus(t('main.loadingMotion'), false);
        try {
            await loadManager.load({ kind: 'vmd', path });
        } catch (err) {
            setStatus(t('main.vmdLoadFailed') + formatError(err), false);
            console.error('loadManager vmd failed:', err);
        }
    }
}

export function initDropHandler(): void {
    let dragCounter = 0;
    _reg(window, 'dragenter', (e) => {
        e.preventDefault();
        dragCounter++;
        if (dragCounter === 1) {
            document.getElementById('dropOverlay')!.classList.add('visible');
        }
    });
    _reg(window, 'dragleave', (e) => {
        e.preventDefault();
        dragCounter--;
        if (dragCounter <= 0) {
            dragCounter = 0;
            hideDropOverlay();
        }
    });
    _reg(window, 'dragover', (e) => e.preventDefault());
    _reg(window, 'drop', async (e) => {
        e.preventDefault();
        hideDropOverlay();
        // Wails v2 used to provide file.path on dropped files
        // Wails v3 may need different handling - check documentation
        // For now, log the files to see what's available
        if (e.dataTransfer?.files) {
            for (const file of Array.from(e.dataTransfer.files)) {
                // @ts-ignore - Wails v2 provided path property, may need v3-specific handling
                const path = file.path || file.name;
                await handleDropFile(path);
            }
        }
    });
}

