// ======== Bootstrap ========
// Wires dev-hooks / render-loop / events modules and starts the app.
export function bootstrap(): void {
    // Initialize hover hints for static [data-hint] elements
    initHints();
    setupE2ECapture();
    startRenderLoop();

    // Boot the app, then on Android prompt for storage permission if needed.
    init()
        .then(() => {
            // Small delay so the main UI is ready before the permission dialog.
            setTimeout(checkAndroidStoragePermission, 1500);
        })
        .catch(console.error);
}

// observer-handle.ts 鈥?缁熶竴 Observer 鐢熷懡鍛ㄦ湡绠＄悊
//
// 灏佽 Babylon.js Observable.add/remove锛岀‘淇濓細
// 1. 姣忔 add 閮借繑鍥炰竴涓彲 dispose 鐨勫彞鏌刓n// 2. 鏀寔鎵归噺娓呯悊锛圤bserverRegistry锛塡n// 3. 骞傜瓑 dispose锛堥噸澶嶈皟鐢ㄥ畨鍏級
// 4. 涓嶅啀闇€瑕佹墜鍔ㄥ湪 metadata 涓瓨鍌?observer 寮曠敤
//
// 鐢ㄦ硶锛歕n//   import { observe, observeOnce, ObserverRegistry } from '@/core/observer-handle';
//
//   // 鍗曚釜 observer
//   const h = observe(scene.onBeforeRenderObservable, () => { ... });
//   h.dispose(); // 绉婚櫎 observer
//
//   // 鎵归噺绠＄悊
//   const reg = new ObserverRegistry();
//   reg.add(scene.onBeforeRenderObservable, () => { ... });
//   reg.add(scene.onAfterRenderObservable, () => { ... });
//   reg.disposeAll(); // 涓€娆℃€ф竻鐞嗘墍鏈塡n
import { Observable, Observer } from '@babylonjs/core/Misc/observable';

// ======== ObserverHandle ========

/**
 * 鍙噴鏀剧殑 Observer 鍙ユ焺銆俓n * 璋冪敤 dispose() 浠?Observable 涓Щ闄ゅ搴旂殑 observer銆俓n * 骞傜瓑锛氶噸澶嶈皟鐢?dispose() 瀹夊叏銆俓n */
export class ObserverHandle {
    private _observable: Observable<any> | null;
    private _observer: Observer<any> | null;

    constructor(observable: Observable<any>, observer: Observer<any>) {
        this._observable = observable;
        this._observer = observer;
    }

    /** 浠?Observable 涓Щ闄?observer锛岀劧鍚庨噴鏀惧紩鐢ㄣ€傚箓绛夈€?*/
    dispose(): void {
        if (this._observable && this._observer) {
            this._observable.remove(this._observer);
        }
        this._observable = null;
        this._observer = null;
    }

    get isDisposed(): boolean {
        return this._observer === null;
    }
}

// ======== 渚垮埄鍑芥暟 ========

/**
 * 璁㈤槄 Observable 骞惰繑鍥炶嚜鍔ㄧ鐞嗙殑鍙ユ焺銆俓n * 绛変环浜?observable.add(callback)锛屼絾杩斿洖鍊兼槸 ObserverHandle 鑰岄潪 Observer銆俓n */
export function observe<T>(
    observable: Observable<T>,
    callback: (eventData: T, eventState: any) => void
): ObserverHandle {
    const observer = observable.add(callback);
    if (!observer) {
        throw new Error('ObserverHandle: observable.add() returned null');
    }
    return new ObserverHandle(observable, observer);
}

/**
 * 涓€娆℃€ц闃咃細鍥炶皟鎵ц鍚庤嚜鍔ㄧЩ闄わ紝绛変环浜?observable.addOnce()銆俓n */
export function observeOnce<T>(
    observable: Observable<T>,
    callback: (eventData: T, eventState: any) => void
): ObserverHandle {
    const observer = observable.addOnce(callback);
    if (!observer) {
        throw new Error('ObserverHandle: observable.addOnce() returned null');
    }
    return new ObserverHandle(observable, observer);
}

// ======== ObserverRegistry ========

/**
 * 绠＄悊鍣細鏀堕泦澶氫釜 ObserverHandle锛屾敮鎸佷竴娆℃€?disposeAll()銆俓n * 閫傚悎妯″潡鏈夊涓?observer 闇€瑕佺粺涓€娓呯悊鐨勫満鏅€俓n */
export class ObserverRegistry {
    private _handles: ObserverHandle[] = [];

    /** 璁㈤槄骞舵敞鍐岋紝杩斿洖鍙ユ焺銆?*/
    add<T>(
        observable: Observable<T>,
        callback: (eventData: T, eventState: any) => void
    ): ObserverHandle {
        const handle = observe(observable, callback);
        this._handles.push(handle);
        return handle;
    }

    /** 娉ㄥ唽涓€涓凡鏈夌殑鍙ユ焺銆?*/
    register(handle: ObserverHandle): void {
        this._handles.push(handle);
    }

    /** 浠庢敞鍐岃〃涓Щ闄ゆ寚瀹氬彞鏌勫苟 dispose銆傝繑鍥?true 琛ㄧず鎵惧埌骞剁Щ闄ゃ€?*/
    remove(handle: ObserverHandle): boolean {
        const idx = this._handles.indexOf(handle);
        if (idx === -1) {
            return false;
        }
        this._handles.splice(idx, 1);
        handle.dispose();
        return true;
    }

    /** 涓€娆℃€ф竻鐞嗘墍鏈夋敞鍐岀殑 observer銆傚箓绛夈€?*/
    disposeAll(): void {
        for (const h of this._handles) {
            h.dispose();
        }
        this._handles.length = 0;
    }

    /** 褰撳墠绠＄悊鐨?observer 鏁伴噺銆?*/
    get size(): number {
        return this._handles.length;
    }

    /** 閲婃斁鎵€鏈夊彞鏌勫苟娓呯┖锛堝悓 disposeAll锛夈€?*/
    clear(): void {
        this.disposeAll();
    }
}

