                }
                mmdRuntime.seekAnimation(Math.min(dur, mmdRuntime.currentTime + 5), true);
                updatePlaybackUI();
            },
            group: 'shortcuts.group.playbackControl',
        },
        {
            id: 'screenshot:current',
            label: 'shortcuts.label.screenshot',
            defaultKey: 'F6',
            defaultCtrl: true,
            prevent: true,
            handler: () => void screenshotCurrent(),
            group: 'shortcuts.group.screenshot',
        },
        // [doc:adr-125 P2] 妯″潡灞傛挙閿€/閲嶅仛
        {
            id: 'motion:undo',
            label: 'shortcuts.label.motionUndo',
            defaultKey: 'KeyZ',
            defaultCtrl: true,
            prevent: true,
            handler: () => {
                const modelId = focusedModelId;
                if (modelId && canUndo(modelId)) {
                    undo(modelId, (snap) => applyModuleSnapshot(modelId, snap));
                    setStatus(t('motion.undoApplied'), true);
                    return;
                }
                // 鏃?motion 鎾ら攢鏃讹紝灏濊瘯鍦烘櫙绾ф挙閿€锛圕trl+Z 鍏奸【鍏ㄥ眬锛塡n                const snap = popUndoSnapshot();
                if (snap) {
                    void restoreUndoSnapshot(snap).then((ok) => {
                        if (ok) {
                            setStatus(t('scene.undoApplied'), true);
                        }
                    });
                }
            },
            group: 'shortcuts.group.motionUndoRedo',
        },
        {
            id: 'motion:redo',
            label: 'shortcuts.label.motionRedo',
            defaultKey: 'KeyZ',
            defaultCtrl: true,
            defaultShift: true,
            prevent: true,
            handler: () => {
                const modelId = focusedModelId;
                if (!modelId || !canRedo(modelId)) {
                    return;
                }
                redo(modelId, (snap) => applyModuleSnapshot(modelId, snap));
                setStatus(t('motion.override.redoApplied'), true);
            },
            group: 'shortcuts.group.motionUndoRedo',
        },
    ]);
}

// [doc:architecture] ui-advanced-rows 鈥?楂樼骇鑿滃崟琛屾帶浠讹紙color-slider / mode-slider锛塡n// addColorSliderRow / addModeSlider

import { createIconifyIcon } from './icons';
import { ControlOptions } from './ui-types';
import { initControl } from './ui-rows';
import { clampPct } from '@/core/utils';
import { col3FromTriple, rgbString } from './color-helpers';
import { DragSliderController } from './ui-slider-controller';

// ===================================================================
// addColorSliderRow
// ===================================================================

export function addColorSliderRow(
    container: HTMLElement,
    label: string,
    color: [number, number, number],
    onChange: (v: [number, number, number]) => void,
    opts?: ControlOptions<[number, number, number]>,
    testId?: string
): void {
    const block = document.createElement('div');
    block.className = 'clr-block';
    if (testId) {
        block.setAttribute('data-testid', testId);
    }
    const header = document.createElement('div');
    header.className = 'clr-header';
    const title = document.createElement('span');
    title.className = 'clr-title';
    title.textContent = label;
    title.id = `color-${Math.random().toString(36).slice(2, 11)}`;
    header.appendChild(title);
    const swatch = document.createElement('span');
    swatch.className = 'clr-swatch';
    swatch.style.background = rgbString(col3FromTriple(color));
    header.appendChild(swatch);
    block.appendChild(header);
    const channelColors = ['#f66', '#6f6', '#66f'];
    const current: [number, number, number] = [color[0], color[1], color[2]];
    const controllers: DragSliderController[] = [];

    for (let ci = 0; ci < 3; ci++) {
        const sub = document.createElement('div');
        sub.className = 'clr-row';
        const ch = document.createElement('span');
        ch.className = 'clr-channel';
        ch.style.color = channelColors[ci];
        ch.textContent = ['R', 'G', 'B'][ci];
        ch.id = `${title.id}-ch${ci}`;
        sub.appendChild(ch);

        const val = document.createElement('span');
        val.className = 'clr-value';
        val.textContent = color[ci].toFixed(2);

        const bar = document.createElement('div');
        bar.className = 'cs-bar';
        bar.tabIndex = 0;
        bar.setAttribute('role', 'slider');
        bar.setAttribute('aria-label', `${label} ${['Red', 'Green', 'Blue'][ci]} channel`);
        bar.setAttribute('aria-valuemin', '0');
        bar.setAttribute('aria-valuemax', '1');
        bar.setAttribute('aria-valuenow', String(color[ci]));
        bar.setAttribute('aria-labelledby', ch.id);

        const fill = document.createElement('div');
        fill.className = 'cs-fill';
        fill.style.background = channelColors[ci];
        fill.style.width = color[ci] * 100 + '%';

        const thumb = document.createElement('div');
        thumb.className = 'cs-thumb';
        thumb.style.left = color[ci] * 100 + '%';

        bar.appendChild(fill);
        bar.appendChild(thumb);

        function updateDisplay(v: number): void {
            current[ci] = v;
            val.textContent = v.toFixed(2);
            fill.style.width = v * 100 + '%';
            thumb.style.left = v * 100 + '%';
            bar.setAttribute('aria-valuenow', String(v));
            swatch.style.background = rgbString(col3FromTriple(current));
            onChange([current[0], current[1], current[2]]);
        }

        const controller = new DragSliderController({
            value: color[ci],
            min: 0,
            max: 1,
            step: 0.01,
            onChange: (v) => updateDisplay(v),
        });
        controller.bind(bar);
        controllers[ci] = controller;

        sub.appendChild(bar);
        sub.appendChild(val);
        block.appendChild(sub);
    }
    container.appendChild(block);

    // === 鑷洿鏂版敮鎸?===
    if (opts) {
        const vals: HTMLElement[] = [];
        const fills: HTMLElement[] = [];
        const thumbs: HTMLElement[] = [];
        const bars: HTMLElement[] = [];
        const clrRows = block.querySelectorAll('.clr-row');
        clrRows.forEach((row, i) => {
            vals[i] = row.querySelector('.clr-value') as HTMLElement;
            fills[i] = row.querySelector('.cs-fill') as HTMLElement;
            thumbs[i] = row.querySelector('.cs-thumb') as HTMLElement;
            bars[i] = row.querySelector('.cs-bar') as HTMLElement;
        });
        initControl(block, opts, [color[0], color[1], color[2]], (v, cached) => {
            if (!Array.isArray(v) || v.length < 3) {
                return false;
            }
            let changed = false;
            for (let i = 0; i < 3; i++) {
                if (v[i] !== cached[i]) {
                    changed = true;
                    current[i] = v[i];
                    vals[i].textContent = v[i].toFixed(2);
                    fills[i].style.width = v[i] * 100 + '%';
                    thumbs[i].style.left = v[i] * 100 + '%';
                    bars[i].setAttribute('aria-valuenow', String(v[i]));
                    controllers[i].setValue(v[i]);
                }
            }
            if (changed) {
                swatch.style.background = rgbString(col3FromTriple(v));
            }
            return changed;
        });
    }
}

// ===================================================================
// addVector3SliderRow 鈥?涓夌淮鍚戦噺婊戝潡锛圶/Y/Z 涓夐€氶亾锛塡n// ===================================================================

export function addVector3SliderRow(
    container: HTMLElement,
    label: string,
    value: [number, number, number],
    min: number,
    max: number,
    step: number,
    onChange: (v: [number, number, number]) => void,
    axisLabels?: [string, string, string],
    icon?: string,
    onDragEndCb?: (v: [number, number, number]) => void,
    opts?: ControlOptions<[number, number, number]>,
    testId?: string
): void {
    const axes: [string, string, string] = axisLabels ?? ['X', 'Y', 'Z'];
    const range = max - min;

    const block = document.createElement('div');
    block.className = 'vec3-block';
    if (testId) {
        block.setAttribute('data-testid', testId);
    }

    const header = document.createElement('div');
    header.className = 'vec3-header';
    if (icon) {
        const iconBox = document.createElement('span');
        iconBox.className = 'cs-icon';
        const iconEl = createIconifyIcon(icon);
        if (iconEl) {
            iconBox.appendChild(iconEl);
        } else {
            const fb = document.createElement('span');
            fb.className = 'cs-icon-fallback';
            fb.textContent = label.charAt(0) || '?';
            iconBox.appendChild(fb);
        }
        header.appendChild(iconBox);
    }
    const title = document.createElement('span');
    title.className = 'vec3-title';
    title.textContent = label;
    title.id = `vec3-${Math.random().toString(36).slice(2, 11)}`;
    header.appendChild(title);
    block.appendChild(header);

    const current: [number, number, number] = [value[0], value[1], value[2]];
    const axisColors = ['var(--accent)', 'var(--success)', 'var(--warning)'];

    const controllers: DragSliderController[] = [];
    const valEls: HTMLElement[] = [];
    const fillEls: HTMLElement[] = [];
    const thumbEls: HTMLElement[] = [];
    const barEls: HTMLElement[] = [];

    for (let ai = 0; ai < 3; ai++) {
        const sub = document.createElement('div');
        sub.className = 'vec3-row';
        const ch = document.createElement('span');
        ch.className = 'vec3-axis';
        ch.style.color = axisColors[ai];
        ch.textContent = axes[ai];
        ch.id = `${title.id}-ax${ai}`;
        sub.appendChild(ch);

        const val = document.createElement('span');
        val.className = 'vec3-value';
        val.textContent = step < 1 ? current[ai].toFixed(2) : String(Math.round(current[ai]));
        valEls[ai] = val;

        const bar = document.createElement('div');
        bar.className = 'cs-bar';
        bar.tabIndex = 0;
        bar.setAttribute('role', 'slider');
        bar.setAttribute('aria-label', `${label} ${axes[ai]}`);
        bar.setAttribute('aria-valuenow', String(current[ai]));
        bar.setAttribute('aria-valuemin', String(min));
        bar.setAttribute('aria-valuemax', String(max));
        bar.setAttribute('aria-valuenow', String(current[ai]));
        bar.setAttribute('aria-labelledby', ch.id);
        barEls[ai] = bar;

        const pct = ((current[ai] - min) / range) * 100;

        const fill = document.createElement('div');
        fill.className = 'cs-fill';
        fill.style.background = axisColors[ai];
        fill.style.width = clampPct(pct) + '%';
        fillEls[ai] = fill;

        const thumb = document.createElement('div');
        thumb.className = 'cs-thumb';
        thumb.style.left = clampPct(pct) + '%';
        thumbEls[ai] = thumb;

        bar.appendChild(fill);
        bar.appendChild(thumb);

        function updateDisplay(v: number): void {
            current[ai] = v;
            val.textContent = step < 1 ? v.toFixed(2) : String(Math.round(v));
            const newPct = ((v - min) / range) * 100;
            const clamped = clampPct(newPct);
            fill.style.width = clamped + '%';
            thumb.style.left = clamped + '%';
            bar.setAttribute('aria-valuenow', String(v));
            onChange([current[0], current[1], current[2]]);
        }

        const controller = new DragSliderController({
            value: current[ai],
            min,
            max,
            step,
            onChange: (v) => updateDisplay(v),
            onDragEnd: (v) => onDragEndCb?.([current[0], current[1], current[2]]),
        });
        controller.bind(bar);
        controllers[ai] = controller;

        sub.appendChild(bar);
        sub.appendChild(val);
        block.appendChild(sub);
    }

    container.appendChild(block);

    // === 鑷洿鏂版敮鎸?===
    if (opts) {
        initControl(block, opts, [value[0], value[1], value[2]], (v, cached) => {
            if (!Array.isArray(v) || v.length < 3) {
                return false;
            }
            let changed = false;
            for (let i = 0; i < 3; i++) {
                if (v[i] !== cached[i]) {
                    changed = true;
                    current[i] = v[i];
                    valEls[i].textContent = step < 1 ? v[i].toFixed(2) : String(Math.round(v[i]));
                    const newPct = ((v[i] - min) / range) * 100;
                    const clamped = clampPct(newPct);
                    fillEls[i].style.width = clamped + '%';
                    thumbEls[i].style.left = clamped + '%';
                    barEls[i].setAttribute('aria-valuenow', String(v[i]));
                    controllers[i].setValue(v[i]);
                }
            }
            return changed;
        });
    }
}

// ===================================================================
// addModeSlider
// ===================================================================

export function addModeSlider<T extends string | number>(
    container: HTMLElement,
    label: string,
    options: Array<{ value: T; label: string }>,
    currentValue: T,
    onChange: (v: T) => void,
    icon?: string,
    onDragEndCb?: (v: T) => void,
    opts?: ControlOptions<T>,
    testId?: string
): void {
    const total = options.length;
    if (total === 0) {
        return;
    }

    let currentIndex = options.findIndex((o) => o.value === currentValue);
    if (currentIndex < 0) {
        currentIndex = 0;
    }

    const row = document.createElement('div');
    row.className = 'cs-row';
    if (testId) {
        row.setAttribute('data-testid', testId);
    }

    const top = document.createElement('div');
    top.className = 'cs-top';
    top.tabIndex = 0;
    top.setAttribute('role', 'listbox');
    top.setAttribute('aria-label', label);
    top.setAttribute('aria-valuenow', String(currentIndex));
    top.setAttribute('aria-valuemin', '0');
    top.setAttribute('aria-valuemax', String(total - 1));

    if (icon) {
        const iconBox = document.createElement('span');
        iconBox.className = 'cs-icon';
        const iconEl = createIconifyIcon(icon);
        if (iconEl) {
            iconBox.appendChild(iconEl);
        } else {
            const fb = document.createElement('span');
            fb.className = 'cs-icon-fallback';
            fb.textContent = label.charAt(0) || '?';
            iconBox.appendChild(fb);
        }
        top.appendChild(iconBox);
    }

    const lbl = document.createElement('span');
    lbl.className = 'cs-label';
    lbl.textContent = label;

    const val = document.createElement('span');
    val.className = 'cs-value';
    val.textContent = options[currentIndex].label;

    top.appendChild(lbl);
    top.appendChild(val);

    const bar = document.createElement('div');
    bar.className = 'cs-bar';

    const fill = document.createElement('div');
    fill.className = 'cs-fill';
    const pct = total > 1 ? (currentIndex / (total - 1)) * 100 : 100;
    fill.style.width = clampPct(pct) + '%';

    const thumb = document.createElement('div');
    thumb.className = 'cs-thumb';
    thumb.style.left = clampPct(pct) + '%';

    bar.appendChild(fill);
    bar.appendChild(thumb);

    function updateDisplay(idx: number): void {
        currentIndex = idx;
        val.textContent = options[idx].label;
        const newPct = total > 1 ? (idx / (total - 1)) * 100 : 100;
        const clamped = clampPct(newPct);
        fill.style.width = clamped + '%';
        thumb.style.left = clamped + '%';
        top.setAttribute('aria-valuenow', String(idx));
    }

    function cycleIdx(dir: -1 | 1): void {
        const next = Math.max(0, Math.min(total - 1, currentIndex + dir));
        if (next !== currentIndex) {
            updateDisplay(next);
            onChange(options[next].value);
            onDragEndCb?.(options[next].value);
        }
    }

    // 閿洏鏂瑰悜閿垏鎹n    top.addEventListener('keydown', (e: KeyboardEvent) => {
        if (e.key === 'ArrowLeft' || e.key === 'ArrowUp') {
            e.preventDefault();
            cycleIdx(-1);
        } else if (e.key === 'ArrowRight' || e.key === 'ArrowDown') {
            e.preventDefault();
            cycleIdx(1);
        }
    });

    // 鐐瑰嚮 cs-top锛氬乏鍗婂墠涓€椤广€佸彸鍗婂悗涓€椤筡n    top.addEventListener('click', (e) => {
        e.stopPropagation();
        const rect = top.getBoundingClientRect();
        const x = (e.clientX - rect.left) / rect.width;
        cycleIdx(x < 0.5 ? -1 : 1);
    });

    row.appendChild(top);
    row.appendChild(bar);
    container.appendChild(row);

    // === 鑷洿鏂版敮鎸?===
    initControl(row, opts, currentValue, (v, cached) => {
        if (v === cached) {
            return false;
        }
        const idx = options.findIndex((o) => o.value === v);
        if (idx >= 0) {
            updateDisplay(idx);
        }
        return true;
    });
}

// [doc:architecture] ResourcePanel 鈥?缂╃暐鍥剧綉鏍肩粍浠禱n// 鏀寔缃戞牸/鍒楄〃甯冨眬锛孖ntersectionObserver 鎳掑姞杞絓n// [doc:adr-066] 澶ф暟鎹噺鏃朵娇鐢?VirtualGrid 铏氭嫙婊氬姩

import { createIconifyIcon } from './icons';
import { createVirtualGrid, type VirtualGridHandle } from './ui-virtual-grid';
import { thumbnailCache as liveThumbnailCache, setThumbnailUpdateCallback } from './state';
import { thumbDataUrl } from '@/scene/manager/thumbnail-capture';
import { safeDispose } from './dispose-helpers';

// ======== 娲昏穬闈㈡澘杩借釜锛堢缉鐣ュ浘鍐风紦瀛樺洖濉級 ========
// setThumbnailCache 鏇存柊缂撳瓨鍚庤皟鐢?notifyThumbnailUpdate()锛岃嚜鍔ㄥ埛鏂版墍鏈夋椿璺冮潰鏉跨殑缂╃暐鍥?DOM銆俓nconst _activePanels = new Set<ResourcePanelHandle>();

// ======== Types ========

export interface ResourcePanelOptions {
    /** 鏁版嵁婧愶細妯″瀷鍒楄〃 */
    items: ResourceItem[];
    /** 缂╃暐鍥剧紦瀛?*/
    thumbnailCache: Map<string, string>;
    /** 鐐瑰嚮鍥炶皟 */
    onSelect: (item: ResourceItem) => void;
    /** 鏂囦欢澶硅繘鍏ュ洖璋?*/
    onEnterFolder?: (path: string) => void;
    /** 甯冨眬妯″紡 */
    layout?: 'grid' | 'list';
    /** 缃戞牸鍒楁暟锛堣嚜閫傚簲锛?=鑷姩锛?*/
    columns?: number;
    /** 鍗曢」楂樺害锛堢綉鏍兼ā寮忥紝px锛夛紱缂╃暐鍥句负绔栧睆 2:3锛屽崱鐗囧搴?80px 鈫?缂╃暐鍥?120px + 鏍囩 40px = 160px */
    itemHeight?: number;
}

export interface ResourceItem {
    /** 鍞竴鏍囪瘑 */
    id: string;
    /** 鏄剧ず鍚嶇О */
    label: string;
    /** 鏂囦欢璺緞锛堢敤浜庣缉鐣ュ浘缂撳瓨锛?*/
    filePath: string;
    /** 缂╃暐鍥剧紦瀛?key锛圸IP 妯″瀷涓?file_path::zip_inner锛屾櫘閫氭ā鍨嬪悓 filePath锛?*/
    thumbKey?: string;
    /** 缂╃暐鍥惧楂樻瘮锛屽 '2/3'锛堢珫灞忚鑹诧級銆?16/9'锛堟í灞忓満鏅級锛岄粯璁?'2/3' */
    thumbAspect?: string;
    /** 鍥炬爣鍚嶇О锛坒allback锛?*/
    icon: string;
    /** 鏄惁涓烘枃浠跺す */
    isFolder?: boolean;
    /** 瀛愭爣绛?*/
    sublabel?: string;
    /** 鍘熷鏁版嵁 */
    data?: unknown;
}

export interface ResourcePanelHandle {
    /** 鏇存柊鏁版嵁婧?*/
    updateItems: (items: ResourceItem[]) => void;
    /** 鍒囨崲甯冨眬 */
    setLayout: (layout: 'grid' | 'list') => void;
    /** 鍒锋柊缂╃暐鍥锯€斺€旂紦瀛樻洿鏂板悗璋冪敤锛岄噸鏂板簲鐢ㄥ凡鍛戒腑鐨勭缉鐣ュ浘鍒?DOM */
    refreshThumbs: () => void;
    /** 閿€姣?*/
    dispose: () => void;
}

// ======== Main Component ========

/** 瓒呰繃姝ゆ暟閲忔椂鍚敤铏氭嫙婊氬姩 */
const VIRTUAL_THRESHOLD = 50;

export function createResourcePanel(
    container: HTMLElement,
    options: ResourcePanelOptions
): ResourcePanelHandle {
    const {
        items,
        thumbnailCache,
        onSelect,
        onEnterFolder,
        layout = 'grid',
        itemHeight = 160,
    } = options;

    // 鐘舵€乗n    let currentItems = [...items];
    let currentLayout = layout;
    let observer: IntersectionObserver | null = null;
    let virtualGrid: VirtualGridHandle<ResourceItem> | null = null;
    let mutationObs: MutationObserver | null = null;

    // 鍒涘缓瀹瑰櫒
    const panel = document.createElement('div');
    panel.className = 'resource-panel';
    container.appendChild(panel);

    // 鍒濆鍖栬瀵熷櫒 鈥?浣跨敤瀹炴椂 liveThumbnailCache 寮曠敤锛岀紦瀛樺懡涓悗鑷姩 unobserve
    observer = new IntersectionObserver(
        (entries) => {
            for (const entry of entries) {
                if (entry.isIntersecting) {
                    const el = entry.target as HTMLElement;
                    const path = el.dataset.resourcePath;
                    if (path && liveThumbnailCache.has(path)) {
                        el.style.backgroundImage = `url(${thumbDataUrl(liveThumbnailCache.get(path)!)})`;
                        observer?.unobserve(el);
                    }
                }
            }
        },
        { rootMargin: '200px' }
    );

    function applyThumbIfCached(el: HTMLElement): void {
        const path = el.dataset.resourcePath;
        if (!path) {
            return;
        }
        if (liveThumbnailCache.has(path)) {
            el.style.backgroundImage = `url(${thumbDataUrl(liveThumbnailCache.get(path)!)})`;
            observer?.unobserve(el);
        } else {
            observer?.observe(el);
        }
    }

    // MutationObserver 鐩戝惉铏氭嫙婊氬姩 DOM 鍙樺寲锛岃嚜鍔?observe 鏂板垱寤虹殑缂╃暐鍥綷n    mutationObs = new MutationObserver((mutations) => {
        for (const mut of mutations) {
            for (let i = 0; i < mut.addedNodes.length; i++) {
                const node = mut.addedNodes[i];
                if (node.nodeType !== Node.ELEMENT_NODE) {
                    continue;
                }
                const el = node as HTMLElement;
                // 妫€鏌ヨ妭鐐规湰韬槸鍚︽槸缂╃暐鍥惧厓绱燶n                if (
                    el.classList.contains('resource-thumb') ||
                    el.classList.contains('resource-thumb-sm')
                ) {
                    applyThumbIfCached(el);
                }
                // 妫€鏌ュ瓙鑺傜偣涓殑缂╃暐鍥綷n                const thumbs = el.querySelectorAll(
                    '.resource-thumb, .resource-thumb-sm'
                ) as NodeListOf<HTMLElement>;
                for (let j = 0; j < thumbs.length; j++) {
                    applyThumbIfCached(thumbs[j]);
                }
            }
        }
    });
    mutationObs.observe(panel, { childList: true, subtree: true });

    // 娓呯悊铏氭嫙婊氬姩锛坥bserver 鍜?mutationObs 鎸佷箙瀛樺湪锛岃法 render 澶嶇敤锛塡n    function cleanup(): void {
        if (virtualGrid) {
            virtualGrid = safeDispose(virtualGrid);
        }
    }

    // 娓叉煋
    function render(): void {
        cleanup();
        panel.innerHTML = '';

        if (currentLayout === 'grid' && currentItems.length > VIRTUAL_THRESHOLD) {
            virtualGrid = createVirtualGridFromItems(
                panel,
                currentItems,
                thumbnailCache,
                onSelect,
                onEnterFolder,
                itemHeight
            );
        } else if (currentLayout === 'grid') {
            renderGrid(panel, currentItems, thumbnailCache, onSelect, onEnterFolder, itemHeight);
        } else {
            renderList(panel, currentItems, thumbnailCache, onSelect, onEnterFolder);
        }
    }

    // 鍒濆娓叉煋
    render();

    // 杩斿洖鍙ユ焺
    const handle: ResourcePanelHandle = {
        updateItems: (newItems: ResourceItem[]) => {
            currentItems = [...newItems];
            render();
        },
        setLayout: (newLayout: 'grid' | 'list') => {
            if (currentLayout !== newLayout) {
                currentLayout = newLayout;
                render();
            }
        },
        refreshThumbs: () => {
            panel
                .querySelectorAll<HTMLElement>('.resource-thumb, .resource-thumb-sm')
                .forEach((el) => applyThumbIfCached(el));
        },
        dispose: () => {
            _activePanels.delete(handle);
            if (mutationObs) {
                mutationObs.disconnect();
                mutationObs = null;
            }
            if (observer) {
                observer.disconnect();
                observer = null;
            }
            cleanup();
            panel.remove();
        },
    };
    _activePanels.add(handle);
    return handle;
}

// ======== Virtual Grid Rendering [doc:adr-066] ========

function createVirtualGridFromItems(
    container: HTMLElement,
    items: ResourceItem[],
    cache: Map<string, string>,
    onSelect: (item: ResourceItem) => void,
    onEnterFolder?: (path: string) => void,
    itemHeight: number = 160
): VirtualGridHandle<ResourceItem> {
    const thumbSize = 100; // --resource-thumb-size
    const gap = 8; // --resource-gap
    const cols = Math.max(1, Math.floor((container.clientWidth || 280) / (thumbSize + gap)));

    return createVirtualGrid<ResourceItem>(container, {
        items,
        itemHeight,
        columns: cols,
        renderItem: (item) => {
            const card = createGridCard(item, cache, onSelect, onEnterFolder, itemHeight);
            const aspect = item.thumbAspect || '2/3';
            if (aspect === '16/9') {
                card.style.gridColumn = 'span 2';
            }
            return card;
        },
        bufferRows: 2,
    });
}

// ======== Grid Rendering ========

function renderGrid(
    container: HTMLElement,
    items: ResourceItem[],
    cache: Map<string, string>,
    onSelect: (item: ResourceItem) => void,
    onEnterFolder?: (path: string) => void,
    itemHeight: number = 160
): void {
    const grid = document.createElement('div');
    grid.className = 'resource-grid';
    grid.style.cssText = `
        display: grid;
        grid-template-columns: repeat(auto-fill, minmax(var(--resource-thumb-size), 1fr));
        gap: var(--resource-gap);
        padding: var(--resource-gap);
    `;

    for (const item of items) {
        const card = createGridCard(item, cache, onSelect, onEnterFolder, itemHeight);
        const aspect = item.thumbAspect || '2/3';
        if (aspect === '16/9') {
            card.style.gridColumn = 'span 2';
        }
        grid.appendChild(card);
    }

    container.appendChild(grid);
}

function createGridCard(
    item: ResourceItem,
    cache: Map<string, string>,
    onSelect: (item: ResourceItem) => void,
    onEnterFolder?: (path: string) => void,
    itemHeight: number = 120
): HTMLElement {
    const card = document.createElement('div');
    card.className = 'resource-card';
    card.tabIndex = 0; // [doc:adr-066] 閿洏瀵艰埅鏀寔
    card.style.cssText = `
        background: var(--card-bg);
        border: 1px solid var(--white-08);
        border-radius: var(--resource-radius);
        overflow: hidden;
        cursor: pointer;
        transition: background 0.15s, border-color 0.15s;
    `;

    // 缂╃暐鍥惧尯鍩燂細榛樿绔栧睆 2:3锛堣鑹诧級锛宻tage 鍦烘櫙鐢ㄦí灞?16:9
    const thumb = document.createElement('div');
    thumb.className = 'resource-thumb';
    thumb.dataset.resourcePath = item.thumbKey ?? item.filePath;
    const aspect = item.thumbAspect || '2/3';
    thumb.style.cssText = `
        width: 100%;
        aspect-ratio: ${aspect};
        background-color: var(--bg-overlay-alt);
        background-size: cover;
        background-position: center;
        display: flex;
        align-items: center;
        justify-content: center;
    `;

    // 缂╃暐鍥炬垨 fallback 鍥炬爣
    const tKey = item.thumbKey ?? item.filePath;
    if (cache.has(tKey)) {
        thumb.style.backgroundImage = `url(${thumbDataUrl(cache.get(tKey)!)})`;
    } else {
        const iconEl = createIconifyIcon(item.isFolder ? 'folder' : item.icon);
        if (iconEl) {
            iconEl.style.cssText =
                'width:var(--resource-icon-size);height:var(--resource-icon-size);opacity:0.5';
            thumb.appendChild(iconEl);
        }
    }

    // 鏍囩
    const label = document.createElement('div');
    label.className = 'resource-label';
    label.style.cssText = `
        padding: 6px 8px;
        font-size: var(--font-ui-sm);
        color: var(--text);
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
    `;
    label.textContent = item.label;
    label.title = item.label;

    card.appendChild(thumb);
    card.appendChild(label);

    // 鐐瑰嚮浜嬩欢
    card.addEventListener('click', () => {
        if (item.isFolder && onEnterFolder) {
            onEnterFolder(item.id);
        } else {
            onSelect(item);
        }
    });

    // Hover + Focus 鏁堟灉
    const applyHover = () => {
        card.style.background = 'var(--card-hover)';
        card.style.borderColor = 'var(--white-16)';
    };
    const clearHover = () => {
        card.style.background = 'var(--card-bg)';
        card.style.borderColor = 'var(--white-08)';
    };
    card.addEventListener('mouseenter', applyHover);
    card.addEventListener('mouseleave', clearHover);
    card.addEventListener('focus', applyHover);
    card.addEventListener('blur', clearHover);

    return card;
}

