export function thumbnailKeyForModel(m: LibraryModel, resolution?: number): string {
    // 缁熶竴缁?thumbnail-key 妯″潡鏋勯€狅紝涓庡啓渚э紙model-loader / props锛夊悓婧愶紝鏉滅粷鍙屾簮鎷兼帴鍙嶅脊銆俓n    // 鏍煎紡锛歚<baseKey>::<resolution>::<aspect>`锛孼IP 鍐呮ā鍨?baseKey 涓?`file_path::zip_inner`銆俓n    const baseKey = libraryModelBaseKey(m);
    const res = resolution ?? uiState.thumbnailResolution ?? 512;
    return buildThumbnailKey({ baseKey, isStage: isStageLike(m.type), resolution: res });
}

async function ensureModelMeta(pmxPaths: string[]): Promise<void> {
    const guard = getPendingMetaGuard();
    const uncached = pmxPaths.filter((p) => !modelMetaCache.has(p) && !guard.isLoading(p));
    if (uncached.length === 0) {
        return;
    }
    for (const p of uncached) {
        guard.tryEnter(p);
    }
    try {
        const batch = await GetModelMetaBatch(uncached);
        if (batch) {
            const merged = new Map(modelMetaCache);
            for (const [path, meta] of Object.entries(batch)) {
                merged.set(path, meta);
            }
            setModelMetaCache(merged);
        }
    } catch (err) {
        logWarn('library-core', 'ensureModelMeta:', err);
    } finally {
        for (const p of uncached) {
            guard.leave(p);
        }
    }
}

/**
 * 娴佸紡鍔犺浇缂╃暐鍥撅細骞跺彂鎺у埗锛屾瘡鍔犺浇涓€寮犵珛鍗虫洿鏂扮紦瀛樺苟閫氱煡闈㈡澘鍒锋柊锛孿n * 鏇夸唬涓€娆℃€?GetThumbnailBatch 鐨刓

妯″紡锛屽疄鐜扮缉鐣ュ浘閫愬紶鍑虹幇銆俓n * 鍚?key 宸插湪缂撳瓨涓椂璺宠繃锛堜笉鏀瑰姩鐜版湁缂撳瓨锛夈€俓n */
const THUMB_STREAM_CONCURRENCY = 4;

// [adr-136] 缂╃暐鍥炬祦寮忓姞杞姐€屽綋鍓嶆壒娆°€嶆帶鍒跺櫒锛氭瘡娆℃柊璋冪敤閮戒細 abort 涓婁竴鎵规锛孿n// 閬垮厤蹇€熷垏鎹㈡枃浠跺す鏃舵棫鐨?GetThumbnail 璇锋眰鍫嗙Н銆俓n// 娉細GetThumbnail 鏄?Wails binding锛孏o 渚ф棤娉曠湡姝ｄ腑姝紱姝ゅ涓恒€屽崗浣滃紡鍙栨秷銆嶁€斺€擻n// abort 鍚庝笉鍐嶆淳鍙戞柊 worker銆佷涪寮冨凡鎷夊彇浣嗘湭鍐欏叆鐨勮繃鏈熺粨鏋滐紝閬垮厤鍚戝凡涓嶅彲瑙佺殑闈㈡澘鍐欑紦瀛?閫氱煡銆俓nlet _thumbAbortController: AbortController | null = null;

/**
 * 娴佸紡鍔犺浇缂╃暐鍥撅細骞跺彂鎺у埗锛屾瘡鍔犺浇涓€寮犵珛鍗虫洿鏂扮紦瀛樺苟閫氱煡闈㈡澘鍒锋柊锛孿n * 鏇夸唬涓€娆℃€?GetThumbnailBatch 鐨刓

妯″紡锛屽疄鐜扮缉鐣ュ浘閫愬紶鍑虹幇銆俓n * 鍚?key 宸插湪缂撳瓨涓椂璺宠繃锛堜笉鏀瑰姩鐜版湁缂撳瓨锛夈€俓n *
 * @param signal 澶栭儴鍙栨秷淇″彿銆備紶鍏ュ悗锛宎bort 鏃跺崗浣滃紡鍋滄锛氫笉鍐嶅鐞嗗墿浣?key銆乗n *               涓斾涪寮冨凡鎷夊彇浣嗘湭鍐欏叆鐨勮繃鏈熺粨鏋溿€備笌鍐呴儴銆屽綋鍓嶆壒娆°€嶆帶鍒跺櫒鍚堝苟锛屼袱鑰呬换涓€ abort 鍗崇敓鏁堛€俓n */
export async function loadThumbnailsStreaming(keys: string[], signal?: AbortSignal): Promise<void> {
    if (keys.length === 0) {
        return;
    }
    // [adr-136] 鍙栨秷涓婁竴鎵规锛堝揩閫熷垏鎹㈡枃浠跺す鏃堕伩鍏嶈姹傚爢绉級
    if (_thumbAbortController) {
        _thumbAbortController.abort();
    }
    const internalCtrl = new AbortController();
    _thumbAbortController = internalCtrl;
    // 鍚堝苟澶栭儴 signal 涓庡唴閮ㄦ帶鍒跺櫒锛氫换涓€ abort 鍗崇敓鏁堛€俓n    // 鐢?AbortSignal.any 鑰岄潪 ?? 鍥為€€锛屽惁鍒欎細蹇界暐鍐呴儴鎵规鍙栨秷锛堜笌 model-loader 鍚屾鑰冮噺锛孉DR-096/105锛夈€俓n    const effectiveSignal = signal
        ? AbortSignal.any([signal, internalCtrl.signal])
        : internalCtrl.signal;
    let index = 0;
    const workers = Array.from(
        { length: Math.min(THUMB_STREAM_CONCURRENCY, keys.length) },
        async () => {
            while (index < keys.length) {
                if (effectiveSignal.aborted) {
                    break; // 鍗忎綔寮忓仠姝㈡淳鍙慭n                }
                const key = keys[index++];
                if (thumbnailCache.has(key)) {
                    continue;
                }
                try {
                    const data = await GetThumbnail(key);
                    // 鎷夊彇瀹屾垚鍚庡啀鍒や竴娆?abort锛氫涪寮冨凡涓嶅彲瑙佺殑杩囨湡缁撴灉
                    if (effectiveSignal.aborted) {
                        continue;
                    }
                    if (data) {
                        thumbnailCache.set(key, data);
                        // 閫氱煡鎵€鏈夋椿璺冮潰鏉匡紝浣垮綋鍓嶅彲瑙佺殑缂╃暐鍥剧珛鍗虫樉绀篭n                        notifyThumbnailUpdate();
                    }
                } catch (err) {
                    logWarn('library-core', `GetThumbnail failed for ${key}:`, err);
                }
            }
        }
    );
    try {
        await Promise.all(workers);
    } finally {
        // 鎵规鑷劧缁撴潫鏃舵竻寮曠敤锛涜嫢宸茶澶栭儴/鏂版壒娆″彇浠ｅ垯涓嶅姩锛堥槻璇竻鏂版壒娆★級
        if (_thumbAbortController === internalCtrl) {
            _thumbAbortController = null;
        }
    }
}

/** [adr-136] 鍙栨秷褰撳墠姝ｅ湪杩涜鐨勭缉鐣ュ浘娴佸紡鍔犺浇鎵规锛堝寮圭獥鍏抽棴/閲嶅紑鏃惰皟鐢級銆?*/
export function abortThumbnailStreaming(): void {
    if (_thumbAbortController) {
        _thumbAbortController.abort();
        _thumbAbortController = null;
    }
}

