/** 娓叉煋涓婁笅鏂囨爤 鈥?鎺т欢鍒涘缓鍑芥暟閫氳繃 getCurrentRenderingMenu() 鑾峰緱褰撳墠鑿滃崟 */
const _renderingStack: SlideMenu[] = [];

/** 鑾峰彇褰撳墠姝ｅ湪娓叉煋鐨?SlideMenu 瀹炰緥锛堜緵 ui-helpers 涓殑鎺т欢鍑芥暟鑷姩娉ㄥ唽锛?*/
