}

export class SlideMenu {
    private levels: PopupLevel[] = [];
    private container: HTMLElement;
    private viewport: HTMLElement;
    private panel: HTMLElement;
    private headerEl: HTMLElement;
    private focusIndex = -1;
    private transitioning = false;
    /** 璺熻釜鏈喅鐨?setTimeout锛岀‘淇?cancelAnims 鑳藉叏閮ㄦ竻闄?*/
    private _pendingTimeouts: ReturnType<typeof setTimeout>[] = [];
    /** 缂撳瓨鐨勯澶栨寜閽紝閬垮厤姣忔 updateHeader 閲嶅缓銆佹棫鐩戝惉鍣ㄦ硠婕?*/
    private _cachedExtraBtns: HTMLElement[] | null = null;
    /** 璁板綍鏈喅鐨?RAF reRender锛岀敤浜庡幓鎶?*/
    private _reRenderPending = false;
    /** keydown 鐩戝惉鍣ㄥ紩鐢紝渚?dispose 娓呯悊 */
    private _keydownHandler: ((e: KeyboardEvent) => void) | null = null;
    /** 瑙﹀睆婊戝姩鎵嬪娍璧峰鍧愭爣 */
    private _swipeStartX = 0;
    private _swipeStartY = 0;
    private _swipeTouchStartHandler: ((e: TouchEvent) => void) | null = null;
    private _swipeTouchEndHandler: ((e: TouchEvent) => void) | null = null;
    private _keydownDisp: Disposable | null = null;
    private _swipeTouchStartDisp: Disposable | null = null;
    private _swipeTouchEndDisp: Disposable | null = null;
    /** 鑷洿鏂版帶浠舵敞鍐岃〃 鈥?姣忎釜鍏冪礌鏈?update() 鏂规硶锛岀敱 updateControls() 缁熶竴璋冪敤 */
    private _controls: Array<{ update: () => void }> = [];
    /** renderCustom 杩斿洖鐨勬竻鐞嗗嚱鏁帮紝鍦?buildPanel 閲嶅缓鎴?dispose 鏃惰皟鐢?*/
    private _customDispose: (() => void) | null = null;
    /** 鍝嶅簲寮忚闃呭彇娑堝嚱鏁?鈥?dispose 鏃惰皟鐢?*/
    private _unsubscribe: (() => void) | null = null;
    /** 璁板綍涓婁竴娆¤瑷€鐮侊紝渚?updateControls 妫€娴?i18n 鐑垏鎹紙ADR-065锛?*/
    private _lastLang: string = getLang();

    onItemClick?: (row: PopupRow, menu: SlideMenu) => void;
    onFolderEnter?: (
        row: PopupRow,
        menu: SlideMenu
    ) => PopupLevel | null | Promise<PopupLevel | null>;
    onHover?: (row: PopupRow, entering: boolean) => void;
    onAfterRender?: (level: PopupLevel, menu: SlideMenu) => void;
    onClose?: () => void;
    extraButtonFactory?: () => HTMLElement[];
    /** 姣忔 level 鍙樻洿锛坧ush/pop锛夊悗鍥炶皟锛屼緵澶栭儴鎸佷箙鍖栧綋鍓嶇洰褰曠瓑鐘舵€?*/
    onLevelEnter?: (level: PopupLevel, menu: SlideMenu) => void;

    constructor(opts: {
        container: HTMLElement;
        onItemClick?: (row: PopupRow, menu: SlideMenu) => void;
        onFolderEnter?: (
            row: PopupRow,
            menu: SlideMenu
        ) => PopupLevel | null | Promise<PopupLevel | null>;
        onHover?: (row: PopupRow, entering: boolean) => void;
        onAfterRender?: (level: PopupLevel, menu: SlideMenu) => void;
        onClose?: () => void;
        extraButtonFactory?: () => HTMLElement[];
        onLevelEnter?: (level: PopupLevel, menu: SlideMenu) => void;
    }) {
        this.container = opts.container;
        this.onItemClick = opts.onItemClick;
        this.onFolderEnter = opts.onFolderEnter;
        this.onHover = opts.onHover;
        this.onAfterRender = opts.onAfterRender;
        this.onClose = opts.onClose;
        this.extraButtonFactory = opts.extraButtonFactory;
        this.onLevelEnter = opts.onLevelEnter;

        this.container.innerHTML = '';
        this.container.classList.add('slide-menu');

        this.viewport = document.createElement('div');
        this.viewport.className = 'slide-viewport';

        this.panel = document.createElement('div');
        this.panel.className = 'slide-panel';
        // 鍐呰仈鏍峰紡鐢?CSS 鎺у埗锛屽彧璁剧疆蹇呰鐨勮繃娓n        this.panel.style.transition = `opacity ${TRANSITION_DURATION} ease, transform ${TRANSITION_DURATION} ease`;
        this.panel.style.opacity = '1';
        this.panel.style.transform = 'translateX(0)';
        this.panel.style.display = 'flex';

        this.viewport.appendChild(this.panel);
        this.container.appendChild(this.viewport);

        this.headerEl = document.createElement('div');
        this.headerEl.className = 'slide-header';
        this.container.appendChild(this.headerEl);

        // 閿洏瀵艰埅
        this.container.tabIndex = -1;
        this._keydownHandler = (e) => {
            if (this.transitioning) {
                return;
            }
            switch (e.key) {
                case 'ArrowDown':
                    e.preventDefault();
                    this.focusNext();
                    break;
                case 'ArrowUp':
                    e.preventDefault();
                    this.focusPrev();
                    break;
                case 'ArrowRight':
                case 'Enter':
                    e.preventDefault();
                    this.activateFocused();
                    break;
                case 'ArrowLeft':
                    e.preventDefault();
                    this.pop();
                    break;
            }
        };
        this._keydownDisp = addDisposableListener(this.container, 'keydown', this._keydownHandler);

        // 瑙﹀睆鎵嬪娍锛氬彸婊戣繑鍥炰笂涓€灞傜骇
        this._swipeStartX = 0;
        this._swipeStartY = 0;
        this._swipeTouchStartHandler = (e: TouchEvent) => {
            if (e.touches.length === 1) {
                this._swipeStartX = e.touches[0].clientX;
                this._swipeStartY = e.touches[0].clientY;
            }
        };
        this._swipeTouchEndHandler = (e: TouchEvent) => {
            if (this.transitioning || this.levels.length <= 1) {
                return;
            }
            const ct = e.changedTouches[0];
            if (!ct) {
                return;
            }
            const dx = ct.clientX - this._swipeStartX;
            const dy = Math.abs(ct.clientY - this._swipeStartY);
            // 鍙虫粦 > 60px 涓斿瀭鐩村亸绉?< 40px 鈫?杩斿洖
            if (dx > 60 && dy < 40) {
                this.pop();
            }
        };
        this._swipeTouchStartDisp = addDisposableListener(
            this.container,
            'touchstart',
            this._swipeTouchStartHandler,
            { passive: true }
        );
        this._swipeTouchEndDisp = addDisposableListener(
            this.container,
            'touchend',
            this._swipeTouchEndHandler,
            { passive: true }
        );

        // 鍝嶅簲寮忚闃咃細鐘舵€佸彉鏇?鈫?鑷姩 updateControls
        this._unsubscribe = subscribe(() => this.updateControls());
    }

    // ======== 鍏叡 API ========

    get currentLevel(): PopupLevel | undefined {
        return this.levels[this.levels.length - 1];
    }

    get levelCount(): number {
        return this.levels.length;
    }

    /** 鍙鏆撮湶鍔ㄧ敾涓姸鎬侊紝渚涘閮ㄨ瘖鏂€屽睍寮€鏈熼棿 push 琚潤榛樹涪寮冦€嶇殑 race */
    get isTransitioning(): boolean {
        return this.transitioning;
    }

    reset(level: PopupLevel): void {
        this._cancelAnim();
        this.levels = [level];
        this.panel.style.transition = 'none';
        this.panel.style.opacity = '1';
        this.panel.style.transform = 'translateX(0)';
        safeCallAsync('menu', 'buildPanel failed:', () =>
            this.buildPanel(level).then(() => {
                this.updateHeader(level);
                this.setupFocus();
                this.onAfterRender?.(level, this);
                this.onLevelEnter?.(level, this);
            })
        );
    }

    push(level: PopupLevel): void {
        if (this.transitioning) {
            return;
        }
        this.transitioning = true;
        this.levels.push(level);

        // 鏃у唴瀹规贰鍑篭n        this.panel.style.transition = `opacity ${TRANSITION_DURATION_FAST} ease, transform ${TRANSITION_DURATION_FAST} ease`;
        this.panel.style.opacity = '0';
        this.panel.style.transform = 'translateX(-8px)';

        let fadeOutDisp: Disposable | null = null;
        const onFadeOut = async () => {
            fadeOutDisp = safeDispose(fadeOutDisp);
            await this.buildPanel(level);
            this.updateHeader(level);
            // 鏂板唴瀹逛粠涓嬫柟娣″叆
            this.panel.style.transition = 'none';
            this.panel.style.opacity = '0';
            this.panel.style.transform = 'translateX(8px)';
            void this.panel.offsetHeight;
            this.panel.style.transition = `opacity ${TRANSITION_DURATION} ease, transform ${TRANSITION_DURATION} ease`;
            this.panel.style.opacity = '1';
            this.panel.style.transform = 'translateX(0)';

            let fadeInDisp: Disposable | null = null;
            const onFadeIn = () => {
                fadeInDisp = safeDispose(fadeInDisp);
                this._cancelTimeout();
                this.transitioning = false;
                this.setupFocus();
                this.onAfterRender?.(level, this);
                this.onLevelEnter?.(level, this);
            };
            fadeInDisp = addDisposableListener(this.panel, 'transitionend', onFadeIn);
            this._pushTimeout(
                setTimeout(() => {
                    if (this.transitioning) {
                        this.panel.style.opacity = '1';
                        this.panel.style.transform = 'translateX(0)';
                        this.transitioning = false;
                        this.setupFocus();
                        this.onAfterRender?.(level, this);
                        this.onLevelEnter?.(level, this);
                    }
                }, 200)
            );
        };

        fadeOutDisp = addDisposableListener(this.panel, 'transitionend', onFadeOut);
        this._pushTimeout(
            setTimeout(() => {
                if (this.transitioning) {
                    this.panel.style.opacity = '0';
                    this.panel.style.transform = 'translateX(-8px)';
                    onFadeOut();
                }
            }, 150)
        );
    }

    pop(): void {
        if (this.transitioning || this.levels.length <= 1) {
            return;
        }
        this.transitioning = true;
        this.levels.pop();
        const prevLevel = this.levels[this.levels.length - 1];

        this.panel.style.transition = `opacity ${TRANSITION_DURATION_FAST} ease, transform ${TRANSITION_DURATION_FAST} ease`;
        this.panel.style.opacity = '0';
        this.panel.style.transform = 'translateX(8px)';

        let fadeOutDisp: Disposable | null = null;
        const onFadeOut = async () => {
            fadeOutDisp = safeDispose(fadeOutDisp);
            await this.buildPanel(prevLevel);
            this.updateHeader(prevLevel);
            this.panel.style.transition = 'none';
            this.panel.style.opacity = '0';
            this.panel.style.transform = 'translateX(-8px)';
            void this.panel.offsetHeight;
            this.panel.style.transition = `opacity ${TRANSITION_DURATION} ease, transform ${TRANSITION_DURATION} ease`;
            this.panel.style.opacity = '1';
            this.panel.style.transform = 'translateX(0)';

            let fadeInDisp: Disposable | null = null;
            const onFadeIn = () => {
                fadeInDisp = safeDispose(fadeInDisp);
                this._cancelTimeout();
                this.transitioning = false;
                this.setupFocus();
                this.onAfterRender?.(prevLevel, this);
                this.onLevelEnter?.(prevLevel, this);
            };
            fadeInDisp = addDisposableListener(this.panel, 'transitionend', onFadeIn);
            this._pushTimeout(
                setTimeout(() => {
                    if (this.transitioning) {
                        this.panel.style.opacity = '1';
                        this.panel.style.transform = 'translateX(0)';
                        this.transitioning = false;
                        this.setupFocus();
                        this.onAfterRender?.(prevLevel, this);
                        this.onLevelEnter?.(prevLevel, this);
                    }
                }, 200)
            );
        };

        fadeOutDisp = addDisposableListener(this.panel, 'transitionend', onFadeOut);
        this._pushTimeout(
            setTimeout(() => {
                if (this.transitioning) {
                    this.panel.style.opacity = '0';
                    this.panel.style.transform = 'translateX(8px)';
                    onFadeOut();
                }
            }, 150)
        );
    }

    popTo(index: number): void {
        if (index < 0 || index >= this.levels.length || this.transitioning) {
            return;
        }
        if (index === this.levels.length - 1) {
            return;
        }
        this._cancelAnim();
        this.levels = this.levels.slice(0, index + 1);
        const level = this.currentLevel!;
        this.panel.style.transition = 'none';
        this.panel.style.opacity = '1';
        this.panel.style.transform = 'translateX(0)';
        safeCallAsync('menu', 'buildPanel failed:', () =>
            this.buildPanel(level).then(() => {
                this.updateHeader(level);
                this.setupFocus();
                this.onAfterRender?.(level, this);
                this.onLevelEnter?.(level, this);
            })
        );
    }

    reRender(opts?: { preserveFocus?: boolean }): void {
        if (this.transitioning) {
            return;
        }
        // RAF 鍘绘姈锛氬悓甯у唴澶氭 reRender 鍚堝苟涓轰竴娆n        if (this._reRenderPending) {
            return;
        }
        this._reRenderPending = true;
        requestAnimationFrame(() => {
            this._reRenderPending = false;
            this._doReRender(opts);
        });
    }

    /** 娉ㄥ唽涓€涓嚜鏇存柊鎺т欢锛岀敱 updateControls() 缁熶竴椹卞姩鍒锋柊 */
    registerControl(update: () => void): void {
        this._controls.push({ update });
    }

    /** 澧為噺鍒锋柊鎵€鏈夊凡娉ㄥ唽鐨勮嚜鏇存柊鎺т欢锛堜笉閲嶅缓 DOM锛?*/
    updateControls(): void {
        const _start = performance.now();
        for (const c of this._controls) {
            c.update();
        }
        const level = this.currentLevel;
        // [doc:adr-065] i18n 鐑垏鎹細璇█鍙樺寲鏃讹紝renderCustom 灞傜骇鐨?schema 鏍囩涓庤嚜瀹氫箟 DOM
        // 鍧囧湪娓叉煋鏈熺粡 t() 姹傚€硷紝椤诲叏閲忛噸寤哄綋鍓嶅眰鎵嶈兘鍒锋柊锛堢函 items 灞傜敱涓嬫柟 itemBuilder patch 瑕嗙洊锛夈€俓n        const lang = getLang();
        if (lang !== this._lastLang) {
            this._lastLang = lang;
            if (level?.renderCustom && this.panel.querySelector('.slide-list')) {
                this.reRender({ preserveFocus: true });
            }
        }
        // [doc:adr-065] 绾?items 灞傜骇璇█鐑埛鏂帮細褰撳墠灞傛寔鏈?itemBuilder 鏃讹紝
        // 閲嶅缓 items 骞跺閲?patch锛堜粎褰撻潰鏉垮凡娓叉煋鈥斺€旈伩鍏嶅鏈墦寮€/宸?dispose 鐨勮彍鍗曡瑙﹀彂鍏ㄩ噺 buildPanel锛夈€俓n        if (level?.itemBuilder && this.panel.querySelector('.slide-list')) {
            level.items = level.itemBuilder();
            this.patchPanel(level.items);
        }
        const _elapsed = performance.now() - _start;
        if (_elapsed > 4) {
            logWarn(
                'perf:menu',
                `updateControls took ${_elapsed.toFixed(1)}ms (${this._controls.length} controls, itemBuilder=${!!level?.itemBuilder})`
            );
        }
    }

    private _doReRender(opts?: { preserveFocus?: boolean }): void {
        const level = this.currentLevel;
        if (!level) {
            return;
        }
        this._cachedExtraBtns = null;

        const finalize = () => {
            this.updateHeader(level);
            // reRenderCustom 璺緞鏄閲忔洿鏂帮紝涓嶆姠鐒︾偣
            const preserve = opts?.preserveFocus ?? level.reRenderCustom !== undefined;
            if (!preserve) {
                this.setupFocus();
            }
            this.onAfterRender?.(level, this);
        };

        if (level.reRenderCustom) {
            // === 澧為噺璺緞锛歱atch items锛堥潪绌烘椂锛? reRenderCustom ===
            const list = this.panel.querySelector('.slide-list');
            if (list) {
                if (level.items.length > 0) {
                    this.patchPanel(level.items);
                }
                level.reRenderCustom(list as HTMLElement);
                finalize();
                return;
            }
            // 娌℃湁鏃?DOM 鈫?閫€鍖栦负鍏ㄩ噺閲嶅缓
            safeCallAsync('menu', 'buildPanel failed:', () =>
                this.buildPanel(level).then(finalize)
            );
        } else if (level.renderCustom || level.items.length === 0) {
            // === 鑷畾涔夋覆鏌?/ 绌哄垪琛?鈫?鍏ㄩ噺閲嶅缓 ===
            safeCallAsync('menu', 'buildPanel failed:', () =>
                this.buildPanel(level).then(finalize)
            );
        } else {
            // === 绾?items 鈫?鍏ㄩ噺閲嶅缓锛坈ard-per-divider 缁撴瀯涓嶆敮鎸佸閲?patch锛?===
            safeCallAsync('menu', 'buildPanel failed:', () =>
                this.buildPanel(level).then(finalize)
            );
            finalize();
        }
    }

    /** 閲嶇疆瀵艰埅鏍堝埌鏍瑰眰绾э紝涓嶈Е鍙戞覆鏌?*/
    resetToRoot(): void {
        if (this.levels.length > 1) {
            this.levels = [this.levels[0]];
        }
    }

    getLevel(index: number): PopupLevel | undefined {
        return this.levels[index];
    }

    setLevel(index: number, level: PopupLevel): void {
        if (index >= 0 && index < this.levels.length) {
            this.levels[index] = level;
            // 濡傛灉鏇挎崲鐨勬槸褰撳墠鏄剧ず灞傜骇锛岃嚜鍔ㄩ噸缁榎n            if (index === this.levels.length - 1) {
                this.reRender();
            }
        }
    }

    /** 鐢ㄦ柊灞傜骇鏇挎崲褰撳墠锛堟爤椤讹級灞傜骇骞惰Е鍙戦噸缁橈紝甯哥敤浜庡瓙鑿滃崟鐘舵€佸彉鍖栧悗鍒锋柊 */
    replaceCurrentLevel(level: PopupLevel): void {
        if (this.levels.length === 0) {
            return;
        }
        this.setLevel(this.levels.length - 1, level);
    }

    /**
     * 绮惧噯鏇挎崲绗?index 琛岀殑 DOM锛屼笉璧?reRender 鍏ㄩ噺閲嶅缓銆俓n     * 甯哥敤浜庡崟琛岀姸鎬佸彉鍖栵紙寮€鍏炽€侀€変腑鎬佺瓑锛夈€俓n     */
    updateRow(index: number, row: PopupRow): void {
        const level = this.currentLevel;
        if (!level || index < 0 || index >= level.items.length) {
            return;
        }
        level.items[index] = row;
        const list = this.panel.querySelector('.slide-list');
        if (!list) {
            return;
        }
        const oldChild = list.children[index] as HTMLElement | undefined;
        if (oldChild) {
            const newEl = this.createRow(row);
            if (newEl) {
                oldChild.replaceWith(newEl);
            }
        }
    }

    /** 鍙埛鏂版爣棰樻爮锛堣繑鍥炴寜閽?+ 鏍囬 + 棰濆鎸夐挳锛夛紝涓嶇闈㈡澘 */
    refreshHeader(): void {
        const level = this.currentLevel;
        if (!level) {
            return;
        }
        this._cachedExtraBtns = null;
        this.updateHeader(level);
    }

    /** 寮哄埗缁撴潫褰撳墠鍔ㄧ敾锛屾竻闄ゆ墍鏈夋湭鍐冲畾鏃跺櫒锛岄噸缃繃娓＄姸鎬?*/
    private _cancelAnim(): void {
        this.transitioning = false;
        this._reRenderPending = false;
        this._cancelTimeout();
        this.panel.style.transition = 'none';
        this.panel.style.opacity = '1';
        this.panel.style.transform = 'translateX(0)';
    }

    /** 璁板綍涓€涓敱鍔ㄧ敾鐢熷懡鍛ㄦ湡绠＄悊鐨?setTimeout */
    private _pushTimeout(id: ReturnType<typeof setTimeout>): void {
        this._pendingTimeouts.push(id);
    }

    /** 娓呴櫎鎵€鏈夋湭鍐崇殑鍔ㄧ敾鍚庡 setTimeout */
    private _cancelTimeout(): void {
        for (const id of this._pendingTimeouts) {
            clearTimeout(id);
        }
        this._pendingTimeouts = [];
    }

    // ======== 鍐呴儴鏂规硶 ========

    private get panelItems(): NodeListOf<HTMLElement> {
        return this.panel.querySelectorAll<HTMLElement>('.slide-item');
    }

    private clearFocus(): void {
        this.panel
            .querySelectorAll('.slide-focused')
            .forEach((el) => el.classList.remove('slide-focused'));
    }

    private applyFocus(): void {
        this.clearFocus();
        const items = this.panelItems;
        if (this.focusIndex < 0 || this.focusIndex >= items.length) {
            return;
        }
        items[this.focusIndex].classList.add('slide-focused');
        items[this.focusIndex].scrollIntoView({ block: 'nearest' });
    }

    private setupFocus(): void {
        this.focusIndex = -1;
        this.clearFocus();
        if (this.panelItems.length > 0) {
            this.focusIndex = 0;
            this.applyFocus();
        }
        this.container.focus({ preventScroll: true });
    }

    private focusPrev(): void {
        const len = this.panelItems.length;
        if (len === 0) {
            return;
        }
        this.focusIndex = this.focusIndex <= 0 ? len - 1 : this.focusIndex - 1;
        this.applyFocus();
    }

    private focusNext(): void {
        const len = this.panelItems.length;
        if (len === 0) {
            return;
        }
        this.focusIndex = this.focusIndex >= len - 1 ? 0 : this.focusIndex + 1;
        this.applyFocus();
    }

    private activateFocused(): void {
        const items = this.panelItems;
        if (this.focusIndex < 0 || this.focusIndex >= items.length) {
            return;
        }
        items[this.focusIndex].click();
    }

    private _buildSeq = 0;

    // ======== 澧為噺娓叉煋 ========

    /** 鐢熸垚琛岀殑绋冲畾鏍囪瘑 key锛氫紭鍏堢敤 row.rowKey锛屽惁鍒欐寜 kind:target 鑷姩鎺ㄥ */
    private rowKey(row: PopupRow): string {
        if (row.rowKey) {
            return row.rowKey;
        }
        if (row.kind === 'divider') {
            return '__divider__';
        }
        // [doc:adr-129] sectionTitle 鐢?label 鍖哄垎锛坱arget 閫氬父涓虹┖锛夛紝閬垮厤澶氫釜鏍囬琛?key 鎾炶溅
        if (row.kind === 'sectionTitle') {
            return `sectionTitle:${row.label}`;
        }
        return `${row.kind}:${row.target}`;
    }

    /** 澧為噺 patch 褰撳墠 panel锛氬彧鍒涘缓/鏇挎崲/鍒犻櫎鏈夊彉鍖栫殑琛?*/
    private patchPanel(items: PopupRow[]): void {
        if (items.length === 0) {
            return;
        }
        const list = this.panel.querySelector('.slide-list');
        if (!list) {
            this.buildPanel(this.currentLevel!);
            return;
        }

        // [doc:adr-NNN] 澶?lcard锛坈ard-per-divider锛夊満鏅細鎸?divider 鍒嗗壊 items锛孿n        // 鍒嗗埆 patch 鍒板搴旂殑 lcard锛岄伩鍏嶅叏閲忛噸寤篭n        const cards = list.querySelectorAll(':scope > .lcard') as NodeListOf<HTMLElement>;
        if (cards.length > 1) {
            this._patchMultiCard(cards, items);
            return;
        }

        // 鍗曞鍣紙鏃?lcard 鎴栦粎涓€涓級鈫?鍘熸湁閫昏緫
        const card = cards.length === 1 ? cards[0] : null;
        const container = card || list;
        const oldChildren = Array.from(container.children) as HTMLElement[];

        // 1. 鍒犻櫎澶氫綑鐨勮锛堜粠鍚庡線鍓嶏紝閬垮厤绱㈠紩鍋忕Щ锛塡n        for (let i = oldChildren.length - 1; i >= items.length; i--) {
            oldChildren[i].remove();
        }

        // 2. 閫愯姣旇緝
        for (let i = 0; i < items.length; i++) {
            const newRow = items[i];
            const newKey = this.rowKey(newRow);

            if (i < oldChildren.length) {
                const oldEl = oldChildren[i];
                const oldKey = oldEl.dataset.rowKey || '';
                if (oldKey !== newKey) {
                    // key 涓嶅尮閰?鈫?鏇挎崲鏁磋
                    const newEl = this.createRow(newRow);
                    if (newEl) {
                        oldEl.replaceWith(newEl);
                    }
                } else {
                    // [doc:adr-065] key 鍖归厤浣嗚瑷€鍙兘宸插垏鎹細鍘熷湴鍒锋柊鍙鏂囨湰锛坙abel/hint锛夛紝
                    // 涓嶉噸寤?DOM銆佷繚鐣欏凡鏈夌洃鍚櫒涓庨敭鐩樼劍鐐广€傛帶浠惰锛坰lider/toggle/鈥︼級鐢?registerControl 绠＄悊锛岃烦杩囥€俓n                    this.refreshRowText(oldEl, newRow);
                }
            } else {
                // 杩藉姞鏂拌
                const newEl = this.createRow(newRow);
                if (newEl) {
                    container.appendChild(newEl);
                }
            }
        }
    }

    /** 澶?lcard 鍦烘櫙锛氭寜 divider 鍒嗗壊 items锛岄€?card patch */
    private _patchMultiCard(cards: NodeListOf<HTMLElement>, items: PopupRow[]): void {
        // 鎸?divider 鍒嗗壊 items锛堜笌 buildPanel 鍒嗙粍閫昏緫涓€鑷达細divider 鏈韩涓嶅綊灞炰换浣曠粍锛塡n        const segments: PopupRow[][] = [];
        let cur: PopupRow[] = [];
        for (const row of items) {
            if (row.kind === 'divider') {
                if (cur.length > 0) {
                    segments.push(cur);
                    cur = [];
                }
                continue;
            }
            cur.push(row);
        }
        if (cur.length > 0) {
            segments.push(cur);
        }

        // lcard 鏁颁笌鍒嗙粍鏁颁笉鍖归厤 鈫?items 缁撴瀯鍙樺寲锛屽洖閫€鍏ㄩ噺閲嶅缓
        if (cards.length !== segments.length) {
            this.buildPanel(this.currentLevel!);
            return;
        }

        // 閫愪釜 lcard 鐙珛 patch
        for (let c = 0; c < cards.length; c++) {
            const container = cards[c];
            const seg = segments[c];
            const oldChildren = Array.from(container.children) as HTMLElement[];

            // 鍒犻櫎澶氫綑鐨勮
            for (let i = oldChildren.length - 1; i >= seg.length; i--) {
                oldChildren[i].remove();
            }

            // 閫愯姣旇緝
            for (let i = 0; i < seg.length; i++) {
                const newRow = seg[i];
                const newKey = this.rowKey(newRow);

                if (i < oldChildren.length) {
                    const oldEl = oldChildren[i];
                    const oldKey = oldEl.dataset.rowKey || '';
                    if (oldKey !== newKey) {
                        const newEl = this.createRow(newRow);
                        if (newEl) {
                            oldEl.replaceWith(newEl);
                        }
                    } else {
                        this.refreshRowText(oldEl, newRow);
                    }
                } else {
                    const newEl = this.createRow(newRow);
                    if (newEl) {
                        container.appendChild(newEl);
                    }
                }
            }
        }
    }

    /**
     * [doc:adr-065] 鍘熷湴鍒锋柊鍗曡鍙鏂囨湰锛堣瑷€鐑垏鎹㈢敤锛夈€俓n     * 浠呮洿鏂?folder/action/model 琛岀殑 label / data-hint锛屼笉閲嶅缓 DOM銆佷笉涓㈢劍鐐逛笌鐩戝惉鍣ㄣ€俓n     * 鎺т欢琛岋紙slider/toggle/modeSlider/chips锛夌敱 registerControl 绠＄悊锛屾澶勮烦杩囥€俓n     */
    private refreshRowText(el: HTMLElement, row: PopupRow): void {
        if (
            row.kind === 'slider' ||
            row.kind === 'toggle' ||
            row.kind === 'modeSlider' ||
            row.kind === 'chips'
        ) {
            return;
        }
        // [doc:adr-129] sectionTitle锛氱洿鎺ユ洿鏂?textContent锛堟棤 .slide-label 瀛愬厓绱狅級
        if (row.kind === 'sectionTitle') {
            el.textContent = row.label ?? '';
            return;
        }
        const labelEl = el.querySelector('.slide-label') as HTMLElement | null;
        if (labelEl) {
            labelEl.textContent = row.label ?? '';
        }
        const hint = row.sublabel || (row.model ? t('menu.noDesc') : t('menu.noHint'));
        el.setAttribute('data-hint', hint);
    }

    private async buildPanel(level: PopupLevel): Promise<void> {
        const seq = ++this._buildSeq;
        this.panel.innerHTML = '';
        // 閲婃斁涓婁竴娆?renderCustom 杩斿洖鐨?dispose
        this._customDispose?.();
        this._customDispose = null;
        // 姣忔閲嶅缓闈㈡澘锛屾竻绌烘棫鐨勬帶浠舵敞鍐岃〃
        this._controls = [];
        const list = document.createElement('div');
        list.className = 'slide-list';

        if (level.items.length === 0 && !level.renderCustom) {
            list.innerHTML = '<div class="slide-empty">' + t('common.empty') + '</div>';
        } else if (level.items.length > 0 && !level.renderCustom) {
            // 绾?items 鑿滃崟锛氭寜 divider 鍒嗙粍锛屾瘡缁勫寘涓€涓?lcard
            let card: HTMLElement | null = null;
            for (const row of level.items) {
                if (row.kind === 'divider') {
                    card = null; // 鍏抽棴褰撳墠缁勶紝涓嬩竴涓潪 divider 琛屽紑鍚柊缁刓n                    continue;
                }
                if (!card) {
                    card = document.createElement('div');
                    card.className = 'lcard';
                    list.appendChild(card);
                }
                const el = this.createRow(row);
                if (el) {
                    card.appendChild(el);
                }
            }
        } else {
            // 鏈?renderCustom锛氬厛娓叉煋 items 瀵艰埅琛岋紝鍐嶈皟鑷畾涔夊洖璋僜n            for (const row of level.items) {
                const el = this.createRow(row);
                if (el) {
                    list.appendChild(el);
                }
            }
            _renderingStack.push(this);
            try {
                const result = await level.renderCustom(list);
                if (typeof result === 'function') {
                    this._customDispose = result;
                }
            } catch (err) {
                console.error('[SlideMenu] renderCustom failed:', err);
                list.innerHTML = `<div class="slide-empty" style="color:var(--danger);">鍔犺浇澶辫触: ${err instanceof Error ? err.message : '鏈煡閿欒'}</div>`;
            } finally {
                _renderingStack.pop();
            }
        }
        // 鍙湁鏈€鏂扮殑 build 鎵?appendChild锛岄槻姝㈠苟鍙戝鑷撮噸澶峔n        if (seq === this._buildSeq) {
            this.panel.appendChild(list);
        }
    }

    /** 閲婃斁鎵€鏈夎祫婧愶紙娓呴櫎鍔ㄧ敾瀹氭椂鍣ㄣ€侀敭鐩?瑙︽懜鐩戝惉銆佺姸鎬侊級锛岃皟鐢ㄥ悗瀹炰緥涓嶅彲鍐嶇敤銆?*/
    dispose(): void {
        this._cancelAnim();
        if (this._unsubscribe) {
            this._unsubscribe();
            this._unsubscribe = null;
        }
        this._keydownDisp?.dispose();
        this._keydownDisp = null;
        this._keydownHandler = null;
        this._swipeTouchStartDisp?.dispose();
        this._swipeTouchStartDisp = null;
        this._swipeTouchStartHandler = null;
        this._swipeTouchEndDisp?.dispose();
        this._swipeTouchEndDisp = null;
        this._swipeTouchEndHandler = null;
        this.levels = [];
        this._cachedExtraBtns = null;
        // 娓呯悊 initControl 娉ㄥ唽鐨勯棴鍖呭紩鐢?+ panel DOM锛圓DR-106 琛ュ叏锛塡n        this._customDispose?.();
        this._customDispose = null;
        this._controls = [];
        this.panel.innerHTML = '';
    }

    private updateHeader(level: PopupLevel): void {
        this.headerEl.innerHTML = '';
        const backBtn = document.createElement('span');
        backBtn.className = 'slide-back';
        const backIcon = createIconifyIcon(
            this.levels.length > 1 ? 'lucide:chevron-left' : 'lucide:x'
        );
        if (backIcon) {
            backBtn.appendChild(backIcon);
        }
        if (this.levels.length > 1) {
            backBtn.addEventListener('click', () => this.pop());
        } else {
            backBtn.addEventListener('click', () => this.onClose());
        }
        this.headerEl.appendChild(backBtn);

        const title = document.createElement('span');
        title.className = 'slide-title';
        title.textContent = level.label || '';
        this.headerEl.appendChild(title);

        // === headerToggle 寮€鍏筹紙寮圭獥鏍囬鏃侊級===
        const ht = level.headerToggle;
        if (ht) {
            const toggle = document.createElement('label');
            toggle.className = 'toggle header-toggle';
            const input = document.createElement('input');
            input.type = 'checkbox';
            input.checked = ht.value;
            const slider = document.createElement('span');
            slider.className = 'slider';
            toggle.appendChild(input);
            toggle.appendChild(slider);
            toggle.addEventListener('click', (e) => {
                e.preventDefault();
                e.stopPropagation();
                input.checked = !input.checked;
                ht.onChange(input.checked);
            });
            this.headerEl.appendChild(toggle);

            // 鑷洿鏂版敮鎸乗n            if (ht.bind) {
                let cached = ht.value;
                const update = () => {
                    const v = !!ht.bind!();
                    if (v !== cached) {
                        cached = v;
                        input.checked = v;
                    }
                };
                this.registerControl(update);
            }
        }

        // 澶嶇敤棰濆鎸夐挳锛岄伩鍏嶆瘡娆￠噸寤哄垱寤烘柊 DOM + 鏃х洃鍚櫒娉勬紡
        if (!this._cachedExtraBtns) {
            this._cachedExtraBtns = this.extraButtonFactory?.() ?? [];
        }
        for (const btn of this._cachedExtraBtns) {
            this.headerEl.appendChild(btn);
        }
    }

    private createRow(row: PopupRow): HTMLElement | null {
        if (row.kind === 'divider') {
            const el = document.createElement('div');
            el.className = 'slide-divider';
            return el;
        }

        // [doc:adr-129] sectionTitle锛歭card 鍐呰瑙夊垎缁勭殑鏍囬琛岋紙闈炰氦浜掞紝浠呮覆鏌?.section-title锛塡n        if (row.kind === 'sectionTitle') {
            const el = document.createElement('div');
            el.className = 'section-title';
            el.textContent = row.label;
            el.dataset.rowKey = this.rowKey(row);
            return el;
        }

        // ======== 鏂?kind锛歴lider / toggle / modeSlider / chips ========
        // 杩欎簺 kind 涓嶆槸鍙偣鍑荤殑瀵艰埅琛岋紝鑰屾槸鍐呭祵鎺т欢琛屻€俓n        // 閫氳繃 ui-helpers 娓叉煋锛屽寘涓€灞傚甫 rowKey 鐨?wrapper 浠ユ敮鎸佸閲?patch銆俓n        if (
            row.kind === 'slider' ||
            row.kind === 'toggle' ||
            row.kind === 'modeSlider' ||
            row.kind === 'chips'
        ) {
            const wrapper = document.createElement('div');
            wrapper.dataset.rowKey = this.rowKey(row);
            wrapper.dataset.testid = this.rowKey(row);
            if (row.kind === 'slider') {
                addSliderRow(
                    wrapper,
                    row.label,
                    row.sliderValue ?? 0,
                    row.sliderMin ?? 0,
                    row.sliderMax ?? 1,
                    row.sliderStep ?? 0.1,
                    row.onSliderChange ?? (() => {}),
                    row.icon || undefined,
                    row.onSliderDragEnd
                );
            } else if (row.kind === 'toggle') {
                addToggleRow(
                    wrapper,
                    row.label,
                    row.toggleValue ?? false,
                    row.onToggleChange ?? (() => {}),
                    row.icon || undefined
                );
            } else if (row.kind === 'modeSlider') {
                addModeSlider(
                    wrapper,
                    row.label,
                    row.modeOptions ?? [],
                    row.modeValue as string & (string | number),
                    row.onModeChange ?? (() => {}),
                    row.icon || undefined
                );
            } else if (row.kind === 'chips') {
                wrapper.className = 'preset-group';
                for (const chip of row.chips ?? []) {
                    addPresetChip(wrapper, chip.label, !!chip.active, chip.onClick);
                }
            }
            return wrapper;
        }

        // ======== folder / model / action锛氬師鏈?slide-item 閫昏緫 ========

        // folder + headerToggle锛氬鎵樼粰 slideRow锛堜笌 renderCustom 涓殑瑙嗚涓€鑷达級
        if (row.kind === 'folder' && row.headerToggle) {
            const wrapper = document.createElement('div');
            slideRow(
                wrapper,
                row.icon,
                row.label,
                true,
                async () => {
                    const next = await this.onFolderEnter?.(row, this);
                    if (next) {
                        this.push(next);
                    }
                },
                row.sublabel,
                undefined,
                undefined,
                row.headerToggle
            );
            const el = wrapper.firstChild as HTMLElement | null;
            if (el) {
                el.dataset.rowKey = this.rowKey(row);
                el.dataset.testid = this.rowKey(row);
                const hint = row.sublabel || t('menu.noHint');
                el.setAttribute('data-hint', hint);
                el.addEventListener('mouseenter', () => {
                    if (this.focusIndex >= 0) {
                        this.clearFocus();
                        this.focusIndex = -1;
                    }
                    showHint(hint);
                    this.onHover?.(row, true);
                });
                el.addEventListener('mouseleave', () => {
                    hideHint();
                    this.onHover?.(row, false);
                });
            }
            return el;
        }

        const el = document.createElement('div');
        el.className = 'slide-item' + (row.focused ? ' slide-focused' : '');
        el.dataset.rowKey = this.rowKey(row);
        el.dataset.testid = this.rowKey(row);
        const hint = row.sublabel || (row.model ? t('menu.noDesc') : t('menu.noHint'));
        el.setAttribute('data-hint', hint);

        // === 缁熶竴宸︿晶琛屼负鍖猴細leading 浼樺厛浜庣函灞曠ず .slide-icon锛堜簰鏂ワ級===
        // leading 瀛樺湪鏃讹紝宸︿晶鍥炬爣琚覆鏌撲负鍙偣鍑绘寜閽紙淇濇寔 radio 鎸囩ず瑙嗚锛夛紝
        // 鐐瑰嚮 stopPropagation 鍚庤Е鍙戣鍔ㄤ綔锛堝鍒囩劍鐐癸級锛屼笌鏁磋 onClick 瑙ｈ€︺€俓n        if (row.leading) {
            el.appendChild(createLeadingBtn(row.leading));
        } else {
            const iconSpan = document.createElement('span');
            iconSpan.className = 'slide-icon';
            const iconEl = createIconifyIcon(row.icon);
            if (iconEl) {
                iconSpan.appendChild(iconEl);
            } else {
                iconSpan.textContent = row.icon;
            }
            el.appendChild(iconSpan);
        }

        const labelSpan = document.createElement('span');
        labelSpan.className = 'slide-label' + (row.wrapLabel ? ' wrap-2' : '');
        labelSpan.textContent = row.label;
        el.appendChild(labelSpan);

        // === 缁熶竴灏鹃儴琛屼负鍖猴細trailing | +(onAddClick) | 瑁呴グ `>`锛堜笁鑰呬簰鏂ワ級===
        // 鍙璁剧疆浜嗙浜岀偣鍑讳簨浠?鍥炬爣(trailing)锛屾垨 +(onAddClick)锛岃楗版€?`>` 鍗宠鍙栦唬锛孿n        // 浠庢瀯閫犱笂鏉滅粷銆屾枃浠跺す鏃㈡覆鏌?> 鍙堟覆鏌撶浜屾寜閽€嶇殑璇覆鏌撱€俓n        if (row.trailing) {
            el.appendChild(createTrailingBtn(row.trailing));
        } else if (row.onAddClick) {
            // `+` 鐢?lucide:plus 鍥炬爣锛屼笌 trailing 榻胯疆/leading radio 缁熶竴 iconify 娓叉煋锛?1px 椤舵弧锛塡n            el.appendChild(
                createTrailingBtn({
                    icon: 'lucide:plus',
                    title: t('library.loadModel'),
                    onClick: (e) => row.onAddClick!(),
                })
            );
        } else if (row.kind === 'folder') {
            const arrow = document.createElement('span');
            arrow.className = 'slide-arrow';
            arrow.textContent = '>';
            el.appendChild(arrow);
        }

        if (row.kind === 'folder') {
            el.addEventListener('click', async (e) => {
                if ((e.target as HTMLElement).closest('.slide-add-btn')) {
                    return;
                }
                const next = await this.onFolderEnter?.(row, this);
                if (next) {
                    this.push(next);
                }
            });
        } else {
            el.addEventListener('click', () => this.onItemClick(row, this));
        }

        el.addEventListener('mouseenter', () => {
            if (this.focusIndex >= 0) {
                this.clearFocus();
                this.focusIndex = -1;
            }
            showHint(hint);
            this.onHover?.(row, true);
        });
        el.addEventListener('mouseleave', () => {
            hideHint();
            this.onHover?.(row, false);
        });

        return el;
    }
}

