/**
 * canvas 鈫?base64 寮傛缂栫爜锛圓DR-017 A2-04锛夈€俓n * 鐢?toBlob 鏇夸唬 toDataURL锛岀紪鐮佺Щ鑷冲悗鍙扮嚎绋嬶紝闄嶄綆浣庣鏈?OOM 椋庨櫓銆俓n * toBlob 澶辫触鏃堕檷绾?toDataURL锛堝彈绾︽潫鐜鍏煎锛夈€俓n */
function canvasToBase64(
    canvas: HTMLCanvasElement,
    format: string,
    quality: number
): Promise<string> {
    return new Promise((resolve) => {
        canvas.toBlob(
            (blob) => {
                if (!blob) {
                    resolve(
                        canvas.toDataURL(format, quality).replace(/^data:image\/\w+;base64,/, '')
                    );
                    return;
                }
                const reader = new FileReader();
                reader.onload = () => {
                    const r = reader.result;
                    resolve(
                        typeof r === 'string'
                            ? r.replace(/^data:image\/\w+;base64,/, '')
                            : canvas
                                  .toDataURL(format, quality)
                                  .replace(/^data:image\/\w+;base64,/, '')
                    );
                };
                reader.onerror = () => {
                    resolve(
                        canvas.toDataURL(format, quality).replace(/^data:image\/\w+;base64,/, '')
                    );
                };
                reader.readAsDataURL(blob);
            },
            format,
            quality
        );
    });
}

