                            false,
                            () => getSceneMenu()?.push(buildPropDetailLevel(item.id)),
                            undefined,
                            undefined,
                            false,
                            undefined,
                            {
                                trailing: {
                                    icon: '脳',
                                    title: t('scene.deleteProp'),
                                    onClick: (e) => {
                                        e.stopPropagation();
                                        if (item.fromPropRegistry) {
                                            removeProp(item.id);
                                        } else {
                                            removeModel(item.id);
                                        }
                                        reRenderSceneMenu();
                                    },
                                },
                            }
                        );
                    }
                });
            },
        });
    }

    return nodes;
}

