type TextureSlotKey =
    'diffuseTexture' | 'toonTexture' | 'sphereTexture' | 'bumpTexture' | 'emissiveTexture';

type OutfitTextureSlot = 'diffuse' | 'toon' | 'spa' | 'normal' | 'emissive';

interface _SlotMapping {
    matName: string;
    slot: string;
    basename: string;
}

function _isSharedTexture(basename: string): boolean {
    const lower = basename.toLowerCase();
    if (lower.startsWith('shared_toon_texture_')) {
        return true;
    }
    return false;
}

function _collectSlotMappings(inst: ModelInstance): _SlotMapping[] {
    const result: _SlotMapping[] = [];
    const seen = new Set<string>();
    for (const mesh of inst.meshes) {
        const sm = mesh.material as StandardMaterial;
        if (!sm) {
            continue;
        }
        const matName = sm.name;
        const mmdSm = sm as MmdStandardMaterial;
        for (const [slot, tex] of [
            ['diffuse', sm.diffuseTexture],
            ['toon', mmdSm.toonTexture],
            ['spa', mmdSm.sphereTexture],
            ['normal', sm.bumpTexture],
            ['emissive', sm.emissiveTexture],
        ] as const) {
            if (!tex) {
                continue;
            }
            const url = (tex as Texture).name || (tex as Texture).url || '';
            const base = getBaseName(url.split('?')[0]) || '';
            if (!base) {
                continue;
            }
            if (_isSharedTexture(base)) {
                continue;
            }
            const key = matName + '|' + slot + '|' + base;
            if (seen.has(key)) {
                continue;
            }
            seen.add(key);
            result.push({ matName, slot, basename: base });
        }
    }
    return result;
}

// _encodePath 宸叉敼涓哄鐢?normPath锛園/core/utils锛塡n
export async function loadOutfits(id: string, signal?: AbortSignal): Promise<OutfitFile | null> {
    if (!_loadingOutfitsGuard.tryEnter(id)) {
        return null;
    }

    // [adr-105] AbortSignal锛氬厑璁稿閮ㄥ彇娑堬紱鍐呴儴 AbortController 鍚堝苟澶栭儴 signal
    let abortCtrl: AbortController | undefined;
    let effectiveSignal: AbortSignal;
    if (signal) {
        effectiveSignal = signal;
    } else {
        abortCtrl = new AbortController();
        effectiveSignal = abortCtrl.signal;
    }

    try {
        const inst = modelRegistry.get(id);
        if (!inst) {
            return null;
        }
        if (!inst.filePath) {
            return null;
        }

        // [adr-105] 姣忎釜 await 鐐瑰墠妫€鏌ュ彇娑堢姸鎬乗n        if (effectiveSignal.aborted) {
            return null;
        }

        try {
            const json = await LoadOutfitFile(inst.filePath);
            if (json) {
                const outfit: OutfitFile = JSON.parse(json);
                if (outfit.version && Array.isArray(outfit.variants)) {
                    inst.outfitFile = outfit;
                    return outfit;
                }
            }
        } catch {
            /* fall through */
        }

        if (effectiveSignal.aborted) {
            return null;
        }

        try {
            const mappings = _collectSlotMappings(inst);
            if (mappings.length === 0) {
                inst.outfitFile = undefined;
                return null;
            }
            const modelDir = getDirPath(inst.filePath);
            const subdirs = await ListSubDirs(modelDir);
            if (!subdirs || subdirs.length === 0) {
                inst.outfitFile = undefined;
                return null;
            }

            if (effectiveSignal.aborted) {
                return null;
            }

            interface _Probe {
                subdir: string;
                matName: string;
                slot: string;
                relPath: string;
                fullPath: string;
            }
            const seenPath = new Set<string>();
            const probes: _Probe[] = [];
            for (const subdir of subdirs) {
                for (const m of mappings) {
                    const relPath = subdir + '/' + m.basename;
                    const fullPath = modelDir + '/' + normPath(relPath);
                    if (seenPath.has(fullPath)) {
                        continue;
                    }
                    seenPath.add(fullPath);
                    probes.push({ subdir, matName: m.matName, slot: m.slot, relPath, fullPath });
                }
            }
            const headCache = new Map<string, boolean>();
            // 骞跺彂闄愬埗锛氶伩鍏嶅澶ч噺瀛愮洰褰曞悓鏃跺彂璧锋暟鐧句釜 HEAD 璇锋眰
            const HEAD_CONCURRENCY = 6;
            const semaphore = { count: 0 };
            const withLimit = async <T>(fn: () => Promise<T>): Promise<T> => {
                while (semaphore.count >= HEAD_CONCURRENCY) {
                    await delay(10);
                    if (effectiveSignal.aborted) {
                        break;
                    }
                }
                semaphore.count++;
                try {
                    return await fn();
                } finally {
                    semaphore.count--;
                }
            };
            const results = await Promise.all(
                subdirs.map(async (subdir): Promise<OutfitVariant | null> => {
                    if (effectiveSignal.aborted) {
                        return null;
                    }
                    const byMaterial: Record<string, OutfitSlot> = {};
                    let hasAny = false;
                    const subdirProbes = probes.filter((p) => p.subdir === subdir);
                    await Promise.all(
                        subdirProbes.map(async (p) => {
                            if (effectiveSignal.aborted) {
                                return;
                            }
                            let ok: boolean;
                            if (headCache.has(p.fullPath)) {
                                ok = headCache.get(p.fullPath)!;
                            } else {
                                ok = await withLimit(async () => {
                                    try {
                                        return await FileExists(p.fullPath);
                                    } catch {
                                        return false;
                                    }
                                });
                                headCache.set(p.fullPath, ok);
                            }
                            if (!ok) {
                                return;
                            }
                            if (!byMaterial[p.matName]) {
                                byMaterial[p.matName] = {};
                            }
                            (byMaterial[p.matName] as Record<string, string>)[p.slot] = p.relPath;
                            hasAny = true;
                        })
                    );
                    return hasAny ? { name: subdir, byMaterial } : null;
                })
            );
            const variantList: OutfitVariant[] = results.filter(Boolean) as OutfitVariant[];
            if (variantList.length === 0) {
                inst.outfitFile = undefined;
                return null;
            }
            const outfit: OutfitFile = { version: 1, variants: variantList };
            inst.outfitFile = outfit;
            return outfit;
        } catch {
            inst.outfitFile = undefined;
            return null;
        }
    } finally {
        abortCtrl?.abort(); // 娓呯悊鍐呴儴 AbortController
        _loadingOutfitsGuard.leave(id);
    }
}

async function _applySlot(
    sm: StandardMaterial,
    slot: TextureSlotKey,
    newPath: string | null,
    origTex: Texture | null,
    modelDir: string
): Promise<void> {
    const mmdSm = sm as MmdStandardMaterial & Record<TextureSlotKey, Texture | null>;
    const cur = mmdSm[slot];
    if (newPath) {
        const scene = await _getScene();
        // ReadFileBytes 鈫?base64 鈫?Blob URL锛堟浛鎹?HTTP 涓浆锛塡n        const bytes = await readFileBytes(modelDir + '/' + normPath(newPath));
        if (!bytes) {
            logWarn('outfit', '_applySlot: failed to read texture', newPath);
            return;
        }
        const ext = newPath.split('.').pop()?.toLowerCase() || 'png';
        const mimeMap: Record<string, string> = {
            png: 'image/png',
            jpg: 'image/jpeg',
            jpeg: 'image/jpeg',
            bmp: 'image/bmp',
            tga: 'image/x-tga',
            dds: 'image/vnd-ms.dds',
            spa: 'image/png',
            sph: 'image/png',
        };
        const blob = new Blob([bytes.buffer as ArrayBuffer], {
            type: mimeMap[ext] || 'application/octet-stream',
        });
        const url = URL.createObjectURL(blob);
        const newTex = new Texture(url, scene);
        let loaded = false;
        await new Promise<void>((resolve) => {
            if (newTex.isReady()) {
                loaded = true;
                resolve();
                return;
            }
            const handle = observe(newTex.onLoadObservable, () => {
                handle.dispose();
                loaded = true;
                resolve();
            });
            setTimeout(() => {
                handle.dispose();
                resolve(); // 瓒呮椂锛歭oaded 淇濇寔 false
            }, 5000);
        });
        if (loaded) {
            if (cur && cur !== origTex) {
                cur.dispose();
            }
            mmdSm[slot] = newTex;
            URL.revokeObjectURL(url);
        } else {
            let done = false;
            const trySwap = (): void => {
                if (done) {
                    return;
                }
                done = true;
                URL.revokeObjectURL(url);
                if (mmdSm[slot] === cur) {
                    if (cur && cur !== origTex) {
                        cur.dispose();
                    }
                    mmdSm[slot] = newTex;
                } else {
                    newTex.dispose();
                }
            };
            if (newTex.isReady()) {
                trySwap();
            } else {
                const handle = observe(newTex.onLoadObservable, () => {
                    handle.dispose();
                    trySwap();
                });
            }
        }
    } else {
        if (origTex) {
            if (cur && cur !== origTex) {
                cur.dispose();
            }
            mmdSm[slot] = origTex;
        }
    }
}

function _getSlotFor(
    variant: OutfitVariant | undefined,
    smName: string,
    cat: string,
    slotKey: OutfitTextureSlot
): string | null {
    if (!variant) {
        return null;
    }
    const v =
        variant.byMaterial?.[smName]?.[slotKey] ??
        variant.byCategory?.[cat]?.[slotKey] ??
        variant.all?.[slotKey];
    return v ?? null;
}

function _getParamsFor(
    variant: OutfitVariant | undefined,
    smName: string,
    cat: string
): OutfitSlot['params'] | undefined {
    if (!variant) {
        return undefined;
    }
    return (
        variant.byMaterial?.[smName]?.params ??
        variant.byCategory?.[cat]?.params ??
        variant.all?.params
    );
}

function _getTintFor(
    variant: OutfitVariant | undefined,
    smName: string,
    cat: string
): [number, number, number] | undefined {
    if (!variant) {
        return undefined;
    }
    const t =
        variant.byMaterial?.[smName]?.tint ?? variant.byCategory?.[cat]?.tint ?? variant.all?.tint;
    return t;
}

function _applyOutfitParams(
    sm: StandardMaterial,
    params: OutfitSlot['params'],
    orig: {
        diffuseR: number;
        diffuseG: number;
        diffuseB: number;
        specularR: number;
        specularG: number;
        specularB: number;
        specularPower: number;
        ambientR: number;
        ambientG: number;
        ambientB: number;
    }
): void {
    if (!params) {
        return;
    }
    if (params.diffuseMul !== undefined) {
        sm.diffuseColor.set(
            orig.diffuseR * params.diffuseMul,
            orig.diffuseG * params.diffuseMul,
            orig.diffuseB * params.diffuseMul
        );
    }
    if (params.specularMul !== undefined) {
        sm.specularColor.set(
            orig.specularR * params.specularMul,
            orig.specularG * params.specularMul,
            orig.specularB * params.specularMul
        );
    }
    if (params.shininess !== undefined) {
        sm.specularPower = params.shininess;
    }
    if (params.ambientMul !== undefined) {
        sm.ambientColor.set(
            orig.ambientR * params.ambientMul,
            orig.ambientG * params.ambientMul,
            orig.ambientB * params.ambientMul
        );
    }
}

function _applyOutfitTint(sm: StandardMaterial, tint: [number, number, number]): void {
    sm.diffuseColor.multiplyInPlace(col3FromTriple(tint));
}

function _captureOrigParams(inst: ModelInstance): void {
    if (inst._origParams) {
        return;
    }
    inst._origParams = new Map();
    for (let mi = 0; mi < inst.meshes.length; mi++) {
        const sm = inst.meshes[mi].material as StandardMaterial;
        if (!sm) {
            continue;
        }
        inst._origParams.set(mi, {
            diffuseR: sm.diffuseColor.r,
            diffuseG: sm.diffuseColor.g,
            diffuseB: sm.diffuseColor.b,
            specularR: sm.specularColor.r,
            specularG: sm.specularColor.g,
            specularB: sm.specularColor.b,
            specularPower: sm.specularPower,
            ambientR: sm.ambientColor.r,
            ambientG: sm.ambientColor.g,
            ambientB: sm.ambientColor.b,
        });
    }
}

// 骞跺彂閿侊細闃叉鍚屼竴妯″瀷鐨勫彉浣撳簲鐢ㄥ苟鍙戞墽琛屽鑷寸珵鎬乗nconst _applyingVariantGuard = new LoadingGuard();

// R3 鍘婚噸锛氶槻姝㈠鍚屼竴妯″瀷骞跺彂鎵ц loadOutfits 瀵艰嚧閲嶅璇锋眰
const _loadingOutfitsGuard = new LoadingGuard();

// 骞跺彂闃熷垪锛氬揩閫熷垏鎹㈠彉浣撴椂璁板綍鏈€鏂颁竴娆¤姹傦紙last-wins锛夛紝寰呭綋鍓嶅簲鐢ㄥ畬鎴愬悗鍐嶆墽琛岋紝
// 閬垮厤鐩存帴 return 瀵艰嚧鐢ㄦ埛鐐瑰嚮鐨勫垏鎹㈣闈欓粯涓㈠純
const _pendingVariant = new Map<string, string>();

export async function applyOutfitVariant(id: string, variantName: string): Promise<void> {
    if (_applyingVariantGuard.isLoading(id)) {
        _pendingVariant.set(id, variantName);
        return;
    }
    _applyingVariantGuard.tryEnter(id);
    try {
        let target = variantName;
        for (;;) {
            await _applyOutfitVariantCore(id, target);
            const next = _pendingVariant.get(id);
            if (next === undefined) {
                break;
            }
            _pendingVariant.delete(id);
            target = next;
        }
    } finally {
        _applyingVariantGuard.leave(id);
    }
}

async function _applyOutfitVariantCore(id: string, variantName: string): Promise<void> {
    const inst = modelRegistry.get(id);
    if (!inst) {
        return;
    }
    if (!inst.outfitFile) {
        return;
    }
    const variant =
        variantName === RESET_VARIANT
            ? undefined
            : inst.outfitFile.variants.find((v) => v.name === variantName);
    if (!variant && variantName !== RESET_VARIANT) {
        return;
    }

    if (!inst._origTextures) {
        inst._origTextures = new Map();
        for (let mi = 0; mi < inst.meshes.length; mi++) {
            const sm = inst.meshes[mi].material as StandardMaterial;
            if (!sm) {
                continue;
            }
            const mmdSm = sm as MmdStandardMaterial;
            inst._origTextures.set(mi, {
                diffuse: sm.diffuseTexture as Texture | null,
                toon: mmdSm.toonTexture,
                spa: mmdSm.sphereTexture,
                normal: sm.bumpTexture as Texture | null,
                emissive: sm.emissiveTexture as Texture | null,
            });
        }
    }
    _captureOrigParams(inst);

    const promises: Promise<void>[] = [];

    // overlay 澶勭悊锛堜笌绾圭悊鏇挎崲骞惰锛夛細娓呯悊鏃?overlay 鈫?鍔犺浇鏂?overlay 鈫?闅愯棌 PMX 甯冩枡
    // token 瀹堝崼锛氶槻姝㈠揩閫熷垏鎹㈠彉浣撴椂锛屾棫 loadOverlay 瀹屾垚鍚庤鐩栨柊鐘舵€佸鑷村鍎?mesh 娉勬紡
    const token = Symbol('overlay');
    inst._overlayLoadToken = token;
    promises.push(
        (async () => {
            if (inst._overlayMeshes) {
                disposeOverlay(inst);
                restoreMaterials(inst);
            }
            if (variant?.meshFile) {
                const { meshes, retargetOk } = await loadOverlay(
                    inst,
                    variant.meshFile,
                    await _getScene()
                );
                // token 杩囨湡锛氳鏄庢鏈熼棿宸插垏鎹㈠埌鍏朵粬鍙樹綋锛屼涪寮冩湰娆＄粨鏋淺n                if (inst._overlayLoadToken !== token) {
                    console.info('[outfit] overlay load stale (token mismatch), discarding');
                    for (const m of meshes) {
                        try {
                            m.dispose();
                        } catch {
                            // ignore
                        }
                    }
                    return;
                }
                // 浠呭湪 overlay 鎴愬姛鍔犺浇涓旈楠奸噸瀹氬悜鎴愬姛鏃堕殣钘?PMX 甯冩枡锛沑n                // retarget 澶辫触锛堥潤鎬侀檷绾э級鏃朵繚鐣欏師甯冩枡锛岄伩鍏嶇┛妯n                if (meshes.length > 0 && retargetOk && variant.hideMaterials) {
                    hideMaterials(inst, variant.hideMaterials);
                } else if (meshes.length > 0 && !retargetOk && variant.hideMaterials) {
                    logWarn(
                        'outfit',
                        'FBX overlay retarget failed, keeping PMX materials to avoid绌挎ā'
                    );
                }
            }
        })()
    );

    for (let mi = 0; mi < inst.meshes.length; mi++) {
        const sm = inst.meshes[mi].material as StandardMaterial;
        if (!sm) {
            continue;
        }
        const origTex = inst._origTextures.get(mi);
        if (!origTex) {
            continue;
        }
        const origParams = inst._origParams.get(mi)!;
        const cat = _catOf(sm);

        promises.push(
            _applySlot(
                sm,
                'diffuseTexture',
                _getSlotFor(variant, sm.name, cat, 'diffuse'),
                origTex.diffuse,
                inst.modelDir
            )
        );
        promises.push(
            _applySlot(
                sm,
                'toonTexture',
                _getSlotFor(variant, sm.name, cat, 'toon'),
                origTex.toon,
                inst.modelDir
            )
        );
        promises.push(
            _applySlot(
                sm,
                'sphereTexture',
                _getSlotFor(variant, sm.name, cat, 'spa'),
                origTex.spa,
                inst.modelDir
            )
        );
        promises.push(
            _applySlot(
                sm,
                'bumpTexture',
                _getSlotFor(variant, sm.name, cat, 'normal'),
                origTex.normal,
                inst.modelDir
            )
        );
        promises.push(
            _applySlot(
                sm,
                'emissiveTexture',
                _getSlotFor(variant, sm.name, cat, 'emissive'),
                origTex.emissive,
                inst.modelDir
            )
        );

        const slotParams = _getParamsFor(variant, sm.name, cat);
        if (slotParams) {
            _applyOutfitParams(sm, slotParams, origParams);
        }

        const tint = _getTintFor(variant, sm.name, cat);
        if (tint) {
            _applyOutfitTint(sm, tint);
        }
    }

    await Promise.all(promises);
    inst.activeVariant = variantName;
    setStatus(t('outfit.switched', { name: variantName }), true);
    triggerAutoSave();
}

export async function resetOutfit(id: string): Promise<void> {
    const inst = modelRegistry.get(id);
    if (!inst) {
        return;
    }
    const promises: Promise<void>[] = [];
    if (inst._origTextures) {
        for (let mi = 0; mi < inst.meshes.length; mi++) {
            const sm = inst.meshes[mi].material as StandardMaterial;
            if (!sm) {
                continue;
            }
            const orig = inst._origTextures.get(mi);
            if (!orig) {
                continue;
            }
            promises.push(_applySlot(sm, 'diffuseTexture', null, orig.diffuse, inst.modelDir));
            promises.push(_applySlot(sm, 'toonTexture', null, orig.toon, inst.modelDir));
            promises.push(_applySlot(sm, 'sphereTexture', null, orig.spa, inst.modelDir));
            promises.push(_applySlot(sm, 'bumpTexture', null, orig.normal, inst.modelDir));
            promises.push(_applySlot(sm, 'emissiveTexture', null, orig.emissive, inst.modelDir));
        }
    }
    await Promise.all(promises);
    if (inst._origParams) {
        for (let mi = 0; mi < inst.meshes.length; mi++) {
            const sm = inst.meshes[mi].material as StandardMaterial;
            if (!sm) {
                continue;
            }
            const p = inst._origParams.get(mi);
            if (!p) {
                continue;
            }
            sm.diffuseColor.set(p.diffuseR, p.diffuseG, p.diffuseB);
            sm.specularColor.set(p.specularR, p.specularG, p.specularB);
            sm.specularPower = p.specularPower;
            sm.ambientColor.set(p.ambientR, p.ambientG, p.ambientB);
        }
    }
    // 娓呯悊 overlay mesh 骞舵仮澶嶈闅愯棌鐨?PMX 鏉愯川
    // token 澶辨晥锛屼娇杩涜涓殑 loadOverlay 瀹屾垚鍚庝涪寮冪粨鏋淺n    inst._overlayLoadToken = undefined;
    disposeOverlay(inst);
    restoreMaterials(inst);

    inst.activeVariant = undefined;
    inst.outfitFile = undefined;
    inst._origTextures = undefined;
    inst._origParams = undefined;
    triggerAutoSave();
}

/**
 * wind-physics.ts 鈥?椋庡姏娉ㄥ叆 WASM Bullet 鐗╃悊
 *
 * 閫氳繃 MmdWasmPhysicsRuntimeImpl.onSyncObservable 鍦ㄦ瘡娆＄墿鐞嗘杩涘墠
 * 瀵规墍鏈?Dynamic 鍒氫綋鏂藉姞椋庡姏锛屼娇澶村彂/瑁欏瓙绛夌墿鐞嗛儴浠跺彈椋庡奖鍝嶃€俓n *
 * 璁捐绾︽潫锛歕n * - 浠?WASM 杩愯鏃剁敓鏁堬紙JS 杩愯鏃舵棤 Bullet 鐗╃悊锛岄浠嶅奖鍝?XPBD 甯冩枡/绮掑瓙锛塡n * - Kinematic 鍒氫綋锛堥楠艰窡闅忥級涓嶅彈鍔涳紝Bullet 鑷姩蹇界暐
 * - 閫氳繃鍙嶅皠璁块棶 babylon-mmd 鍐呴儴瀛楁锛坃rigidBodyBundleMap锛夛紝
 *   babylon-mmd 鍗囩骇鏃惰嫢瀛楁閲嶅懡鍚嶄細闈欓粯闄嶇骇锛堢┖鏁扮粍鈫掗鍔涙秷澶憋級锛孿n *   姝ゆ椂闇€妫€鏌?babylon-mmd Physics/Bind/Impl/physicsRuntime.d.ts 鏇存柊閫傞厤
 */

import { Vector3 } from '@babylonjs/core/Maths/math.vector';
import type { IMmdRuntime } from 'babylon-mmd/esm/Runtime/IMmdRuntime';
import { MmdWasmRuntime as MmdWasmRuntimeClass } from 'babylon-mmd/esm/Runtime/Optimized/mmdWasmRuntime';
import type { MmdWasmPhysicsRuntimeImpl } from 'babylon-mmd/esm/Runtime/Optimized/Physics/mmdWasmPhysicsRuntimeImpl';
import { getWindVector, isWindActive } from '../core/wind-utils';
import { observe, type ObserverHandle } from '@/core/observer-handle';

/** 椋庡姏绯绘暟 鈥?Bullet 鍒氫綋璐ㄩ噺鎯€уぇ锛岄渶瑕佹瘮 XPBD 甯冩枡鏇村ぇ鐨勭郴鏁?*/
const WIND_FORCE_SCALE = 0.15;

/** 涓存椂鍚戦噺锛岄伩鍏嶆瘡甯у垎閰?*/
const _tmpWind = new Vector3();

/** 姣忚繍琛屾椂璁㈤槄鐘舵€侊細鏀寔澶?MmdWasmRuntime 鍦烘櫙锛堝鍦烘櫙/澶氱獥鍙ｏ級 */
interface _WindSub {
    /** 宸茶闃呯殑 observer锛岀敤浜庣簿纭Щ闄わ紙涓嶈浼ゅ叾浠栬闃呰€咃級 */
    observer: ObserverHandle | null;
}
const _subs = new Map<IMmdRuntime, _WindSub>();

/**
 * 灏濊瘯浠?MmdWasmRuntime 鑾峰彇 PhysicsRuntimeImpl銆俓n * physics impl 鍦ㄩ涓ā鍨嬪姞杞藉墠涓?null锛岄渶寤惰繜鑾峰彇銆俓n */
function _getPhysicsImpl(runtime: IMmdRuntime): MmdWasmPhysicsRuntimeImpl | null {
    const physics = (runtime as any).physics;
    if (!physics) {
        return null;
    }
    // MmdWasmPhysicsRuntime.impl 鏄?public getter
    const impl = physics.impl;
    return impl ?? null;
}

/**
 * 浠?PhysicsRuntimeImpl 鑾峰彇鎵€鏈?RigidBodyBundle銆俓n * 鍙嶅皠璁块棶 _rigidBodyBundleMap锛圡ap<RigidBodyBundle, number>锛夈€俓n * babylon-mmd 鍗囩骇鑻ラ噸鍛藉悕姝ゅ瓧娈碉紝鐩存帴鎶涢敊銆俓n */
export function _getBundles(
    impl: MmdWasmPhysicsRuntimeImpl
): Iterable<{ count: number; applyCentralForce(index: number, force: Vector3): void }> {
    const map = (impl as any)._rigidBodyBundleMap;
    if (map instanceof Map) {
        return map.keys();
    }
    // babylon-mmd 鍗囩骇鍙兘閲嶅懡鍚?绉婚櫎璇ュ瓧娈碉細鐩存帴鎶涢敊
    if (map === undefined) {
        throw new Error(
            'wind-physics: _rigidBodyBundleMap 涓嶅瓨鍦紙鍙兘宸茶 babylon-mmd 閲嶅懡鍚嶏級銆傛鏌?babylon-mmd 鐗堟湰鍏煎鎬?
        );
    }
    throw new Error('wind-physics: _rigidBodyBundleMap 绫诲瀷寮傚父銆傛鏌?babylon-mmd 鐗堟湰鍏煎鎬?);
}

/**
 * physics sync 鍥炶皟 鈥?鍦?Bullet 璇勪及鍓嶆柦鍔犻鍔涖€俓n * 娉ㄦ剰锛欱uffered 妯″紡涓嬫鍥炶皟鍦ㄩ攣鍐呮墽琛岋紝applyCentralForce 浼氳嚜鍔ㄧ瓑寰呴攣銆俓n */
function _onPhysicsSync(impl: MmdWasmPhysicsRuntimeImpl): void {
    if (!isWindActive()) {
        return;
    }

    const wind = getWindVector();
    _tmpWind.copyFrom(wind).scaleInPlace(WIND_FORCE_SCALE);

    for (const bundle of _getBundles(impl)) {
        const count = bundle.count;
        for (let i = 0; i < count; i++) {
            bundle.applyCentralForce(i, _tmpWind);
        }
    }
}

/**
 * 鍒濆鍖栭鍔涚墿鐞嗘敞鍏ャ€俓n * 鍦?scene.ts 涓?MmdWasmRuntime 鍒涘缓鍚庤皟鐢ㄣ€俓n *
 * 鐢变簬 physics impl 寤惰繜鍒涘缓锛堥涓ā鍨嬪姞杞芥椂锛夛紝姝ゅ璁㈤槄鍙兘澶辫触锛孿n * 鐢?model-loader 鍦ㄦā鍨嬪姞杞芥垚鍔熷悗璋冪敤 retryWindPhysicsSubscription() 鏄惧紡閲嶈瘯銆俓n *
 * 瀹夊叏鎬э細骞傜瓑鈥斺€旈噸澶嶈皟鐢ㄤ笉浼氶噸澶嶈闃呫€俓n *
 * [adr-104] 宸茬Щ闄ゅ師 monkey-patch createMmdModel 鐨勫仛娉曪紙鑴嗗急锛孿n * babylon-mmd 鍐呴儴瀹炵幇鍙樻洿鍗抽潤榛樺け鏁堬級锛屾敼涓烘樉寮忚皟鐢ㄧ偣鎵胯浇銆俓n */
export function initWindPhysics(runtime: IMmdRuntime): void {
    if (!(runtime instanceof MmdWasmRuntimeClass)) {
        return;
    }
    let sub = _subs.get(runtime);
    if (!sub) {
        sub = { observer: null };
        _subs.set(runtime, sub);
    }
    // 灏濊瘯绔嬪嵆璁㈤槄锛堝鏋?impl 宸插瓨鍦級锛涘惁鍒欑敱 retry 鍦ㄦā鍨嬪姞杞藉悗琛ラ綈
    _trySubscribe(runtime);
}

/**
 * [adr-104] 妯″瀷鍔犺浇鎴愬姛鍚庣敱 model-loader 鏄惧紡璋冪敤锛岄噸璇曡闃?physics impl
 * 锛堟鏃?physics impl 宸插氨缁級銆傛浛浠ｅ師 monkey-patch createMmdModel 鐨勮剢寮卞仛娉曘€俓n *
 * @param runtime 鎸囧畾杩愯鏃讹紱鐪佺暐鏃堕噸璇曟墍鏈夊凡娉ㄥ唽杩愯鏃讹紙鐢ㄤ簬鍏ㄥ眬閲嶈瘯鍦烘櫙锛塡n */
export function retryWindPhysicsSubscription(runtime?: IMmdRuntime): void {
    if (runtime) {
        _trySubscribe(runtime);
        return;
    }
    for (const rt of _subs.keys()) {
        _trySubscribe(rt);
    }
}

function _trySubscribe(runtime: IMmdRuntime): void {
    const sub = _subs.get(runtime);
    if (!sub || sub.observer) {
        return;
    } // 宸茶闃匼n
    const impl = _getPhysicsImpl(runtime);
    if (!impl) {
        return;
    }

    sub.observer = observe(impl.onSyncObservable, () => _onPhysicsSync(impl));
}

/**
 * 閿€姣侀鍔涚墿鐞嗘敞鍏ャ€俓n * 浠呯Щ闄よ嚜宸辩殑 observer锛屼笉褰卞搷鍏朵粬 onSyncObservable 璁㈤槄鑰呫€傞噸缃墍鏈夌姸鎬併€俓n */
export function disposeWindPhysics(): void {
    for (const [, sub] of _subs) {
        if (sub.observer) {
            sub.observer.dispose();
        }
    }
    _subs.clear();
}

/**
 * 褰撳墠杩愯鏃舵槸鍚﹀疄闄呭惎鐢ㄤ簡椋庡姏鐗╃悊锛圵ASM Bullet锛夈€俓n * 渚?UI 灞傚垽鏂槸鍚﹂渶瑕佹樉绀篭

鐨勬彁绀恒€俓n */
export function isWindPhysicsActive(): boolean {
    for (const sub of _subs.values()) {
        if (sub.observer) {
            return true;
        }
    }
    return false;
}

