        p.distance,
        new Vector3(0, getFocusCenterY() + p.targetHeight, 0),
        scene
    );
    cam.minZ = 0.1;
    cam.lowerRadiusLimit = 2;
    cam.upperRadiusLimit = 50;
    installInvertablePointers(cam);
