    let mode = s.mode || s.preset.mode;
    // 瀛樻。鎭㈠鏃惰烦杩?AR锛氳繘鍏?AR 闇€瑕佺敤鎴锋墜鍔挎巿鏉冩憚鍍忓ご锛屽惎鍔ㄦ椂鏃犳墜鍔胯皟 getUserMedia
    // 澶氭暟娴忚鍣ㄤ細鐩存帴鎷掔粷锛涚敤鎴峰彲鍦ㄥ姞杞藉悗鎵嬪姩杩涘叆 AR銆俓n    if (s.preset) {
