        // 鐜伴噸瀹氬悜涓?surround锛堢幆缁?杞彴锛夛紝concert 褰掍綅涓恒€岀矇涓濇満浣嶃€嶃€俓n        const oldConcert = loaded.concert as Record<string, any> | undefined;
        if (oldConcert && 'speed' in oldConcert && !('sweepAngle' in oldConcert)) {
            loaded.surround = {
                radius: (oldConcert.radius ?? def.surround.radius) as number,
                height: (oldConcert.height ?? def.surround.height) as number,
                speed: (oldConcert.speed ?? def.surround.speed) as number,
            };
            if (mode === 'concert') {
                mode = 'surround';
            }
            delete (loaded as Partial<CameraPreset>).concert;
        }
        // 娣卞悎骞跺埌榛樿棰勮锛岃ˉ榻愭柊澧?缂哄け瀛楁锛岄槻姝㈡棫瀛樻。缂哄瓧娈靛鑷?NaN銆俓n        setCameraPreset({
            mode: loaded.mode ?? def.mode,
            orbit: { ...def.orbit, ...(loaded.orbit || {}) },
            freefly: { ...def.freefly, ...(loaded.freefly || {}) },
            surround: { ...def.surround, ...(loaded.surround || {}) },
            concert: { ...def.concert, ...(loaded.concert || {}) },
        });
    }

    // 鈹€鈹€ ADR-100 P3锛氬弻杞磋В鏋愶紙鏂板瓧娈典紭鍏堬紝鏃?mode 鍏滃簳锛夆攢鈹€
    let control: CameraControl;
    let behavior: CameraBehavior;
    let sub: ScriptedSubMode = 'loop';
    if (s.control && s.behavior) {
        control = s.control;
        behavior = s.behavior;
        sub = s.scriptedSubMode ?? 'loop';
    } else {
        const m = LEGACY_MODE_MAP[mode];
        // ADR-100 P3 杈圭晫鍔犲浐锛氶儴鍒嗘柊瀛楁瀛樻。锛堜粎 control 鎴栦粎 behavior 鍏朵竴锛夐€愬瓧娈靛厹搴曪紝
        // 閬垮厤榻愬叏鍒ゅ畾缂哄け鏃舵暣娈靛洖閫€ LEGACY_MODE_MAP 瀵艰嚧宸叉彁渚涚殑瀛楁闈欓粯涓㈠け銆俓n        control = s.control ?? m.control;
        behavior = s.behavior ?? m.behavior;
        sub = s.scriptedSubMode ?? m.scripted ?? 'loop';
    }
    // 鏃у瓨妗ｄ粎浠?UIState.autoCameraEnabled 鏍囪鑷姩杩愰暅 鈫?鍙犲姞涓?beatcut锛埪?.2 step3锛夈€俓n    // ADR-100 P3 鏀剁揣锛氫粎褰?control/behavior 鍙岃酱鍧囩己澶憋紙绾棫鏍煎紡锛夋墠鍙犲姞锛孿n    // 閬垮厤閮ㄥ垎鏂板瓧娈靛瓨妗ｏ紙宸叉樉寮忓０鏄?behavior锛夎闄堟棫 autoCameraEnabled 瑕嗙洊锛圥2 鏉冨▉鍘熷垯锛夈€俓n    if (
