    const finalMode = deriveLegacyMode(control, behavior, sub);

    // 鐩存帴娲剧敓鍙岃酱鐘舵€侊細涓嶄緷璧?scene锛屼繚璇佹棤澶?娴嬭瘯鐜浜﹀彲鎭㈠锛坰witchCameraMode 鍦ㄦ棤 scene 鏃朵负 no-op锛夈€俓n    _syncAxesFromMode(finalMode);

    // 鐩告満鐢熷懡鍛ㄦ湡锛堥渶 scene锛涙棤澶寸幆澧冧负 no-op锛屼絾鐘舵€佸凡灏辩华锛塡n    if (finalMode && finalMode !== 'ar') {
