// 灏?setEnvState 涓法绯荤粺瀛楁鐨勭壒鍒?if-block 鎶藉彇涓虹嫭绔?middleware锛孿n// 鏂板璺ㄧ郴缁熷瓧娈靛彧闇€娉ㄥ唽涓€涓柊 middleware锛屼笉瑙﹀強鏍稿績娴佺▼銆俓n//
// middleware 鍒嗕袱闃舵鎵ц锛歕n// - pre-facade: 鍦?_applyEnvStateFacade 涔嬪墠锛岀敤浜庤ˉ鍏?envState/migrated
// - post-facade: 鍦?_applyEnvStateFacade 涔嬪悗锛岀敤浜庡鐞嗗壇浣滅敤锛堝璋冪敤 setPerformanceMode锛塡n//
// 閿欒闅旂锛氬崟涓?middleware 鎶涘紓甯镐笉褰卞搷鍚庣画 middleware 鍜?persist/autoSave銆俓n
type EnvStateMiddlewareFn = (
    envState: EnvState,
    migrated: Partial<EnvState>,
    ctx: { skipAutoSave: boolean }
) => void;

interface EnvStateMiddleware {
    name: string;
    phase: 'pre-facade' | 'post-facade';
    fn: EnvStateMiddlewareFn;
}

const _middlewares: EnvStateMiddleware[] = [];

/** 娉ㄥ唽 setEnvState 涓棿浠讹紙浠呴檺 env-bridge.ts 鍐呰皟鐢級 */
function registerEnvStateMiddleware(mw: EnvStateMiddleware): void {
    _middlewares.push(mw);
}

/** 鎸夐樁娈甸亶鍘?middleware锛屽紓甯搁殧绂?*/
function _runMiddlewares(
    phase: 'pre-facade' | 'post-facade',
    envState: EnvState,
    migrated: Partial<EnvState>,
    ctx: { skipAutoSave: boolean }
): void {
    for (const mw of _middlewares) {
        if (mw.phase !== phase) {
            continue;
        }
        try {
            mw.fn(envState, migrated, ctx);
        } catch (e) {
            console.warn(`[env-mw] ${mw.name} failed`, e);
        }
    }
}

