const WEATHER_TYPES = ['sakura', 'rain', 'snow', 'leaves'];

/** 澶╂皵绫诲瀷鐨勭洅鍙戝皠鍣ㄦ柟鍚戝弬鏁?*/
const WEATHER_BOX_DIRS: Record<
    string,
    { dir1: [number, number, number]; dir2: [number, number, number] }
> = {
    sakura: { dir1: [-0.5, -0.2, -0.5], dir2: [0.5, 0.2, 0.5] },
    rain: { dir1: [-0.1, -1, -0.1], dir2: [0.1, -1, 0.1] },
    snow: { dir1: [-0.5, -0.3, -0.5], dir2: [0.5, -0.3, 0.5] },
    leaves: { dir1: [-0.8, -0.3, -0.8], dir2: [0.8, 0.3, 0.8] },
};

function _applyParticleConfig(ps: ParticleSystem, cfg: ParticleConfig, type: string): void {
    ps.blendMode = cfg.blendMode;
    ps.emitRate = cfg.emitRate;
    ps.gravity = new Vector3(...cfg.gravity);
    ps.minLifeTime = cfg.minLifeTime;
    ps.maxLifeTime = cfg.maxLifeTime;
    ps.minEmitPower = cfg.minEmitPower;
    ps.maxEmitPower = cfg.maxEmitPower;
    ps.minSize = cfg.minSize;
    ps.maxSize = cfg.maxSize;
    if (cfg.angularSpeed) {
        ps.minAngularSpeed = cfg.angularSpeed[0];
        ps.maxAngularSpeed = cfg.angularSpeed[1];
    }
    if (cfg.emitter) {
        if (cfg.emitter.kind === 'sphere') {
            ps.createSphereEmitter(cfg.emitter.radius);
        }
    } else if (WEATHER_TYPES.includes(type)) {
        // 澶╂皵绫诲瀷浣跨敤鐩掑彂灏勫櫒
        const dirs = WEATHER_BOX_DIRS[type];
        if (dirs) {
            ps.createBoxEmitter(
                new Vector3(...dirs.dir1),
                new Vector3(...dirs.dir2),
                new Vector3(-WEATHER_BOX_XZ_HALF, 0, -WEATHER_BOX_XZ_HALF),
                new Vector3(WEATHER_BOX_XZ_HALF, WEATHER_BOX_Y_RANGE, WEATHER_BOX_XZ_HALF)
            );
        }
    }
    for (const [t, c1, c2] of cfg.colors) {
        ps.addColorGradient(t, c1, c2);
    }
}

/** 璁＄畻绮掑瓙鍙戝皠鍣?Y 鍧愭爣锛堝ぉ姘旂被鍨嬪湪涓栫晫鍦伴潰浠ヤ笂锛屽眬閮ㄦ晥鏋滄寜绫诲瀷鍋忕Щ锛?*/
function _getEmitterY(type: string, groundY: number): number {
    if (WEATHER_TYPES.includes(type)) {
        return groundY + WEATHER_HEIGHT_ABOVE_GROUND;
    }
    if (type === 'fireflies') {
        return groundY + FIREFLY_HEIGHT_OFFSET;
    }
    if (type === 'fireworks') {
        return groundY + FIREWORK_HEIGHT_OFFSET;
    }
    return groundY;
}

export function createParticleEmitter(type: EnvState['particleType'], windEnabled: boolean): void {
    ensureEnvUpdateObserver();
    if (_envSys.particles.system && _currentParticleType === type) {
        return;
    }
    // [doc:adr-160] 绮掑瓙绫诲瀷鍒囨崲鏃跺悓姝ユ箍韬晥鏋淺n    const prevType = _currentParticleType;
    if (_envSys.particles.system) {
        // keepWetness=true锛氬唴閮ㄩ噸寤轰笉娓呮箍韬紝婀胯韩鐢辩揣闅忓叾鍚庣殑绫诲瀷鍒ゆ柇閫昏緫澶勭悊
        disposeParticles(true);
    }
    _currentParticleType = type;
    // 婀胯韩鏁堟灉锛氳繘鍏?閫€鍑洪洦澶╂椂鍒囨崲
    if (isWeatherType(type) && type === 'rain' && !isWeatherType(prevType)) {
        applyWetnessToAllModels();
    } else if (isWeatherType(prevType) && !isWeatherType(type)) {
        removeWetnessFromAllModels();
    }
    if (type === 'none') {
        return;
    }

    const scene = getScene();
    const cfg = PARTICLE_CONFIGS[type];
    if (!cfg) {
        logWarn('env', `unknown particle type: ${type}`);
        return;
    }

    const ps = new ParticleSystem('envParticles', 15000, scene);
    ps.particleTexture = makeParticleTexture(type, envState.particleCustomTexture || undefined);
    _prevCustomTexKey = envState.particleCustomTexture
        ? `_custom_${envState.particleCustomTexture}`
        : null;
    ps.updateSpeed = 0.01;
    ps.emitter = new Vector3(0, 0, 0);

    _applyParticleConfig(ps, cfg, type);

    _baseEmitRate = ps.emitRate;
    _baseMinSize = ps.minSize;
    _baseMaxSize = ps.maxSize;
    _baseMinEmitPower = ps.minEmitPower;
    _baseMaxEmitPower = ps.maxEmitPower;
    _initialDir1 = ps.direction1.clone();
    _initialDir2 = ps.direction2.clone();

    // 搴旂敤 multiplier锛堢敤鎴疯缃?+ 璐ㄩ噺妗ｄ綅锛塡n    _particleQualityMultiplier = resolveParticleQualityMultiplier(
        envState.particleQuality ?? 'high'
    );
    ps.emitRate = Math.max(0, ps.emitRate * envState.particleEmitRate * _particleQualityMultiplier);
    if (envState.particleSize !== 1) {
        ps.minSize *= envState.particleSize;
        ps.maxSize *= envState.particleSize;
    }
    if (envState.particleSpeed !== 1) {
        ps.minEmitPower *= envState.particleSpeed;
        ps.maxEmitPower *= envState.particleSpeed;
    }
    if (windEnabled) {
        applyWindToParticles(ps);
    }

    // 姣忓抚璺熼殢鐩告満锛圶Z 璺熼殢锛孻 鎸夌被鍨嬬瓥鐣ュ畾浣嶏級
    _envSys.particles.followObserver = observe(scene.onBeforeRenderObservable, () => {
        const cam = scene.activeCamera;
        if (!cam) {
            return;
        }
        const e = ps.emitter;
        if (!(e instanceof Vector3)) {
            return;
        }
        const groundY = envState.groundLevel ?? 0;
        e.x = cam.position.x;
        e.z = cam.position.z;
        e.y = _getEmitterY(type, groundY);
    });

    _envSys.particles.system = ps;
    ps.start();

    if (WEATHER_TYPES.includes(type)) {
        startCollisionDetection(ps, type);
    }
    syncSplashState();
    if (type === 'fireworks') {
        scheduleNextFireworkBurst();
    }
}

export function disposeParticles(keepWetness = false): void {
    _collisionObserver = safeDispose(_collisionObserver);
    _envSys.particles.followObserver = safeDispose(_envSys.particles.followObserver);
    _envSys.particles.system = safeDispose(_envSys.particles.system);
    disposeSplash(); // 绮掑瓙閿€姣佹椂鍚屾閿€姣佹簠灏刓n    stopFireworkBursts(); // 鐑熻姳 burst 娓呯悊
    // 閲婃斁绮掑瓙绾圭悊缂撳瓨锛堥槻姝?GPU 璧勬簮娉勬紡锛塡n    for (const tex of _particleTextures.values()) {
        tex.dispose();
    }
    _particleTextures.clear();
    _initialDir1 = null;
    _initialDir2 = null;
    _baseEmitRate = 0;
    _baseMinSize = 0;
    _baseMaxSize = 0;
    _baseMinEmitPower = 0;
    _baseMaxEmitPower = 0;
    _prevCustomTexKey = null;
    // 褰诲簳鍋滄绮掑瓙锛坱ype鈫抧one / particleEnabled=false / 鍦烘櫙閿€姣侊級鏃剁Щ闄ゆ箍韬紝闃叉鐘舵€佹硠婕忥紱
    // 鍐呴儴绫诲瀷鍒囨崲閲嶅缓锛坘eepWetness=true锛変笉娓咃紝浜ょ敱 createParticleEmitter 绫诲瀷鍒ゆ柇澶勭悊
    if (!keepWetness) {
        removeWetnessFromAllModels();
    }
    // 涓嶉噸缃?_currentParticleType锛屼互渚?particleEnabled 鑷姩鎭㈠鏃剁煡閬撲笂娆＄被鍨媆n}

/** 鑾峰彇褰撳墠绮掑瓙绫诲瀷锛堢敤浜?particleEnabled 鑷姩鍚仠锛?*/
export function getCurrentParticleType(): EnvState['particleType'] {
    return _currentParticleType;
}

// ======== Splash System (鏂规B: GPU娓叉煋 + CPU骞界伒绮掑瓙纰版挒鑱斿姩) ========

/** 鍒ゆ柇褰撳墠绮掑瓙绫诲瀷鏄惁鏀寔婧呭皠锛堜粎澶╂皵绫诲瀷 rain/snow 鏈夋簠灏勶級 */
function isWeatherType(type: EnvState['particleType']): boolean {
    return type === 'rain' || type === 'snow';
}

/** 鍒濆鍖?splash burst 瀵硅薄姹狅紙棰勫垱寤?N 涓皬鍨?GPUParticleSystem锛?*/
function initSplashBurstPool(): void {
    if (_splashPoolReady) {
        return;
    }
    const scene = getScene();
    for (let i = 0; i < SPLASH_POOL_SIZE; i++) {
        const ps = new GPUParticleSystem(`splashBurst_${i}`, { capacity: 30 }, scene);
        ps.particleTexture = makeParticleTexture('splash');
        ps.emitRate = 0; // 寰呭懡鐘舵€侊紝涓嶆寔缁彂灏刓n        ps.emitter = new Vector3(0, 0, 0);
        ps.minLifeTime = 0.3;
        ps.maxLifeTime = 0.8;
        ps.minSize = 0.04;
        ps.maxSize = 0.12;
        ps.minEmitPower = 3;
        ps.maxEmitPower = 6;
        ps.gravity = new Vector3(0, -12, 0);
        ps.blendMode = ParticleSystem.BLENDMODE_STANDARD;
        ps.direction1 = new Vector3(-1.5, 2, -1.5);
        ps.direction2 = new Vector3(1.5, 4, 1.5);
        ps.addColorGradient(0, new Color4(0.8, 0.9, 1, 0.9), new Color4(0.9, 0.95, 1, 0.95));
        ps.addColorGradient(1, new Color4(0.8, 0.9, 1, 0), new Color4(0.9, 0.95, 1, 0));
        ps.updateSpeed = 0.01;
        ps.start();
        _splashBurstPool.push({ system: ps, busy: false, releaseTimer: null });
    }
    _splashPoolReady = true;
}

/** 鍦ㄧ簿纭綅缃Е鍙戜竴娆?splash burst锛堝菇鐏电矑瀛愯Е鍦版椂璋冪敤锛?*/
function spawnSplashAt(x: number, y: number, z: number): void {
    // 鍙栦竴涓┖闂?burst
    let burst: SplashBurst | undefined;
    for (let i = 0; i < _splashBurstPool.length; i++) {
        if (!_splashBurstPool[i].busy) {
            burst = _splashBurstPool[i];
            break;
        }
    }
    if (!burst) {
        return;
    } // 姹犳弧锛岃烦杩囪繖娆℃簠灏刓n
    burst.busy = true;
    const e = burst.system.emitter;
    if (e instanceof Vector3) {
        e.set(x, y + 0.05, z); // 鐣ュ井鎶珮閬垮厤 Z-fighting
    }

    // 鐭殏楂樺瘑搴﹀彂灏刓n    burst.system.emitRate = 300;
    setTimeout(() => {
        burst!.system.emitRate = 0;
    }, 50);

    // 0.8s 鍚庨噴鏀惧洖姹燶n    if (burst.releaseTimer) {
        clearTimeout(burst.releaseTimer);
    }
    burst.releaseTimer = setTimeout(() => {
        burst!.busy = false;
        burst!.releaseTimer = null;
    }, 800);
}

/** 纰版挒妫€娴嬪湴闈㈤珮搴︾┖闂寸綉鏍肩紦瀛?鈥?姣忓抚娓呯┖锛屾寜闇€濉厖锛岄伩鍏嶉噸澶嶈皟鐢?getGroundHeightAt */
const _gridCellSize = 10;
const _groundHeightCache = new Map<number, number>();

function _gridCellKey(x: number, z: number): number {
    const cx = Math.floor(x / _gridCellSize);
    const cz = Math.floor(z / _gridCellSize);
    // 鐢?16 浣嶄氦閿欑紪鐮侊紙Morton-like锛夊悎鎴愬崟 key锛岄伩鍏嶅瓧绗︿覆 GC
    return (cx << 16) | (cz & 0xffff);
}

/** 鍚姩纰版挒妫€娴?鈥?姣忓抚閬嶅巻 CPU 绮掑瓙鏁扮粍锛屾娴嬪湴闈㈢鎾?*/
function startCollisionDetection(ps: ParticleSystem, type: EnvState['particleType']): void {
    const scene = getScene();
    _collisionObserver = safeDispose(_collisionObserver);

    const splashProb = type === 'rain' ? 0.15 : type === 'snow' ? 0.3 : 0.4;
    const frameSkip = type === 'rain' ? 4 : 2;
    let frameIdx = 0;

    _collisionObserver = observe(scene.onBeforeRenderObservable, () => {
        const particles = ps.particles;
        if (!particles || particles.length === 0) {
            return;
        }

        // 姣忓抚娓呯┖缂撳瓨锛岄伩鍏嶆棫甯ф暟鎹畫鐣橽n        _groundHeightCache.clear();

        const startIdx = frameIdx;
        for (let i = startIdx; i < particles.length; i += frameSkip) {
            const p = particles[i];
            if (p.direction.y >= 0) {
                continue;
            }

            // 绌洪棿缃戞牸缂撳瓨锛氬悓缃戞牸鍐呯矑瀛愬叡浜?ground height 鏌ヨ缁撴灉
            const key = _gridCellKey(p.position.x, p.position.z);
            let gh = _groundHeightCache.get(key);
            if (gh === undefined) {
                gh = getGroundHeightAt(p.position.x, p.position.z);
                _groundHeightCache.set(key, gh);
            }

            const deathY = envState.waterEnabled ? Math.max(gh, envState.waterLevel) : gh;
            if (p.position.y <= deathY) {
                p.age = p.lifeTime;
                if (envState.waterEnabled && envState.waterLevel >= gh) {
                    // 姘撮潰娑熸吉
                    addRipple(
                        new Vector3(p.position.x, envState.waterLevel, p.position.z),
                        0.5,
                        0.35,
                        6,
                        1
                    );
                } else {
                    // 鍦伴潰娑熸吉 + splash锛堥洦婊?钀藉彾瑙﹀湴锛塡n                    addGroundRipple(
                        new Vector3(p.position.x, gh, p.position.z),
                        2, // 鍗婂緞鐣ュ皬浜庢按闈紝鍦伴潰娑熸吉鎵╂暎鑼冨洿灏廫n                        0.25, // 寮哄害閫備腑
                        1.5, // 閫熷害
                        1.5 // 瀵垮懡1.5绉抃n                    );
                    if (envState.particleSplash && Math.random() < splashProb) {
                        spawnSplashAt(p.position.x, gh, p.position.z);
                    }
                }
            }
        }
        frameIdx = (frameIdx + 1) % frameSkip;
    });
}

/** 閿€姣?splash burst 姹?*/
export function disposeSplash(): void {
    // 閿€姣?burst 姹燶n    for (const b of _splashBurstPool) {
        if (b.releaseTimer) {
            clearTimeout(b.releaseTimer);
        }
        b.system.dispose();
    }
    _splashBurstPool = [];
    _splashPoolReady = false;
    // 娓呯悊鏃?observer锛堝吋瀹归仐鐣?_envSys.splash.observer锛塡n    if (_envSys.splash.observer) {
        _envSys.splash.observer.dispose();
        _envSys.splash.observer = null;
    }
}

/** 婧呭皠寮€鍏冲垏鎹紙鐢?env-impl 妫€娴?particleSplash 鍙樺寲鏃惰皟鐢級 */
export function syncSplashState(): void {
    const shouldShow =
        envState.particleSplash && isWeatherType(_currentParticleType) && envState.particleEnabled;
    if (shouldShow && !_splashPoolReady) {
        initSplashBurstPool();
    } else if (!shouldShow && _splashPoolReady) {
        disposeSplash();
    }
}

// ======== Firework Multi-Burst System ========
interface FireworkBurstInstance {
    system: GPUParticleSystem;
    cleanupTimer: ReturnType<typeof setTimeout>;
}
let _fireworkBursts: FireworkBurstInstance[] = [];
let _fireworkScheduler: ReturnType<typeof setTimeout> | null = null;

function spawnFireworkBurst(): void {
    const scene = getScene();
    const cam = scene.activeCamera;
    if (!cam) {
        return;
    }

    const groundY = envState.groundLevel ?? 0;
    // 鍦ㄧ浉鏈洪檮杩戦殢鏈轰綅缃垎鏁n    const pos = new Vector3(
        cam.position.x + (Math.random() - 0.5) * 30,
        groundY + FIREWORK_HEIGHT_OFFSET + (Math.random() - 0.5) * 4,
        cam.position.z + (Math.random() - 0.5) * 30
    );

    const burst = new GPUParticleSystem(
        `firework_${_fireworkBursts.length}_${Date.now()}`,
        { capacity: 200 },
        scene
    );
    burst.particleTexture = makeParticleTexture('fireworks');
    burst.emitter = pos;
    // 鐬椂楂樺瘑搴︾垎鍙戯細emitRate=2000锛?0ms 鍐呭嚭绾?100 绮掑瓙锛屼箣鍚庡仠鍙慭n    burst.emitRate = 2000;
    setTimeout(() => {
        burst.emitRate = 0;
    }, 50);

    burst.minLifeTime = 0.4;
    burst.maxLifeTime = 1.0;
    burst.minEmitPower = 4;
    burst.maxEmitPower = 10;
    burst.gravity = new Vector3(0, -2, 0);
    burst.blendMode = ParticleSystem.BLENDMODE_ADD;
    burst.createSphereEmitter(0.2);

    // 姣忓彂闅忔満鑹茬浉
    const hue = Math.random();
    const r = 0.5 + Math.cos(hue * Math.PI * 2) * 0.5;
    const g = 0.5 + Math.cos((hue + 1 / 3) * Math.PI * 2) * 0.5;
    const b = 0.5 + Math.cos((hue + 2 / 3) * Math.PI * 2) * 0.5;

    burst.addColorGradient(0, new Color4(r, g, b, 1), new Color4(r, g, b, 1));
    burst.addColorGradient(
        0.4,
        new Color4(r, g, b, 0.8),
        new Color4(r * 0.8, g * 0.8, b * 0.8, 0.6)
    );
    burst.addColorGradient(
        1,
        new Color4(r * 0.3, g * 0.3, b * 0.3, 0),
        new Color4(r * 0.2, g * 0.2, b * 0.2, 0)
    );

    // 灏哄锛氱垎鐐歌啫鑳€鍚庣缉灏廫n    burst.minSize = 0.05;
    burst.maxSize = 0.1;
    burst.addSizeGradient(0, 0.02, 0.04);
    burst.addSizeGradient(0.3, 0.2, 0.35);
    burst.addSizeGradient(1, 0.04, 0.08);

    burst.start();

    const cleanupTimer = setTimeout(() => {
        burst.dispose();
        _fireworkBursts = _fireworkBursts.filter((b) => b.system !== burst);
    }, 3000);

    _fireworkBursts.push({ system: burst, cleanupTimer });
}

function scheduleNextFireworkBurst(): void {
    const delay = 1200 + Math.random() * 1800; // 1.2~3s 闂撮殧
    _fireworkScheduler = setTimeout(() => {
        if (_currentParticleType !== 'fireworks') {
            return;
        }
        if (!envState.particleEnabled) {
            return;
        }
        spawnFireworkBurst();
        scheduleNextFireworkBurst();
    }, delay);
}

function stopFireworkBursts(): void {
    if (_fireworkScheduler !== null) {
        clearTimeout(_fireworkScheduler);
        _fireworkScheduler = null;
    }
    for (const b of _fireworkBursts) {
        clearTimeout(b.cleanupTimer);
        b.system.dispose();
    }
    _fireworkBursts = [];
}

// ======== Wind System ========
// 鍩轰簬鍒濆鏂瑰悜璁＄畻椋庡姏锛屽彲瀹夊叏澶氭璋冪敤锛堟瘡甯ц皟鐢ㄤ篃涓嶄細鍙犲姞锛塡nexport function applyWindToParticles(ps: ParticleSystem): void {
    if (!_initialDir1 || !_initialDir2) {
        return;
    }
    // 绮掑瓙椋庡搷搴旂郴鏁?0.1锛堟瘮甯冩枡灏忥紝绮掑瓙鏇磋交浣嗗彈鍙戝皠鏂瑰悜绾︽潫锛塡n    const wind = getWindVector().scale(0.1);
    ps.direction1 = _initialDir1.clone().add(wind);
    ps.direction2 = _initialDir2.clone().add(wind);
}

// 杩愯鏃跺姩鎬佹洿鏂伴鍔涳紙鐢?ensureEnvUpdateObserver 姣忓抚璋冪敤锛塡nexport function updateParticleWind(): void {
    if (_envSys.particles.system) {
        applyWindToParticles(_envSys.particles.system);
    }
}

/** 杩愯鏃舵洿鏂扮矑瀛愬弬鏁帮紙瀵嗗害/澶у皬/閫熷害锛夛紝鍝嶅簲婊戞潯鍙樺寲 */
export function updateParticleParams(): void {
    const ps = _envSys.particles.system;
    if (!ps) {
        return;
    }
    ps.emitRate = Math.max(
        0,
        _baseEmitRate * envState.particleEmitRate * _particleQualityMultiplier
    );
    ps.minSize = _baseMinSize * envState.particleSize;
    ps.maxSize = _baseMaxSize * envState.particleSize;
    ps.minEmitPower = _baseMinEmitPower * envState.particleSpeed;
    ps.maxEmitPower = _baseMaxEmitPower * envState.particleSpeed;
}

/** 杩愯鏃舵洿鏂扮矑瀛愮汗鐞嗭紙鍝嶅簲鑷畾涔夌汗鐞嗗彉鍖栵級 */
let _prevCustomTexKey: string | null = null;
export function updateParticleTexture(): void {
    const ps = _envSys.particles.system;
    if (!ps || !_currentParticleType || _currentParticleType === 'none') {
        return;
    }
    const url = envState.particleCustomTexture || undefined;
    const newKey = url ? `_custom_${url}` : null;
    // 鍒囨崲鍓?dispose 涓婁竴涓嚜瀹氫箟绾圭悊锛堥噴鏀?GPU 璧勬簮锛塡n    if (_prevCustomTexKey && _prevCustomTexKey !== newKey) {
        const old = _particleTextures.get(_prevCustomTexKey);
        if (old) {
            old.dispose();
            _particleTextures.delete(_prevCustomTexKey);
        }
    }
    ps.particleTexture = makeParticleTexture(_currentParticleType, url);
    _prevCustomTexKey = newKey;
}

// ======== [ADR-138] env-dispatcher 鍥炶皟娉ㄥ唽 ========
const _PARTICLE_KEYS = getEnvKeys('particle');

registerEnvCallback((changed, state) => {
    if (!changed || [...changed].some((k) => _PARTICLE_KEYS.includes(k))) {
        // particleQuality-only change: light update, no full rebuild
        if (changed && changed.size === 1 && changed.has('particleQuality')) {
            _particleQualityMultiplier = resolveParticleQualityMultiplier(
                state.particleQuality ?? 'high'
            );
            updateParticleParams();
            return;
        }
        if (state.particleEnabled && state.particleType && state.particleType !== 'none') {
            createParticleEmitter(state.particleType, state.windEnabled);
        } else {
            disposeParticles();
        }
    }
});

// env-reflection.ts 鈥?鍙嶅皠瀛愮郴缁熺粺涓€鍏ュ彛锛圓DR-151锛塡n//
// 鍙傝€冨ぉ绌哄瓙绯荤粺锛坋nv-sky.ts锛夌殑 applySky 妯″紡锛歕n//   - 缁熶竴鍏ュ彛 applyReflection(state)
//   - 妯″紡浜掓枼锛堟垨 hybrid 鍒嗗眰娣峰悎锛塡n//   - 鍏ㄩ噺娓呯悊纭繚鏃ц祫婧愮函鍑€
//   - reflectionTexture 鎵€鏈夋潈澹版槑 + save/restore
//
// 鍏抽敭璁捐鍐崇瓥锛堝鏌ュ悗璋冩暣锛夛細
//   1. reflectionMode锛堟柊澧炲瓧娈碉級鎺у埗鍙嶅皠妯″紡锛宺eflectionQuality 淇濇寔鍘熸湁璇箟锛圥lanar 鍒嗚鲸鐜囷級
//   2. 浜掓枼绮掑害涓篭

source:
// env-sky.ts 鈥?澶╃┖瀛愮郴缁燂紙绋嬪簭鍖栨笎鍙?/ CubeTexture / color 妯″紡锛塡n// 浠?env-impl.ts 鎷嗗垎鑰屾潵锛屽鍏ュ叡浜緷璧栭€氳繃 env-impl.ts barrel銆俓n
import {
    Scene,
    Color3,
    Color4,
    Texture,
    BaseTexture,
    DynamicTexture,
    StandardMaterial,
    Constants,
    Mesh,
    MeshBuilder,
    CubeTexture,
    RawCubeTexture,
} from '@babylonjs/core';
import { EnvState, envState } from '@/core/config';
import { col3FromTriple } from '@/core/color-helpers';
import { logWarn } from '@/core/logger';
import { _envSys, getScene, resolveStaticAsset } from './env-context';
import { ensureEnvUpdateObserver } from './env-impl';
import { _disposeSunDisc } from '../render/lighting';
import { observe, type ObserverHandle } from '@/core/observer-handle';
import { safeDispose } from '@/core/dispose-helpers';

// ======== Module state ========
let _lastProceduralSkyKey = '';
let _lastSkyCubePath: string | null = null; // cube 璺緞缂撳瓨锛岄伩鍏嶆棆杞?寮哄害寰皟鏃堕噸澶嶄粠纾佺洏鍔犺浇
let _skyFollowHandle: ObserverHandle | null = null;
let _proceduralEnvTexture: RawCubeTexture | null = null;

/** 澶╃┖娓愬彉 canvas 灏哄 */
const SKY_TEX_SIZE = 256;

// ======== 鏄熺┖璐村浘寮傛鍔犺浇缂撳瓨 ========
let _texStarsImg: HTMLImageElement | null = null;
let _texStarsImgUrl: string | null = null;
let _texStarsGeneration = 0;

export function _getStarsTexCache() {
    return { img: _texStarsImg, url: _texStarsImgUrl, generation: _texStarsGeneration };
}

export function _setStarsTexCache(img: HTMLImageElement | null, url: string | null, gen: number) {
    _texStarsImg = img;
    _texStarsImgUrl = url;
    _texStarsGeneration = gen;
}

export function clearStarsTexCache() {
    _texStarsImg = null;
    _texStarsImgUrl = null;
    _texStarsGeneration = 0;
}

/** 寮傛鍔犺浇鏄熺┖璐村浘锛堝甫 generation 瀹堝崼锛夈€?*/
function _ensureStarsTextureImage(url: string, onReady: (img: HTMLImageElement) => void): void {
    if (_texStarsImg && _texStarsImgUrl === url && _texStarsImg.complete) {
        onReady(_texStarsImg);
        return;
    }
    if (_texStarsImgUrl !== url) {
        _texStarsImg = null;
        _texStarsImgUrl = url;
    }
    const generation = ++_texStarsGeneration;
    const img = new Image();
    img.onload = () => {
        if (generation !== _texStarsGeneration) {
            return;
        }
        _texStarsImg = img;
        onReady(img);
    };
    img.onerror = () => {
        if (generation !== _texStarsGeneration) {
            return;
        }
        logWarn('stars', 'texture load failed:', url);
    };
    img.src = url;
}

// ======== Sky Gradient Drawing ========

function drawSkyGradient(
    ctx: CanvasRenderingContext2D,
    top: Color3,
    mid: Color3,
    bot: Color3,
    brightness: number,
    sunAngle: number,
    starsEnabled: boolean,
    starsTextureImg?: HTMLImageElement | null
): void {
    const W = SKY_TEX_SIZE,
        H = SKY_TEX_SIZE;
    ctx.clearRect(0, 0, W, H);

    const grad = ctx.createLinearGradient(0, 0, 0, H);
    const scale = (c: Color3) =>
        `rgb(${(c.r * brightness * 255) | 0},${(c.g * brightness * 255) | 0},${(c.b * brightness * 255) | 0})`;
    grad.addColorStop(0, scale(bot));
    grad.addColorStop(0.35, scale(bot));
    grad.addColorStop(0.5, scale(mid));
    grad.addColorStop(0.65, scale(top));
    grad.addColorStop(1, scale(top));
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, W, H);

    if (starsEnabled) {
        const starAlpha = sunAngle > 10 ? 0 : sunAngle < -5 ? 1 : (10 - sunAngle) / 15;
        if (starAlpha > 0.01) {
            if (starsTextureImg) {
                ctx.save();
                ctx.globalAlpha = starAlpha;
                ctx.drawImage(starsTextureImg, 0, 0, W, H);
                ctx.restore();
            } else {
                const starSeed = 12345;
                const hash = (i: number) => {
                    let h = (i * 2654435761 + starSeed) | 0;
                    h ^= h >>> 13;
                    return (h & 0x7fffffff) / 0x7fffffff;
                };
                const starCount = Math.round(200 + starAlpha * 100);
                for (let i = 0; i < starCount; i++) {
                    const sx = hash(i * 3) * W;
                    const sy = hash(i * 3 + 1) * H * 0.55;
                    const sr = 0.5 + hash(i * 3 + 2) * 2.0;
                    const sa = starAlpha * (0.3 + hash(i + 1000) * 0.7);
                    const twinkle = 0.7 + hash(i + 2000) * 0.3;
                    const r = (220 + hash(i + 3000) * 35) | 0;
                    const g = (210 + hash(i + 4000) * 45) | 0;
                    const b = (200 + hash(i + 5000) * 55) | 0;
                    ctx.fillStyle = `rgba(${r},${g},${b},${(sa * twinkle).toFixed(2)})`;
                    ctx.beginPath();
                    ctx.arc(sx, sy, sr, 0, Math.PI * 2);
                    ctx.fill();
                }
            }
        }
    }
}

// ======== DynamicTexture Management ========

function updateSkyDynamicTexture(state: EnvState): DynamicTexture {
    const scene = getScene();
    const envBrightness = state.envBrightness ?? 1;
    const effectiveSkyBrightness = state.skyBrightness * envBrightness;
    let tex = _envSys.sky.skyDynamicTex;
    if (!tex) {
        tex = new DynamicTexture(
            'skyGradient',
            { width: SKY_TEX_SIZE, height: SKY_TEX_SIZE },
            scene,
            false
        );
        tex.wrapU = Constants.TEXTURE_CLAMP_ADDRESSMODE;
        tex.wrapV = Constants.TEXTURE_CLAMP_ADDRESSMODE;
        tex.hasAlpha = false;
        _envSys.sky.skyDynamicTex = tex;
    }
    const ctx = tex.getContext() as CanvasRenderingContext2D;

    let starsImg: HTMLImageElement | null = null;
    if (
        state.starsTexture &&
        _texStarsImg &&
        _texStarsImgUrl === state.starsTexture &&
        _texStarsImg.complete
    ) {
        starsImg = _texStarsImg;
    }

    drawSkyGradient(
        ctx,
        col3FromTriple(state.skyColorTop),
        col3FromTriple(state.skyColorMid),
        col3FromTriple(state.skyColorBot),
        effectiveSkyBrightness,
        state.sunAngle,
        state.starsEnabled,
        starsImg
    );
    tex.update();

    if (state.starsTexture && !starsImg) {
        const url = resolveStaticAsset(state.starsTexture);
        _ensureStarsTextureImage(url, (img) => {
            const cur = _envSys.sky.skyDynamicTex;
            if (!cur) {
                return;
            }
            const curCtx = cur.getContext() as CanvasRenderingContext2D | null;
            if (!curCtx) {
                return;
            }
            drawSkyGradient(
                curCtx,
                col3FromTriple(state.skyColorTop),
                col3FromTriple(state.skyColorMid),
                col3FromTriple(state.skyColorBot),
                effectiveSkyBrightness,
                state.sunAngle,
                state.starsEnabled,
                img
            );
            cur.update();
        });
    }

    return tex;
}

// ======== Procedural Sky ========

function createProceduralSky(state: EnvState): void {
    const scene = getScene();
    const cam = scene.activeCamera;
    const farZ = cam?.maxZ ?? 10000;
    const diameter = Math.min(20000, Math.max(2000, farZ * 1.8));
    const sphere = MeshBuilder.CreateSphere(
        'envSkySphere',
        { diameter, segments: 32, sideOrientation: Mesh.BACKSIDE },
        scene
    );
    sphere.isPickable = false;
    // 鍏堜簬浣撶Н浜戯紙Group -1锛夋覆鏌擄紝濉儗鏅絾涓嶅啓娣卞害锛岄伩鍏嶆尅浣忎簯鐨?alpha 鍚堟垚
    sphere.renderingGroupId = -2;

    const mat = new StandardMaterial('envSkyMat', scene);
    mat.emissiveTexture = updateSkyDynamicTexture(state);
    mat.disableLighting = true;
    mat.backFaceCulling = false;
    mat.disableDepthWrite = true;

    sphere.material = mat;
    _envSys.sky.skyMesh = sphere;

    // 璺熼殢鐩告満锛屼笌浜戝眰鍚屽績锛堝悓 center锛夛紝纭繚娣卞害娴嬭瘯姝ｇ‘
    _skyFollowHandle = observe(scene.onBeforeRenderObservable, () => {
        const cam = scene.activeCamera;
        if (!cam) {
            return;
        }
        sphere.position.x = cam.position.x;
        sphere.position.z = cam.position.z;
    });

    scene.clearColor = new Color4(0, 0, 0, 1);

    // 涓?PBR 鏉愯川鍒涘缓绠€鍗曠幆澧冭创鍥撅紙IBL锛塡n    createProceduralEnvTexture(state, scene);

    const envBrightness = state.envBrightness ?? 1;
    const effectiveSkyBrightness = state.skyBrightness * envBrightness;
    const starsPhase = state.starsEnabled ? (state.sunAngle > 10 ? 'h' : 'l') : '';
    _lastProceduralSkyKey = `${state.skyColorTop}|${state.skyColorMid}|${state.skyColorBot}|${effectiveSkyBrightness}|${state.starsEnabled}|${state.starsTexture}|${starsPhase}`;
}

/** 涓?PBR 鏉愯川鍒涘缓绠€鍗曠幆澧冪珛鏂逛綋璐村浘锛堝熀浜庡ぉ绌烘笎鍙橀鑹诧級 */
function createProceduralEnvTexture(state: EnvState, scene: Scene): void {
    // 閲婃斁鏃ц创鍥綷n    if (_proceduralEnvTexture) {
        _proceduralEnvTexture.dispose();
        _proceduralEnvTexture = null;
    }

    const size = 32; // 灏忓昂瀵歌冻澶燂紝鐜璐村浘涓嶉渶瑕侀珮鍒嗚鲸鐜嘰n    const topColor = col3FromTriple(state.skyColorTop);
    const midColor = col3FromTriple(state.skyColorMid);
    const botColor = col3FromTriple(state.skyColorBot);
    const brightness = state.skyBrightness * (state.envBrightness ?? 1);

    // 鍒涘缓 6 涓潰鐨勫儚绱犳暟鎹紙绠€鍗曟笎鍙橈細涓?椤惰壊锛屼腑=涓壊锛屼笅=搴曡壊锛塡n    const faces: Uint8Array[] = [];
    for (let face = 0; face < 6; face++) {
        const data = new Uint8Array(size * size * 4);
        for (let y = 0; y < size; y++) {
            // 鏍规嵁 y 浣嶇疆鎻掑€奸鑹瞈n            const t = y / size;
            let r: number, g: number, b: number;
            if (t < 0.5) {
                // 涓婂崐锛氶《鑹?鈫?涓壊
                const lt = t * 2;
                r = (topColor.r * (1 - lt) + midColor.r * lt) * brightness;
                g = (topColor.g * (1 - lt) + midColor.g * lt) * brightness;
                b = (topColor.b * (1 - lt) + midColor.b * lt) * brightness;
            } else {
                // 涓嬪崐锛氫腑鑹?鈫?搴曡壊
                const lt = (t - 0.5) * 2;
                r = (midColor.r * (1 - lt) + botColor.r * lt) * brightness;
                g = (midColor.g * (1 - lt) + botColor.g * lt) * brightness;
                b = (midColor.b * (1 - lt) + botColor.b * lt) * brightness;
            }
            for (let x = 0; x < size; x++) {
                const idx = (y * size + x) * 4;
                data[idx] = Math.min(255, r * 255);
                data[idx + 1] = Math.min(255, g * 255);
                data[idx + 2] = Math.min(255, b * 255);
                data[idx + 3] = 255;
            }
        }
        faces.push(data);
    }

    // 鍒涘缓 RawCubeTexture
    _proceduralEnvTexture = new RawCubeTexture(scene, faces, size);
    scene.environmentTexture = _proceduralEnvTexture;
}

// ======== CubeTexture Sky ========

function loadSkyCube(path: string, rotationY: number, intensity: number): void {
    const scene = getScene();
    const ext = path.split('.').pop().toLowerCase();
    const supported = ['hdr', 'dds', 'exr'];
    if (!supported.includes(ext ?? '')) {
        logWarn('sky', `unsupported format .${ext}, falling back to procedural`);
        disposeSky();
        createProceduralSky(envState);
        return;
    }

    const cubeTex = new CubeTexture(
        path,
        scene,
        null,
        false,
        null,
        null,
        (message?: string, exception?: any) => {
            logWarn('sky', `loadSkyCube failed: ${message}`, exception);
            disposeSky();
            createProceduralSky(envState);
        }
    );
    cubeTex.rotationY = rotationY;
    scene.environmentTexture = cubeTex;
    scene.environmentIntensity = intensity;
    scene.clearColor = new Color4(0, 0, 0, 1);
    _envSys.sky.skyCubeTexture = cubeTex;
    _lastSkyCubePath = path; // 缂撳瓨鎴愬姛鍔犺浇鐨勮矾寰勶紝渚?applySky 鍒ゅ畾鏄惁闇€閲嶈浇

    const cam = scene.activeCamera;
    const farZ = cam?.maxZ ?? 10000;
    const diameter = Math.min(20000, Math.max(2000, farZ * 1.8));
    const sphere = MeshBuilder.CreateSphere(
        'envSkyDome',
        { diameter, segments: 32, sideOrientation: Mesh.BACKSIDE },
        scene
    );
    sphere.isPickable = false;
    // 鍏堜簬浣撶Н浜戯紙Group -1锛夋覆鏌擄紝濉儗鏅絾涓嶅啓娣卞害锛岄伩鍏嶆尅浣忎簯鐨?alpha 鍚堟垚
    sphere.renderingGroupId = -2;
    const mat = new StandardMaterial('envSkyDomeMat', scene);
    mat.reflectionTexture = cubeTex;
    mat.reflectionTexture.coordinatesMode = Texture.SKYBOX_MODE;
    mat.diffuseColor = new Color3(0, 0, 0);
    mat.specularColor = new Color3(0, 0, 0);
    mat.disableLighting = true;
    mat.disableDepthWrite = true;
    sphere.material = mat;
    _envSys.sky.skyMesh = sphere;

    // 璺熼殢鐩告満锛屼笌浜戝眰鍚屽績锛堝悓 center锛夛紝纭繚娣卞害娴嬭瘯姝ｇ‘
    _skyFollowHandle = observe(scene.onBeforeRenderObservable, () => {
        const cam = scene.activeCamera;
        if (!cam) {
            return;
        }
        sphere.position.x = cam.position.x;
        sphere.position.z = cam.position.z;
    });
}

// ======== Public API ========

export function disposeSky(): void {
    const scene = getScene();
    // 绉婚櫎鐩告満璺熼殢瑙傚療鑰咃紝閬垮厤娉勬紡
    _skyFollowHandle = safeDispose(_skyFollowHandle);
    if (_envSys.sky.skyMesh) {
        _envSys.sky.skyMesh.material?.dispose();
        _envSys.sky.skyMesh = safeDispose(_envSys.sky.skyMesh);
    }
    if (_envSys.sky.skyCubeTexture) {
        scene.environmentTexture = null;
        _envSys.sky.skyCubeTexture = safeDispose(_envSys.sky.skyCubeTexture);
    }
    if (_envSys.sky.skyDynamicTex) {
        _envSys.sky.skyDynamicTex = safeDispose(_envSys.sky.skyDynamicTex);
    }
    // 閲婃斁绋嬪簭鍖栫幆澧冭创鍥綷n    if (_proceduralEnvTexture) {
        scene.environmentTexture = null;
        _proceduralEnvTexture.dispose();
        _proceduralEnvTexture = null;
    }
    _lastProceduralSkyKey = '';
    _lastSkyCubePath = null;
    _disposeSunDisc();
}

export function applySky(state: EnvState): void {
    const scene = getScene();
    ensureEnvUpdateObserver();
    if (state.skyMode === 'color') {
        disposeSky();
        scene.clearColor = new Color4(
            state.skyColorTop[0],
            state.skyColorTop[1],
            state.skyColorTop[2],
            1
        );
        return;
    }

    const mesh = _envSys.sky.skyMesh;

    if (state.skyMode === 'procedural') {
        if (!mesh || !mesh.material) {
            disposeSky();
            createProceduralSky(state);
            return;
        }
        if (mesh.material && mesh.material.getClassName() === 'StandardMaterial') {
            const mat = mesh.material as StandardMaterial;

            const envBrightness = state.envBrightness ?? 1;
            const effectiveSkyBrightness = state.skyBrightness * envBrightness;
            const starsPhase = state.starsEnabled ? (state.sunAngle > 10 ? 'h' : 'l') : '';
            const skyKey = `${state.skyColorTop}|${state.skyColorMid}|${state.skyColorBot}|${effectiveSkyBrightness}|${state.starsEnabled}|${state.starsTexture}|${starsPhase}`;
            if (skyKey === _lastProceduralSkyKey && _envSys.sky.skyDynamicTex) {
                return;
            }
            _lastProceduralSkyKey = skyKey;

            if (_envSys.sky.skyCubeTexture || mat.reflectionTexture) {
                if (_envSys.sky.skyCubeTexture) {
                    scene.environmentTexture = null;
                    _envSys.sky.skyCubeTexture.dispose();
                    _envSys.sky.skyCubeTexture = null;
                }
                mat.reflectionTexture = null;
            }

            mat.emissiveTexture = updateSkyDynamicTexture(state);
            return;
        }
        disposeSky();
        createProceduralSky(state);
        return;
    }

    if (state.skyTexture) {
        const intensity = state.envIntensity * (state.envBrightness ?? 1);
        // 璺緞鏈彉锛氫粎鏇存柊闈欐€佹棆杞笌 IBL 寮哄害锛岄伩鍏嶉噸澶嶄粠纾佺洏鍔犺浇 CubeTexture
        // 锛堟棆杞粦鍧楁嫋鍔?/ 寮哄害寰皟鍦烘櫙 鈥斺€?淇姝ゅ墠姣忔 sky key 鍙樻洿閮芥暣鍥鹃噸杞界殑闅愭偅锛塡n        if (
            _lastSkyCubePath === state.skyTexture &&
            _envSys.sky.skyCubeTexture &&
            _envSys.sky.skyMesh
        ) {
            (_envSys.sky.skyCubeTexture as CubeTexture).rotationY = state.skyRotationY;
            getScene().environmentIntensity = intensity;
            return;
        }
        disposeSky();
        loadSkyCube(state.skyTexture, state.skyRotationY, intensity);
    } else {
        disposeSky();
    }
}

