// env-type-helpers.ts 鈥?灏佽 Babylon.js 绫诲瀷閫冮€革紝闆嗕腑绠＄悊绉佹湁 API 璁块棶
// 姣忎釜 helper 瀵瑰簲涓€澶?`as unknown as` 鏂█锛屾秷闄ゆ暎钀藉湪涓氬姟浠ｇ爜涓殑绫诲瀷閫冪敓銆俓n
import type { DynamicTexture, PostProcess, AbstractMesh, BaseTexture, Mesh } from '@babylonjs/core';
import type { Scene } from '@babylonjs/core/scene';

// ======== DynamicTexture.getContext() 杩斿洖 RenderingContext | null ========
// 瀹為檯浣跨敤鏃朵竴瀹氭槸 CanvasRenderingContext2D锛屽皝瑁呬竴娆℃柇瑷€銆俓nexport function getCanvasCtx(dt: DynamicTexture): CanvasRenderingContext2D | null {
    return dt.getContext() as unknown as CanvasRenderingContext2D | null;
}

// ======== PostProcess._enabled (绉佹湁瀛楁) ========
// Babylon 鏈鍑?enabled setter锛屼絾杩愯鏃?_enabled 鎺у埗鍚庡鐞嗗紑鍏炽€俓ninterface PostProcessInternal {
    _enabled: boolean;
}
export function setPostProcessEnabled(pp: PostProcess | null, enabled: boolean): void {
    if (pp) {
        (pp as unknown as PostProcessInternal)._enabled = enabled;
    }
}

// ======== AbstractMesh._worldMatrixFrozen (绉佹湁瀛楁) ========
interface FrozenMesh {
    _worldMatrixFrozen?: boolean;
}
export function isWorldMatrixFrozen(mesh: AbstractMesh): boolean {
    return !!(mesh as unknown as FrozenMesh)._worldMatrixFrozen;
}

// ======== RenderTargetTexture.REFRESHRATE_RENDER_ONCE (闈欐€佸父閲忔湭瀵煎嚭) ========
// Babylon 鍐呴儴瀹氫箟璇ュ€间负 Number.MAX_VALUE锛屼絾绫诲瀷澹版槑鏈寘鍚€俓nexport const REFRESHRATE_RENDER_ONCE = Number.MAX_VALUE;

// ======== FreeCamera 绉佹湁瀛楁 _worldMatrix / _isWorldMatrixFrozen ========
// planar-reflection.ts 闇€瑕佹墜鍔ㄨ缃暅鍍忕浉鏈虹煩闃点€俓nexport interface FrozenCamera {
    _worldMatrix: import('@babylonjs/core').Matrix;
    _isWorldMatrixFrozen: boolean;
}

// mirror-debug.ts 鈥?闀滈潰閬撳叿锛堝満鏅弽灏勯亾鍏凤級
// 鐙珛浜?PlanarReflection 寮曟搸锛岀洿鎺ヤ娇鐢?Babylon MirrorTexture銆俓n// 鏈€鍒濅负璋冭瘯鍙嶅皠闂鑰岀敓锛岀幇宸插崌绾т负甯告€佸寲鍦烘櫙閬撳叿锛圓DR-128锛夈€俓n
import {
    Mesh,
    MeshBuilder,
    StandardMaterial,
    MirrorTexture,
    Color3,
    Color4,
    Vector3,
    Plane,
    Matrix,
} from '@babylonjs/core';
import { getScene } from './env-context';
import { envState } from '@/core/config';
import { setEnvState } from './env-bridge';
import { observe, type ObserverHandle } from '@/core/observer-handle';

let _mirrorMesh: Mesh | null = null;
let _mirrorRT: MirrorTexture | null = null;
let _mirrorMat: StandardMaterial | null = null;
// 鍦烘櫙缃戞牸澧炲垹瑙傚療鑰咃細闀滈潰婵€娲绘湡闂磋嚜鍔ㄥ埛鏂板弽灏勫垪琛紙鏂板姞杞界殑 MMD 瑙掕壊绛夛級
let _meshAddedObserver: ObserverHandle | null = null;
let _meshRemovedObserver: ObserverHandle | null = null;

// 鍙皟鍙傛暟锛堥€氳繃 API 淇敼锛屼笅娆?create 鏃剁敓鏁堬級
let _mirrorWidth = 18;
let _mirrorHeight = 21;
let _mirrorPosition: [number, number, number] = [0, 1.5, 8];
let _mirrorRotationY = 0; // 姘村钩鏃嬭浆锛堝姬搴︼級

/** 缁熶竴鍙嶅皠鍒嗚鲸鐜囨槧灏勶細envState.reflectionQuality 鈫?瀹為檯鍍忕礌 */
const RESOLUTION_MAP: Record<string, number> = { high: 2048, medium: 1024, low: 512, off: 0 };

/** 浠庡綋鍓?mesh 涓栫晫鐭╅樀鏇存柊 mirrorPlane锛屼娇鍙嶅皠骞抽潰涓?mesh 瀹為檯浣嶇疆/鏈濆悜涓€鑷淬€?*/
function _updateMirrorPlane(): void {
    if (!_mirrorMesh || !_mirrorRT) {
        return;
    }
    // CreatePlane 灞€閮ㄦ硶绾夸负 (0,0,1)锛岀粡涓栫晫鐭╅樀鍙樻崲寰楀埌涓栫晫娉曠嚎
    const normal = Vector3.TransformNormal(
        new Vector3(0, 0, 1),
        _mirrorMesh.getWorldMatrix()
    ).normalize();
    const position = _mirrorMesh.getAbsolutePosition();
    _mirrorRT.mirrorPlane = Plane.FromPositionAndNormal(position, normal);
}

/** 鍚屾 RT clearColor 涓庡綋鍓嶅ぉ绌烘ā寮忎竴鑷达細
 *  - color 妯″紡锛氱敤 scene.clearColor锛堝ぉ绌鸿壊锛夛紝浣跨函鍑€鐨勫ぉ绌鸿壊鍦ㄩ暅瀛愪腑鍙
 *  - 鍏朵粬妯″紡锛氶€忔槑榛戯紝鐢卞弽灏勫唴瀹硅嚜鐒跺彔鍔?*/
export function updateMirrorClearColor(): void {
    if (!_mirrorRT) {
        return;
    }
    const scene = getScene();
    if (envState.skyMode === 'color') {
        _mirrorRT.clearColor = scene.clearColor.clone();
    } else {
        _mirrorRT.clearColor = new Color4(0, 0, 0, 0);
    }
}

/**
 * 鍒涘缓闀滈潰閬撳叿锛氱珫鐩村钩闈?+ MirrorTexture 鍙嶅皠銆俓n * 鍙嶅皠鍒楄〃鍖呭惈鍦烘櫙鍏ㄩ儴 mesh锛堝惈澶╃┖鐞冦€佸湴闈€佹按闈€佽鑹诧級銆俓n */
export function createMirror(): void {
    if (_mirrorMesh) {
        return;
    }
    const scene = getScene();

    // 鍒涘缓绔栫洿骞抽潰
    _mirrorMesh = MeshBuilder.CreatePlane(
        'mirror',
        { width: _mirrorWidth, height: _mirrorHeight },
        scene
    );
    // Pivot 绉诲埌搴曡竟锛氬钩闈㈤粯璁?y 浠?-h/2 鍒?+h/2锛宐akeTransform 涓婄Щ h/2 鍚庡簳杈瑰湪 y=0
    _mirrorMesh.bakeTransformIntoVertices(Matrix.Translation(0, _mirrorHeight / 2, 0));
    _mirrorMesh.position = new Vector3(_mirrorPosition[0], _mirrorPosition[1], _mirrorPosition[2]);
    _mirrorMesh.rotation.y = _mirrorRotationY;
    _mirrorMesh.isPickable = false;

    // MirrorTexture锛氬弽灏勫叏閮?mesh
    const resolution = RESOLUTION_MAP[envState.reflectionQuality] ?? 512;
    if (!resolution) {
        disposeMirror();
        return;
    }
    _mirrorRT = new MirrorTexture('mirrorRT', resolution, scene, false);
    _mirrorRT.level = 1; // 瀹屽叏鍙嶅皠
    _mirrorRT.adaptiveBlurKernel = 0; // 鍏抽棴妯＄硦锛岄攼鍒╁弽灏勪究浜庢帓鏌n    updateMirrorClearColor(); // 鏍规嵁褰撳墠澶╃┖妯″紡璁剧疆 clearColor

    // 闀滈潰娉曠嚎闅?mesh 浣嶇疆/鏃嬭浆鑱斿姩锛屼粠涓栫晫鐭╅樀瀹炴椂璁＄畻
    _updateMirrorPlane();

    // 娓叉煋鍒楄〃锛氬叏閮?mesh 鎺掗櫎鑷韩
    _mirrorRT.renderList = scene.meshes.filter((m) => m !== _mirrorMesh);

    // 鍦烘櫙缃戞牸澧炲垹鏃惰嚜鍔ㄥ埛鏂板弽灏勫垪琛紙濡傚厛寤洪暅瀛愬悗鍔犺浇 MMD 瑙掕壊锛岃鑹查渶杩涘叆鍙嶅皠锛塡n    _meshAddedObserver = observe(scene.onNewMeshAddedObservable, () => refreshMirrorRenderList());
    _meshRemovedObserver = observe(scene.onMeshRemovedObservable, () => refreshMirrorRenderList());

    // 鏉愯川锛氫綆鍙嶇収鐜囧簳鑹?+ 寮哄弽灏勶紝渚夸簬鍖哄垎鍙嶅皠鍐呭
    _mirrorMat = new StandardMaterial('mirrorMat', scene);
    _mirrorMat.diffuseColor = new Color3(0.05, 0.05, 0.08);
    _mirrorMat.specularColor = new Color3(1, 1, 1);
    _mirrorMat.specularPower = 64;
    _mirrorMat.reflectionTexture = _mirrorRT;
    _mirrorMat.backFaceCulling = false;

    _mirrorMesh.material = _mirrorMat;
}

/** 閿€姣侀暅闈?*/
export function disposeMirror(): void {
    const scene = getScene();
    if (_meshAddedObserver) {
        _meshAddedObserver.dispose();
        _meshAddedObserver = null;
    }
    if (_meshRemovedObserver) {
        _meshRemovedObserver.dispose();
        _meshRemovedObserver = null;
    }
    if (_mirrorRT) {
        _mirrorRT.dispose();
        _mirrorRT = null;
    }
    if (_mirrorMat) {
        _mirrorMat.dispose();
        _mirrorMat = null;
    }
    if (_mirrorMesh) {
        _mirrorMesh.dispose();
        _mirrorMesh = null;
    }
}

export function isMirrorActive(): boolean {
    return _mirrorMesh !== null;
}

export function toggleMirror(): boolean {
    if (_mirrorMesh) {
        disposeMirror();
        return false;
    }
    createMirror();
    return true;
}

/** 鍒锋柊娓叉煋鍒楄〃锛堟ā鍨嬪姞杞?鍗歌浇鍚庤皟鐢級 */
export function refreshMirrorRenderList(): void {
    if (!_mirrorRT || !_mirrorMesh) {
        return;
    }
    _mirrorRT.renderList = getScene().meshes.filter((m) => m !== _mirrorMesh);
}

// ======== 鍙傛暟璁剧疆 API ========

export function setMirrorSize(width: number, height: number): void {
    _mirrorWidth = Math.max(0.5, width);
    _mirrorHeight = Math.max(0.5, height);
    // pivot 鐢?bakeTransform 鍐欏叆椤剁偣锛屾敼灏哄闇€閲嶅缓
    if (_mirrorMesh) {
        disposeMirror();
        createMirror();
    }
}

export function setMirrorPosition(x: number, y: number, z: number): void {
    _mirrorPosition = [x, y, z];
    if (_mirrorMesh) {
        _mirrorMesh.position.set(x, y, z);
        _updateMirrorPlane();
    }
}

export function setMirrorRotationY(rad: number): void {
    _mirrorRotationY = rad;
    if (_mirrorMesh) {
        _mirrorMesh.rotation.y = rad;
        _updateMirrorPlane();
    }
}

export function setMirrorResolution(res: number): void {
    // 缁熶竴鍙嶅皠鍒嗚鲸鐜囷細灏嗗儚绱犲€煎弽鍚戞槧灏勫埌 quality 鏋氫妇锛岀粡 setEnvState 鍐欏叆锛堜笉鐩存帴鍐?envState锛塡n    let quality: 'high' | 'medium' | 'low' | 'off';
    if (res >= 2048) {
        quality = 'high';
    } else if (res >= 1024) {
        quality = 'medium';
    } else if (res >= 512) {
        quality = 'low';
    } else {
        quality = 'off';
    }
    setEnvState({ reflectionQuality: quality });
    // 闇€瑕侀噸寤烘墠鐢熸晥
    if (_mirrorRT) {
        const wasActive = isMirrorActive();
        disposeMirror();
        if (wasActive) {
            createMirror();
        }
    }
}

export function getMirrorInfo(): {
    active: boolean;
    position: [number, number, number];
    width: number;
    height: number;
    resolution: number;
    meshCount: number;
} {
    return {
        active: isMirrorActive(),
        position: _mirrorPosition,
        width: _mirrorWidth,
        height: _mirrorHeight,
        resolution: RESOLUTION_MAP[envState.reflectionQuality] ?? 512,
        meshCount: _mirrorRT?.renderList?.length ?? 0,
    };
}

// [doc:architecture] Scene Props 鈥?鍦烘櫙閬撳叿绠＄悊
// 瑙勮寖鏂囨。: docs/architecture.md 搂鍦烘櫙閬撳叿
// 鑱岃矗: 閬撳叿鍔犺浇銆佺Щ闄ゃ€佸彉鎹€佸垪琛ㄦ煡璇紙鐙珛浜?modelRegistry / VMD / 鐗╃悊锛塡n// 娉ㄦ剰: 浠?scene.ts 闈欐€佸鍏ヤ絾浠呭湪鍑芥暟浣撳唴璁块棶锛孍S module live binding 淇濊瘉瀹夊叏銆俓n
import { Mesh } from '@babylonjs/core/Meshes/mesh';
import { TransformNode } from '@babylonjs/core/Meshes/transformNode';
import { ImportMeshAsync } from '@babylonjs/core/Loading/sceneLoader';
import { Vector3 } from '@babylonjs/core/Maths/math.vector';

import { propRegistry, setStatus, triggerAutoSave, dom, PropInstance } from '@/core/config';
import { readFileBytes } from '@/core/wails-bindings';
import { orbitToCartesian, cartesianToOrbit, normalizeOrbit } from '@/core/orbit';
import { scene } from '../scene';
import { _envSys } from './env';
import { registerMaterialTarget, unregisterMaterialTarget } from '../manager/material';
import { t } from '@/core/i18n/t';
import { getBaseName } from '@/core/utils';
import { logWarn, logError } from '@/core/logger';
import { renderPropThumbnail } from '../manager/thumbnail-capture';
import { setTransformMetadata } from '../transform/transform-pick';
import { thumbnailBaseKey } from '../manager/thumbnail-key';
import { registerTransformAdapter } from '../transform/transform-adapter';

// ======== 绫诲瀷瀹堝崼 ========

function isValidPosition(pos: number[]): pos is [number, number, number] {
    return Array.isArray(pos) && pos.length === 3 && pos.every((v) => Number.isFinite(v));
}

function isValidScaling(s: number): boolean {
    return Number.isFinite(s) && s > 0;
}

// ======== 鍔犺浇 ========

export async function loadProp(filePath: string, signal?: AbortSignal): Promise<string | null> {
    // 浣跨敤 rAF 璋冨害 DOM 鎿嶄綔锛岄伩鍏?onProgress 鍦ㄩ潪涓荤嚎绋嬪洖璋冧腑鐩存帴鎿嶄綔 DOM
    const updateLoadingText = (text: string) => {
        requestAnimationFrame(() => {
            dom.loadingText.textContent = text;
        });
    };
    let loadedMeshes: Mesh[] = [];

    // [adr-105] AbortSignal锛氬厑璁稿閮ㄥ彇娑堬紱鍐呴儴 AbortController 鍚堝苟澶栭儴 signal
    let abortCtrl: AbortController | undefined;
    let effectiveSignal: AbortSignal;
    if (signal) {
        effectiveSignal = signal;
    } else {
        abortCtrl = new AbortController();
        effectiveSignal = abortCtrl.signal;
    }

    try {
        dom.loadingEl.style.display = 'block';
        updateLoadingText(t('props.loadingProgress', { pct: '0' }));

        console.info('[props] loadProp:', filePath);

        // 妫€鏌ユ槸鍚﹀凡鍔犺浇
        for (const [, inst] of propRegistry) {
            if (inst.filePath === filePath) {
                setStatus(t('env.propExists', { name: inst.name }), false);
                return inst.id;
            }
        }

        const pmxBytes = await readFileBytes(filePath);
        if (!pmxBytes || effectiveSignal.aborted) {
            return null;
        }
        const fileName = getBaseName(filePath) || '';
        setStatus(t('props.loading'), false);

        const result = await (ImportMeshAsync as any)(pmxBytes, scene, {
            pluginExtension: '.pmx',
            onProgress: (evt) => {
                if (effectiveSignal.aborted) {
                    return;
                }
                if (evt.lengthComputable) {
                    const pct = Math.round((evt.loaded / evt.total) * 100);
                    updateLoadingText(t('props.loadingProgress', { pct: String(pct) }));
                }
            },
        });

        // [adr-105] 鍙栨秷鍚庢竻鐞嗗凡鍔犺浇璧勬簮
        if (effectiveSignal.aborted) {
            result.meshes.forEach((m) => {
                try {
                    m.dispose();
                } catch {
                    // ignore
                }
            });
            return null;
        }

        loadedMeshes = result.meshes.filter((m) => m instanceof Mesh) as Mesh[];

        if (loadedMeshes.length === 0) {
            setStatus(t('props.noMesh'), false);
            return null;
        }

        const id = `prop_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
        const displayName = fileName.replace(/\.pmx$/i, '');

        // 鍒涘缓鐖剁骇 TransformNode锛岀粺涓€绠＄悊鎵€鏈夌綉鏍肩殑鍙樻崲
        const container = new TransformNode(`prop_container_${id}`, scene);
        for (const m of loadedMeshes) {
            m.parent = container;
        }

        const inst: PropInstance = {
            id,
            name: displayName,
            filePath,
            meshes: loadedMeshes,
            rootMesh: loadedMeshes[0],
            container,
            position: [0, 0, 0],
            rotationY: 0,
            scaling: 1.0,
            visible: true,
        };
        propRegistry.set(id, inst);
        setTransformMetadata(container, 'prop', id);

        // 娉ㄥ唽鍒版潗璐ㄧ郴缁燂紝浣?prop 鍙敤 model 涓€鑷寸殑鏉愯川 API
        registerMaterialTarget(id, loadedMeshes);

        // 闃村奖闆嗘垚
        if (_envSys.shadow.generator) {
            for (const m of inst.meshes) {
                _envSys.shadow.generator.addShadowCaster(m);
                m.receiveShadows = true;
            }
        }

        setStatus(t('env.propAdded', { name: displayName }), true);
        triggerAutoSave();
        console.info('[props] load complete:', id, displayName);

        // [fix:prop-thumbnail] 鍔犺浇鎴愬姛鍚庣灞忔覆鏌撻亾鍏风缉鐣ュ浘骞剁紦瀛樸€俓n        // 缁忕粺涓€ thumbnailBaseKey 鏀跺彛锛堜笌妯″瀷鍐欎晶 / library-core 璇讳晶鍚屾簮锛夛紝鏉滅粷鍙屾簮鎷兼帴鍙嶅脊銆俓n        // 閬撳叿鏃?innerPath锛堜笉鏀寔 zip 鍐咃級锛屾晠浠?filePath 鍏ュ弬锛沰ind='prop' 鈫?isStageLike 鍛戒腑 16/9銆俓n        // fire-and-forget + catch锛屼笉闃诲鍔犺浇涓绘祦绋嬶紱鍏变韩 _thumbMutex 涓茶鍖栥€俓n        void renderPropThumbnail(scene, inst, thumbnailBaseKey({ filePath: inst.filePath })).catch(
            (thumbErr) => {
                logWarn('props', 'renderPropThumbnail:', thumbErr);
            }
        );

        return id;
    } catch (err) {
        // [adr-105] AbortError 涓嶇畻閿欒锛氬彇娑堟槸姝ｅ父娴佺▼锛屼笉鎵?console.error
        if (err instanceof DOMException && err.name === 'AbortError') {
            console.info('[props] loadProp aborted:', filePath);
        } else {
            logError('props', 'loadProp:', err);
        }
        // 娓呯悊宸插姞杞戒絾鏈敞鍐岀殑璧勬簮
        loadedMeshes.forEach((m) => {
            try {
                m.dispose();
            } catch {
                // Intentionally empty 鈥?鍥炴粴闃舵鍗曚釜 mesh dispose 澶辫触涓嶅奖鍝嶆暣浣撴竻鐞哱n            }
        });
        setStatus(t('props.loadFailed'), false);
        return null;
    } finally {
        abortCtrl?.abort(); // 娓呯悊鍐呴儴 AbortController
        requestAnimationFrame(() => {
            dom.loadingEl.style.display = 'none';
        });
    }
}

