export function applyUnlitFallback(id: string): void {
    const fallback = {
        diffuseMul: 0,
        specularMul: 0,
        ambientMul: 2,
        emissiveMul: 2,
        toonTexLevel: 0,
        sphereTexLevel: 0,
        emissiveTexLevel: 2,
        // shininess / bumpTexLevel / diffuseTexLevel 淇濈暀榛樿锛屼笉褰卞搷"浼?unlit"鏁堟灉
