    // 娓呯悊閫愭潗璐ㄨ鐩栵紝閬垮厤灞€閮ㄥ弬鏁板共鎵板叏灞€鍏滃簳
    _matState.delete(id);
    const state = _ensureState(id);
    for (const cat of CATEGORIES) {
        _clampAndAssign(state.get(cat)!, fallback);
