const THUMBNAIL_TIMEOUT_MS = 5000;

function withTimeout<T>(promise: Promise<T>, timeoutMs: number): Promise<T> {
    return new Promise((resolve, reject) => {
        const timer = setTimeout(
            () => reject(new Error(`Promise timeout after ${timeoutMs}ms`)),
            timeoutMs
        );
        promise.then(
            (result) => {
                clearTimeout(timer);
                resolve(result);
            },
            (err) => {
                clearTimeout(timer);
                reject(err);
            }
        );
    });
}

/** Captures a screenshot after model load for thumbnail cache.
 *  浣跨敤绂诲睆娓叉煋鐩爣 + 鐙珛鐩告満锛屽畬鍏ㄤ笉瑙︾涓荤浉鏈猴紝閬垮厤涓庣敤鎴锋搷浣滃啿绐併€俓n *  @param filePath 瑙ｅ帇鍚庣殑涓存椂璺緞鎴栨枃浠惰矾寰刓n *  @param libraryPath 搴撳紩鐢ㄨ矾寰勶紙zip鍖呰矾寰勬垨鏂囦欢璺緞锛塡n *  @param innerPath zip鍐呴儴鐩稿璺緞锛堢敤浜庡尯鍒嗗悓涓€zip鍐呯殑涓嶅悓妯″瀷锛塡n *  @param inst 鍙€夛細鎸囧畾妯″瀷瀹炰緥鎴浘锛屼笉浼犲垯鎴綋鍓嶈仛鐒︽ā鍨媆n */
export async function captureThumbnail(
    filePath: string,
    libraryPath?: string,
    innerPath?: string,
    inst?: ModelInstance
): Promise<void> {
    const gen = ++_thumbCaptureGen;
    // [fix:thumbnail-physics] 鎻愬墠瑙ｆ瀽鐩爣瀹炰緥骞跺喕缁撶墿鐞嗭紝闃叉 whenReadyAsync / rAF
    // 绛夊緟鏈熼棿 WASM Bullet 鎺ㄨ繘鐗╃悊锛屽鑷寸缉鐣ュ浘鎹曟崏鍒拌瀛?澶村彂椋炶涓殑杩囨浮鎬併€俓n    // renderInstanceThumbnail 鍐呴儴鐨?freeze 鍙樹负 no-op锛堝凡鏄叏 0锛夛紝
    // 鐢辨湰鍑芥暟 finally 缁熶竴鎭㈠鍘熷鐘舵€併€俓n    let savedPhysStates: Uint8Array | null = null;
    let targetInst: ModelInstance | null = null;
    try {
        if (!_scene || !_modelManager) {
            return;
        }

        targetInst = inst ?? _modelManager.focused();
        if (!targetInst || !targetInst.rootMesh) {
            return;
        }
        // [fix] setTimeout 闂寘鎹曡幏鐨?inst 鍙兘鍦ㄨ皟搴﹀墠宸茶鍗歌浇锛坃modelManager.remove dispose 浜?meshes锛塡n        if (targetInst.rootMesh.isDisposed()) {
            return;
        }

        // 绔嬪嵆鍐荤粨鐗╃悊锛坮ender 鍓嶇殑浠讳綍寮傛闂撮殭閮芥棤娉曟帹杩涳級
        const mmdModel = targetInst.mmdModel;
        const physStates = mmdModel?.rigidBodyStates ?? null;
        if (physStates) {
            savedPhysStates = new Uint8Array(physStates);
            physStates.fill(0);
        }

        let ready = false;
        try {
            await withTimeout(
                _scene.whenReadyAsync().then(() => {
                    ready = true;
                }),
                THUMBNAIL_TIMEOUT_MS
            );
        } catch {
            // 瓒呮椂鐩存帴鎶涢敊锛屼笉闈欓粯闄嶇骇
            return;
        }
        if (gen !== _thumbCaptureGen) {
            return;
        }

        if (!ready) {
            await new Promise((r) => requestAnimationFrame(r));
        }
        if (gen !== _thumbCaptureGen) {
            return;
        }

        const thumbKey = thumbnailBaseKey({ libraryPath, filePath, innerPath });

        // 澶嶇敤鍏变韩鐨勭灞?RT 娓叉煋锛坧mx 涓庡姩浣滅缉鐣ュ浘鍏辩敤锛岃 thumbnail-capture.ts锛夈€俓n        // 鎴殑鏄ā鍨嬪姞杞界灛闂寸殑褰撳墠濮挎€侊紙闈欐/T-pose锛夛紝鍔ㄧ敾涓嶆帹杩涖€俓n        await renderInstanceThumbnail(_scene, targetInst, thumbKey);
    } catch (err) {
        logWarn('model-loader', 'captureThumbnail:', err);
    } finally {
        // 鎭㈠鐗╃悊鍒板喕缁撳墠鐨勭姸鎬併€俓n        // 娉ㄦ剰锛歱hysStates 鏄?WASM 鍐呭瓨瑙嗗浘锛沘wait 鏈熼棿鑻ユ柊妯″瀷鍔犺浇瑙﹀彂
        // memory.grow()锛屾棫瑙嗗浘浼?detach 鈫?蹇呴』鐢ㄥ綋鍓?model 閲嶆柊鍙栬鍥惧啀鍐欏洖銆俓n        if (savedPhysStates && targetInst) {
            const fresh = targetInst.mmdModel?.rigidBodyStates ?? null;
            if (fresh && fresh.byteLength === savedPhysStates.byteLength) {
                fresh.set(savedPhysStates);
            }
        }
    }
}

// ======== PMX Loading ========

/** @internal 鈥?matches babylon-mmd's IArrayBufferFile for referenceFiles */
interface TextureFile {
    readonly relativePath: string;
    readonly mimeType: string | undefined;
    readonly data: ArrayBuffer;
}

const TEXTURE_EXTS = /\.(png|jpg|jpeg|bmp|tga|dds|tif|tiff)$/i;

function getMimeType(name: string): string {
    const ext = name.split('.').pop()?.toLowerCase();
    const map: Record<string, string | undefined> = {
        png: 'image/png',
        jpg: 'image/jpeg',
        jpeg: 'image/jpeg',
        bmp: 'image/bmp',
        tga: 'image/x-tga',
        dds: 'image/vnd-ms.dds',
        tif: 'image/tiff',
        tiff: 'image/tiff',
    };
    return map[ext ?? ''] ?? 'application/octet-stream';
}

/** Collect texture files from model directory (recursive) for referenceFiles. */
async function collectTextureFiles(modelDir: string): Promise<TextureFile[]> {
    const files: TextureFile[] = [];
    try {
        const entries = await ListDirRecursive(modelDir);
        if (!entries) {
            return files;
        }
        for (const entry of entries) {
            if (!TEXTURE_EXTS.test(entry.name)) {
                continue;
            }
            const data = await readFileBytes(modelDir + '/' + entry.relativePath);
            if (!data) {
                continue;
            }
            files.push({
                relativePath: entry.relativePath,
                mimeType: getMimeType(entry.name),
                data: data.buffer as ArrayBuffer,
            });
        }
    } catch (err) {
        logWarn('model-loader', 'texture scan failed, falling back to HTTP:', err);
    }
    // basename fallback: 涓哄甫鐩綍鍓嶇紑鐨勮创鍥炬敞鍐岃８鏂囦欢鍚嶅壇鏈紝
    // 杩欐牱 PMX 寮曠敤 "face.png" 涔熻兘鍖归厤鍒?"tex/face.png"
    const hasBasename = new Set<string>();
    const fallbacks: TextureFile[] = [];
    for (const tf of files) {
        const rel = tf.relativePath.replace(/\\/g, '/');
        const base = rel.split('/').pop() ?? rel;
        if (base === rel || hasBasename.has(base)) {
            continue;
        }
        hasBasename.add(base);
        fallbacks.push({ ...tf, relativePath: base });
    }
    files.push(...fallbacks);
    return files;
}

export async function loadPMXFile(
    filePath: string,
    asStage?: boolean,
    skipAutoApply?: boolean,
    libraryPath?: string,
    innerPath?: string,
    signal?: AbortSignal
): Promise<string | null> {
    if (!_scene || !_mmdRuntime) {
        return null;
    }
    // 鍙栨秷涔嬪墠鐨勫姞杞斤紝閬垮厤绔炴€佽鐩朶n    if (_loadAbortController) {
        _loadAbortController.abort();
    }
    const abortCtrl = new AbortController();
    _loadAbortController = abortCtrl;
    // 鍚堝苟澶栭儴 signal锛堣皟鐢ㄦ柟鍙栨秷锛変笌鍐呴儴 abortCtrl.signal锛堣嚜鍔ㄥ彇娑堝墠涓€涓姞杞斤紝ADR-096锛塡n    // 涓よ€呬换涓€ abort 鍗崇敓鏁堬紱鐢??? 鍥為€€浼氬拷鐣ュ唴閮?abortCtrl锛屽鑷?ADR-096 鏈哄埗澶辨晥
    const effectiveSignal = signal ? AbortSignal.any([signal, abortCtrl.signal]) : abortCtrl.signal;

    let loadedMeshes: Mesh[] = [];
    let wasmModel: IMmdModel | null = null;
    let registeredId: string | null = null;
    try {
        // Check if already loaded 鈥?switch focus via ModelManager
        const existing = _modelManager?.findByFilePath(filePath);
        if (existing) {
            setFocusedModelId(existing.id);
            _modelManager?.focus(existing.id, uiState.autoCenterModel);
            setStatus(t('scene.loader.switched', { name: existing.name }), true);
            dom.canvas.setAttribute('aria-label', `${t('menu.canvasLabel')}锛?{existing.name}`);
            return existing.id;
        }

        const modelDir = await resolveModelDir(filePath);
        const fileName = getBaseName(filePath) || '';

        setStatus(t('scene.loader.loading'), false);
        dom.loadingEl.style.display = 'block';
        dom.loadingText.textContent = t('scene.loader.loadingZero');

        // [doc:adr-124] Phase 2: 閫掑綊鏀堕泦妯″瀷鐩綍涓嬬汗鐞?鈫?referenceFiles 鐩翠紶 babylon-mmd
        const textureFiles = await collectTextureFiles(modelDir);

        const pmxBytes = await readFileBytes(filePath);
        if (!pmxBytes || effectiveSignal.aborted) {
            return null;
        }
        const result = await (ImportMeshAsync as any)(pmxBytes, _scene, {
            pluginExtension: '.pmx',
            pluginOptions: {
                mmdmodel: {
                    referenceFiles: textureFiles as unknown as File[],
                },
            },
            onProgress: (evt) => {
                if (effectiveSignal.aborted) {
                    return;
                }
                if (evt.lengthComputable) {
                    const pct = Math.round((evt.loaded / evt.total) * 100);
                    dom.loadingText.textContent = t('scene.loader.loadingProgress', { pct });
                }
            },
        });
        if (effectiveSignal.aborted) {
            loadedMeshes = result.meshes.filter((m) => m instanceof Mesh) as Mesh[];
            loadedMeshes.forEach((m) => {
                try {
                    m.dispose(false, true);
                } catch {
                    logWarn('model-loader', 'dispose after abort failed');
                }
            });
            return null;
        }
        loadedMeshes = result.meshes.filter((m) => m instanceof Mesh) as Mesh[];

        dom.loadingEl.style.display = 'none';

        const meshes = loadedMeshes;
        if (meshes.length === 0) {
            setStatus(t('scene.loader.noMeshes'), false);
