        for (const bone of bones) {
            const conflict = ownerByBone.get(bone);
            if (conflict && conflict.moduleId !== moduleId) {
                // 涓?registry.ts:204 涓€鑷达細鏁板€艰秺灏忎紭鍏堢骇瓒婇珮
                // 锛圓DR-147 搂鍏?璇箟杩佺Щ鏄犲皠锛氶伩鍏?Phase 2 step2 鎺ュ叆鏃朵徊瑁佺粨鏋滄暣浣撶炕杞級
                if (priority < conflict.priority) {
                    // 鎶㈠崰锛氭竻钀借触鏂规墍鏈夋潈 + 妲戒綅锛岃褰曘€岃惤璐ユ柟瑙嗚銆嶅啿绐侊紙loser=鍘熶富锛塡n                    console.warn(
                        `[adr-147] bone "${bone}" 琚ā鍧?"${moduleId}"(priority=${priority}) 浠?"${conflict.moduleId}"(priority=${conflict.priority}) 鎶㈠崰`
                    );
                    this._releaseBoneFromOwner(modelId, conflict.moduleId, bone);
                    this.clearSlot(modelId, bone, conflict.moduleId);
                    this._recordConflict(
                        modelId,
                        bone,
                        conflict.moduleId,
                        conflict.priority,
                        moduleId,
                        priority
                    );
                } else {
                    // 钀借触锛氳烦杩囪楠紙涓嶆嫢鏈夛級锛屼絾璁板綍銆屾湰妯″潡瑙嗚銆嶅啿绐侊紙M4 鍙岃瑙掞紝瀵归綈 registry:220 loser=moduleId锛塡n                    console.warn(
                        `[adr-147] bone "${bone}" 宸茶妯″潡 "${conflict.moduleId}"(priority=${conflict.priority}) 鍗犵敤锛屾ā鍧?"${moduleId}"(priority=${priority}) 璺宠繃璇ラ楠糮
                    );
                    this._recordConflict(
                        modelId,
                        bone,
                        moduleId,
                        priority,
                        conflict.moduleId,
                        conflict.priority
                    );
                    continue;
                }
            }
            // 璁ら鎴愬姛锛氬啓鎵€鏈夋潈 + 妯″潡 ownedBones
            ownerByBone.set(bone, { moduleId, priority });
            owned.add(bone);
            claimed.push(bone);
        }

        return claimed;
    }

    releaseBones(modelId: string, moduleId: string): Set<string> {
        const owned = this._ownedMap(modelId).get(moduleId);
        if (!owned) {
            return new Set();
        }
        const ownerByBone = this._ownerMap(modelId);
        const released = new Set<string>();
        for (const bone of [...owned]) {
            this._releaseBoneFromOwner(modelId, moduleId, bone);
            this.clearSlot(modelId, bone, moduleId);
            released.add(bone);
        }
        owned.clear();
        // M5锛氭竻鏈ā鍧椾綔涓?loser 鐨勫啿绐佸崱鐗囷紙瀵归綈 registry._clearConflict锛塡n        const list = this._conflicts.get(modelId);
        if (list) {
            this._conflicts.set(
                modelId,
                list.filter((c) => c.loserModuleId !== moduleId)
            );
        }
        // 閫氱煡 release 鐩戝惉鍣紙P2-1 reclaim 瑙﹀彂閾捐矾锛塡n        for (const l of this._releaseListeners) {
            l(modelId, moduleId, released);
        }
        return released;
    }

    getOwnedBones(modelId: string, moduleId: string): Set<string> {
        return new Set(this._ownedMap(modelId).get(moduleId) ?? []);
    }

    getBoneOwnerModule(modelId: string, bone: string): string | null {
        return this._ownerMap(modelId).get(bone)?.moduleId ?? null;
    }

    setModuleEnabled(modelId: string, moduleId: string, enabled: boolean): void {
        this._ensureModule(modelId, moduleId);
        const state = this._moduleState.get(modelId)!.get(moduleId)!;
        state.enabled = enabled;
        if (!enabled) {
            // 绂佺敤绾ц仈閲婃斁鍏ㄩ儴宸茶棰嗛楠?+ 妲戒綅锛堟牴娌?R3 瀛ゅ効 slot锛塡n            this.releaseBones(modelId, moduleId);
        }
    }

    // 鈥斺€?鍐茬獊 鈥斺€擻n
    getConflicts(modelId: string): BoneConflict[] {
        return [...(this._conflicts.get(modelId) ?? [])];
    }

    getAllConflicts(): BoneConflict[] {
        const all: BoneConflict[] = [];
        for (const list of this._conflicts.values()) {
            all.push(...list);
        }
        return all;
    }

    // 鈥斺€?浜嬩欢鐩戝惉 鈥斺€擻n
    addReleaseListener(listener: ReleaseListener): void {
        this._releaseListeners.push(listener);
    }

    removeReleaseListener(listener: ReleaseListener): void {
        this._releaseListeners = this._releaseListeners.filter((l) => l !== listener);
    }

    // 鈥斺€?妯″瀷鐢熷懡鍛ㄦ湡 鈥斺€擻n
    disposeModel(modelId: string): void {
        // M7锛氭竻鐪熷疄寮曟搸妲斤紙鎸夋墍鏈夋潈閬嶅巻锛屽洜涓哄紩鎿庢Ы鐢辨ā鍧楃洿鎺ュ啓 _overrideMaps锛宻tore._slots 鍙兘涓虹┖锛塡n        const ownedMap = this._ownedBones.get(modelId);
        if (ownedMap) {
            for (const set of ownedMap.values()) {
                for (const bone of set) {
                    this._opts.onClearEngineSlot?.(modelId, bone);
                }
            }
        }
        this._slots.delete(modelId);
        this._ownedBones.delete(modelId);
        this._boneOwner.delete(modelId);
        this._moduleState.delete(modelId);
        this._conflicts.delete(modelId);
    }

    // 鈥斺€?鍐呴儴杈呭姪 鈥斺€擻n
    private _ensureModule(modelId: string, moduleId: string): void {
        let perModel = this._moduleState.get(modelId);
        if (!perModel) {
            perModel = new Map();
            this._moduleState.set(modelId, perModel);
        }
        if (!perModel.has(moduleId)) {
            // 浠呴寤烘椂缃粯璁?priority=0锛涘悗缁潈濞佷紭鍏堢骇鐢?claimBones 鐨?`state.priority = priority` 缁熶竴鍐欏叆锛圡9 鍘诲摠鍏碉級
            perModel.set(moduleId, { enabled: true, priority: 0, ownedBones: new Set() });
        }
        // 鍚屾纭繚 _ownedBones 鐨?per-module set 瀛樺湪锛堥伩鍏?claimBones 鍙?owned 鏃?undefined锛塡n        let ownedPerModel = this._ownedBones.get(modelId);
        if (!ownedPerModel) {
            ownedPerModel = new Map();
            this._ownedBones.set(modelId, ownedPerModel);
        }
        if (!ownedPerModel.has(moduleId)) {
            ownedPerModel.set(moduleId, new Set());
        }
    }

    private _ownedMap(modelId: string): Map<string, Set<string>> {
        let m = this._ownedBones.get(modelId);
        if (!m) {
            m = new Map();
            this._ownedBones.set(modelId, m);
        }
        return m;
    }

    private _ownerMap(modelId: string): Map<string, BoneOwnership> {
        let m = this._boneOwner.get(modelId);
        if (!m) {
            m = new Map();
            this._boneOwner.set(modelId, m);
        }
        return m;
    }

    private _releaseBoneFromOwner(modelId: string, moduleId: string, bone: string): void {
        this._ownerMap(modelId).delete(bone);
        this._ownedMap(modelId).get(moduleId)?.delete(bone);
    }

    private _recordConflict(
        modelId: string,
        bone: string,
        loserModuleId: string,
        loserPriority: number,
        winnerModuleId: string,
        winnerPriority: number
    ): void {
        let list = this._conflicts.get(modelId);
        if (!list) {
            list = [];
            this._conflicts.set(modelId, list);
        }
        // 鍘婚噸锛堝榻?registry._recordConflict 鐨?some 妫€鏌ワ紝閬垮厤鍚?(bone,loser,winner) 閲嶅绱姞锛塡n        if (
            list.some(
                (c) =>
                    c.bone === bone &&
                    c.loserModuleId === loserModuleId &&
                    c.winnerModuleId === winnerModuleId
            )
        ) {
            return;
        }
        list.push({
            modelId,
            bone,
            loserModuleId,
            winnerModuleId,
            loserPriority,
            winnerPriority,
            loserStage: this._opts.stageOf?.(loserModuleId),
            winnerStage: this._opts.stageOf?.(winnerModuleId),
        });
    }
}

// 鈹€鈹€ 鍗曚緥锛圥hase 2 step 2 杩愯鏃舵帴鍏ワ紱寮曟搸妲芥竻闄ゅ鎵?bone-override.clearBoneOverride锛夆攢鈹€

let _storeInstance: BoneOverrideStore | null = null;

/** 鑾峰彇鍏ㄥ眬 BoneOverrideStore 鍗曚緥锛坮egistry / module-base 绛夊鎵樻瀛樺偍楠ㄩ鎵€鏈夋潈涓庡啿绐佺姸鎬侊級 */
export function getBoneOverrideStore(): BoneOverrideStore {
    if (!_storeInstance) {
        _storeInstance = new InMemoryBoneOverrideStore({
            stageOf: (moduleId) =>
                moduleId.startsWith('perception.') ? 'perception' : 'bone-override',
            // store 鍥炶皟绛惧悕涓?(modelId, bone)锛岃€?clearBoneOverride 涓?(bone, modelId)锛屾澶勯噸鎺抃n            onClearEngineSlot: (modelId, bone) => clearBoneOverride(bone, modelId),
        });
    }
    return _storeInstance;
}

