// [doc:adr-145] Motion Preset 鈥?澶氭ā鍧楀崗鍚岄璁撅細涓€閿惎鐢ㄧ粍鍚堝Э鎬乗n// 鑱岃矗锛氬畾涔?applyMotionPreset + 杞崲鍑芥暟
// MotionPreset / PresetModuleState 绫诲瀷瀹氫箟鍦?core/types.ts锛堝洜 ModelInstance 寮曠敤锛塡n
import type { MotionModuleState, MotionPreset, PresetModuleState } from '@/core/types';
import { setModuleEnabled, setModuleParam, createModule } from './registry';

/** 搴忓垪鍖栨牸寮忥紙鍚増鏈彿锛岀敤浜庢枃浠?搴撳瓨鍌級 */
export interface MotionPresetFile {
    version: 1;
    presetName?: string;
    preset: MotionPreset;
}

/** MotionModuleState[] 鈫?MotionPreset['modules'] */
export function modulesToPresetMap(states: MotionModuleState[]): MotionPreset['modules'] {
    const map: MotionPreset['modules'] = {};
    for (const s of states) {
        map[s.id] = { enabled: s.enabled, params: { ...s.params } };
    }
    return map;
}

/** MotionPreset['modules'] 鈫?MotionModuleState[] */
export function presetMapToModules(map: MotionPreset['modules']): MotionModuleState[] {
    return Object.entries(map).map(([id, state]) => ({
        id,
        enabled: state.enabled,
        params: { ...state.params },
    }));
}

/**
 * 搴旂敤棰勮鍒版寚瀹氭ā鍨嬨€俓n * 鍛藉悕鍔犮€孧otion銆嶅墠缂€锛岄伩鍏嶄笌 model-preset.ts 鐨?applyPresetFromLib 鍛藉悕鍐茬獊銆俓n * 閬嶅巻 preset.modules 鈫?setModuleEnabled + setModuleParam + createModule().enable()
 */
export function applyMotionPreset(modelId: string, preset: MotionPreset): void {
    for (const [moduleId, mod] of Object.entries(preset.modules)) {
        if (!mod) {
            continue;
        }
        setModuleEnabled(modelId, moduleId, mod.enabled);
        for (const [key, value] of Object.entries(mod.params)) {
            setModuleParam(modelId, moduleId, key, value);
        }
        const instance = createModule(moduleId, modelId);
        if (instance) {
            if (mod.enabled) {
                instance.enable();
            } else {
                instance.disable();
            }
        }
    }
}

/** 鐢熸垚鍞竴棰勮 ID */
let _presetIdCounter = 0;
export function generatePresetId(): string {
    _presetIdCounter++;
    return `preset_${Date.now()}_${_presetIdCounter}`;
}

// [doc:adr-129] Motion Override Module Registry 鈥?妯″潡娉ㄥ唽琛?+ 鍦烘櫙绾ч厤缃鐞哱n// 鑱岃矗: 娉ㄥ唽妯″潡宸ュ巶銆佸垱寤烘ā鍧楀疄渚嬨€佺鐞嗗満鏅骇妯″潡閰嶇疆銆乷wnedBones 鍐茬獊浠茶
// 鏋舵瀯鍙樻洿: 閰嶇疆瀛樺偍浠?per-model 鏀逛负 per-motion锛堥殢鍔ㄤ綔璧帮級
// 鍐茬獊浠茶: 姣忔潯楠ㄩ鍚屼竴鏃跺埢鍙兘琚竴涓ā鍧?owned锛沚ake 鏃惰嫢楠ㄩ宸茶鍏朵粬妯″潡鍗犵敤锛宑onsole.warn 璺宠繃
// [doc:adr-166] Perception 妯″潡锛坧erception.*锛夊厤浜庢敞鍐岃〃绠＄悊锛屽叾楠ㄩ鐢?perception.ts
// 鐨?_claimPerceptionBones / _releasePerceptionBones 鐩存帴閫氳繃 BoneOverrideStore 绠＄悊锛孿n// 娉ㄥ唽琛ㄤ粎浣?releaseOwnedBones 鐨勯€忎紶鍏ュ彛锛坈laimBones 鍦?perception.ts 鍐呴儴缁曡繃鏈敞鍐岃〃锛夈€俓n
import type { MotionModuleState, ParamValue, SceneMotionIntent } from '@/core/types';
import { modelRegistry } from '@/core/state';
import { triggerAutoSave } from '@/core/utils';
import type { MotionOverrideModule, ModuleFactory, ModuleMeta } from './types';
import { getBoneOverrideStore } from '../bone-override-store';
import type { ModuleDef } from './types';
import { BODY_POSTURE_DEF } from './body-posture';
import { HAND_SYMMETRY_DEF } from './hand-symmetry';
import { SWAY_MOTION_DEF } from './sway-motion';
import { FINGER_POSE_DEF } from './finger-pose';
import { RIDING_MODEL_DEF } from './riding-model';
import { POSITION_OFFSET_DEF } from './position-offset';

// 鈹€鈹€ 娉ㄥ唽琛?鈹€鈹€

interface RegistryEntry {
    factory: ModuleFactory;
    meta: ModuleMeta;
    priority: number;
}

const _registry = new Map<string, RegistryEntry>();

/** 娉ㄥ唽涓€涓姩浣滆鐩栨ā鍧?*/
export function registerModule(
    id: string,
    meta: ModuleMeta,
    priority: number,
    factory: ModuleFactory
): void {
    _registry.set(id, { factory, meta, priority });
}

/** 娉ㄩ攢妯″潡 */
export function unregisterModule(id: string): void {
    _registry.delete(id);
}

/** 鑾峰彇鎵€鏈夊凡娉ㄥ唽妯″潡鐨勫厓淇℃伅锛堟寜浼樺厛绾ф帓搴忥級 */
export function getRegisteredModules(): Array<{ id: string; meta: ModuleMeta; priority: number }> {
    return Array.from(_registry.entries())
        .map(([id, entry]) => ({ id, meta: entry.meta, priority: entry.priority }))
        .sort((a, b) => a.priority - b.priority);
}

/** 涓烘寚瀹氭ā鍨嬪垱寤烘ā鍧楀疄渚?*/
export function createModule(id: string, modelId: string): MotionOverrideModule | null {
    initMotionModules(); // 骞傜瓑鍏滃簳锛氱‘淇濇敞鍐岃〃宸插氨缁猏n    const entry = _registry.get(id);
    if (!entry) {
        return null;
    }
    return entry.factory(modelId);
}

// 鈹€鈹€ 鍦烘櫙绾ч厤缃鐞嗭紙per-motion锛岄殢鍔ㄤ綔璧帮級鈹€鈹€

import { getActiveMotion, findOrCreateModuleState } from '../motion-intent';

/**
 * 鑾峰彇褰撳墠鍔ㄤ綔鐨勬ā鍧楅厤缃紙涓嶅瓨鍦ㄥ垯鍒涘缓榛樿鐘舵€侊紝绉嶅叆 defaults锛夈€俓n * [doc:adr-121 P4-4] _modelId 鏈娇鐢細ADR-129 灏嗛厤缃瓨鍌ㄤ粠 per-model 鏀逛负 per-motion锛堥殢鍔ㄤ綔璧帮級锛孿n * 淇濈暀鍙傛暟浠呬负缁存寔鎺ュ彛鍏煎锛圲I 璋冪敤鏂瑰潎浼犲叆 modelId锛夈€俓n */
export function getModuleState(_modelId: string, moduleId: string): MotionModuleState {
    initMotionModules(); // 骞傜瓑鍏滃簳
    const intent = getActiveMotion();

    // 鏃犲姩浣滄椂杩斿洖涓存椂榛樿鐘舵€侊紙涓嶅啓鍏?intent锛塡n    if (!intent) {
        return { id: moduleId, enabled: false, params: {} };
    }

    // 蹇€熻矾寰勶細宸插瓨鍦ㄥ垯鐩存帴杩斿洖
    if (intent.motionModules) {
        const existing = intent.motionModules.find((m) => m.id === moduleId);
        if (existing) {
            return existing;
        }
    }

    // 鍒涘缓璺緞锛氶€氳繃 findOrCreateModuleState 鏀舵暃 mutate 鍏ュ彛 [doc:adr-121 P4-1]
    const state = findOrCreateModuleState(intent, moduleId);

    // 灏嗘ā鍧楁敞鍐岀殑榛樿鍊肩鍏?params锛岄伩鍏?schema 棣栨娓叉煋璇诲埌 undefined
    const entry = _registry.get(moduleId);
    const defs = entry?.meta.defaults;
    if (defs) {
        state.params = { ...defs };
    }
    return state;
}

/**
 * [doc:adr-116] 璇诲彇妯″潡娉ㄥ唽鐨勯粯璁ゅ弬鏁板€笺€俓n * 渚涜彍鍗曟粦鍧楀湪鏈?seed锛坕nst.motionOverrideModules 涓虹┖锛夋椂鍥為€€锛孿n * 閬垮厤 getStateValue 杩斿洖 undefined 瀵艰嚧婊戝潡鏄剧ず鎴愯礋鍊?min锛圦2 淇锛夈€俓n */
export function getModuleDefaultParam(moduleId: string, paramKey: string): ParamValue | undefined {
    const entry = _registry.get(moduleId);
    return entry?.meta.defaults?.[paramKey];
}

/** 鍐欏叆妯″潡鍙傛暟鍒板満鏅姩浣滄剰鍥?*/
export function setModuleParam(
    _modelId: string,
    moduleId: string,
    param: string,
    value: ParamValue
): void {
    const state = getModuleState(_modelId, moduleId);
    state.params[param] = value;
    // 浠呮寔涔呭寲锛氶厤缃凡鍐欏叆 intent.motionModules锛堥殢鍔ㄤ綔璧帮級銆俓n    // 娉ㄦ剰锛氫笉鍐嶈皟鐢?setActiveMotion 閲嶆柊骞挎挱鈥斺€斿惁鍒欎細瑙﹀彂 VMD 閲嶈浇 + seekAnimation(0)锛孿n    // 姣忔璋冨弬閮芥妸鍔ㄧ敾閲嶅惎鍒板抚 0锛岃〃鐜颁负瑙掕壊鎸佺画鎶栧姩 + 杩涘害閲嶇疆锛圓DR-129 鍥炲綊锛夈€俓n    triggerAutoSave();
}

/** 璁剧疆妯″潡鍚敤/绂佺敤鐘舵€佸埌鍦烘櫙鍔ㄤ綔鎰忓浘 */
export function setModuleEnabled(_modelId: string, moduleId: string, enabled: boolean): void {
    const state = getModuleState(_modelId, moduleId);
    state.enabled = enabled;
    // 浠呮寔涔呭寲锛堝師鍥犲悓 setModuleParam锛氶伩鍏嶉噸鏂板箍鎾鑷?VMD 閲嶈浇鎶栧姩锛塡n    triggerAutoSave();
}

/**
 * 涓烘ā鍧楀０鏄庡涓€缁勯楠肩殑鎵€鏈夋潈锛坆ake 鍓嶈皟鐢級銆俓n * 鍐茬獊浠茶: 鎸?priority 鎶㈠崰锛堟暟鍊艰秺灏忎紭鍏堢骇瓒婇珮锛夈€俓n * - 鑻ユ柊妯″潡 priority < 鍐茬獊鏂癸紝鍒欐姠鍗狅紙娓呰惤璐ユ柟 ownedBones + 寮曟搸 slot锛塡n * - 鍚﹀垯璺宠繃骞?console.warn
 * 杩斿洖瀹為檯鎴愬姛 claim 鐨勯楠煎垪琛ㄣ€俓n *
