let _currentModelId: string | null = null;

/**
 * 鍒囨崲鐩爣妯″瀷锛氱鐢ㄥ綋鍓嶆ā鍨嬬殑鎵€鏈夋ā鍧楄鐩栵紝鍚敤鏂版ā鍨嬪凡淇濆瓨鐨勬ā鍧楃姸鎬併€俓n * [doc:adr-129] 鐜板湪妯″潡閰嶇疆闅忓姩浣滆蛋锛屾鍑芥暟涓昏鐢ㄤ簬娓呯悊 ownedBones
 */
export function setTargetModel(modelId: string | null): void {
    initMotionModules(); // 骞傜瓑鍏滃簳锛氱‘淇濇敞鍐岃〃宸插氨缁猏n    if (_currentModelId === modelId) {
        return;
    }

    // 娓呯悊鏃фā鍨嬬殑 ownedBones锛堥厤缃凡闅忓姩浣滐紝涓嶉渶瑕佸悓姝ワ級
    if (_currentModelId) {
        for (const moduleId of _registry.keys()) {
            const mod = createModule(moduleId, _currentModelId);
            if (mod) {
                // 绂佺敤妯″潡锛岄噴鏀?ownedBones
                mod.disable();
            }
        }
    }

    _currentModelId = modelId;

    // 鍚敤鏂版ā鍨嬬殑妯″潡锛堜粠鍦烘櫙绾ч厤缃鍙栫姸鎬侊級
    if (modelId) {
        const intent = getActiveMotion();
        if (intent?.motionModules) {
            for (const state of intent.motionModules) {
                if (state.enabled) {
                    const mod = createModule(state.id, modelId);
                    if (mod) {
                        mod.enable();
                        // 搴旂敤鍙傛暟
                        for (const [key, value] of Object.entries(state.params)) {
                            mod.setParam?.(key, value);
                        }
                    }
                }
            }
        }
    }
}

/** 娓呴櫎鎸囧畾妯″瀷鐨勬墍鏈夋ā鍧楄鐩栵紙鍒犻櫎妯″瀷鏃惰皟鐢級 */
export function clearAllModulesForModel(modelId: string): void {
    // 閲婃斁骞舵竻闄ゆ墍鏈?ownedBones + 寮曟搸妲斤紙濮旀墭 store.disposeModel锛塡n    getBoneOverrideStore().disposeModel(modelId);
}

/**
 * [doc:adr-129] 灏嗗満鏅骇妯″潡閰嶇疆搴旂敤鍒版寚瀹氭ā鍨媆n * 鐢ㄤ簬鍔ㄤ綔骞挎挱鏃跺簲鐢ㄩ厤缃埌鎵€鏈?inherit 妯″瀷
 */
export function applyMotionModulesToModel(modelId: string): void {
    const intent = getActiveMotion();
    if (!intent?.motionModules) {
        return;
    }

    for (const state of intent.motionModules) {
        const mod = createModule(state.id, modelId);
        if (!mod) {
            continue;
        }

        if (state.enabled) {
            mod.enable();
            // 搴旂敤鍙傛暟
            for (const [key, value] of Object.entries(state.params)) {
                mod.setParam?.(key, value);
            }
        } else {
            mod.disable();
        }
    }
}

