// 鈹€鈹€ 鐪肩悆杩借釜骞虫粦绯绘暟锛堥粯璁ゅ€硷紝瀹為檯浠?perception-shared 鍔ㄦ€佽鍙栵級 鈹€鈹€
const DEFAULT_EYE_SMOOTH = 0.35;

// 鈹€鈹€ AR 妯″紡瑙嗙嚎璺濈锛堢背锛?鈹€鈹€
const AR_GAZE_DISTANCE = 1.5;

// 鈹€鈹€ 澶撮儴/鐪肩悆璺熼殢瑙掑害闄愪綅锛堥粯璁ゅ€硷紝瀹為檯浠?perception-shared 鍔ㄦ€佽鍙栵級 鈹€鈹€
const DEFAULT_HEAD_GAZE_MAX_YAW = (75 * Math.PI) / 180;
