/**
 * 灏哱

閽冲埗鍦ㄧ浉瀵圭埗楠ㄩ鍧愭爣绯荤殑 yaw/pitch 閿ュ舰鍐呫€俓n */
export function _clampGazeTargetInParentFrame(
    oldWorldQ: Quaternion,
    targetWorldQ: Quaternion,
    parentWorldQ: Quaternion,
    maxYawRad: number,
    maxPitchRad: number
): Quaternion {
    return _clampImpl(oldWorldQ, targetWorldQ, parentWorldQ, maxYawRad, maxPitchRad);
}

function _clampImpl(
    oldWorldQ: Quaternion,
    targetWorldQ: Quaternion,
    parentWorldQ: Quaternion,
    maxYawRad: number,
    maxPitchRad: number
): Quaternion {
    const invParent = _q().copyFrom(parentWorldQ).invert();
    const desiredLocal = _q().copyFrom(invParent).multiplyInPlace(targetWorldQ);

    // 鈹€鈹€ Swing-Twist 鍒嗚В 鈹€鈹€
    // desiredLocal = swing 脳 twist
    // twist = 缁曠埗楠ㄩ +Y 杞寸殑鏃嬭浆锛坹aw锛屽乏鍙宠浆澶达級
    // swing = 鍓╀綑鍋忚浆锛堝惈 pitch 淇话 + roll 缈绘粴锛塡n    // 鍒嗚В鍚庡垎鍒檺浣?yaw 鍜?swing 鎬昏锛岄伩鍏?toEulerAngles 鍦ㄥぇ瑙掑害澶嶅悎鏃嬭浆涓嬬殑淇℃伅涓㈠け銆俓n    const twist = _q();
    _swingTwistDecompose(desiredLocal, Vector3.Up(), twist);

    // 闄愪綅 twist锛坹aw锛夛細闄愬埗 twist 涓?Identity 缁?+Y 鐨勫す瑙抃n    let twistAngle = 2 * Math.acos(Math.min(Math.abs(twist.w), 1));
    if (twist.y < 0) {
        twistAngle = -twistAngle;
    } // 淇濈暀鏂瑰悜
    const clampedTwistAngle = Math.max(-maxYawRad, Math.min(maxYawRad, twistAngle));
    const clampedTwist = _q().copyFrom(Quaternion.RotationAxis(Vector3.Up(), clampedTwistAngle));

    // 闄愪綅 swing锛氶檺鍒?swing 涓?Identity 鐨勬€诲す瑙掞紙娑电洊 pitch + roll锛塡n    const swingAngle = 2 * Math.acos(Math.min(Math.abs(desiredLocal.w), 1));
    // swing 鎬昏 鈮?sqrt(pitch虏 + roll虏)锛岀敤 maxPitchRad 浣滀负 swing 涓婇檺
    const maxSwingRad = maxPitchRad;
    const clampedSwing = _q();
    if (swingAngle > maxSwingRad && swingAngle > 1e-6) {
        // 绛夋瘮缂╂斁 swing 鍥涘厓鏁扮殑鏃嬭浆瑙掑害
        const scale = maxSwingRad / swingAngle;
        // swing = desiredLocal 脳 twist鈦宦筡n        const invTwist = _q().copyFrom(twist).invert();
        const swing = _q().copyFrom(desiredLocal).multiplyInPlace(invTwist);
        // 缂╂斁锛氬 swing 鍋?slerp(Identity, swing, scale)
        Quaternion.SlerpToRef(Quaternion.Identity(), swing, scale, clampedSwing);
    } else {
        const invTwist = _q().copyFrom(twist).invert();
        clampedSwing.copyFrom(desiredLocal).multiplyInPlace(invTwist);
    }

    // 閲嶇粍锛歝lampedLocal = clampedSwing 脳 clampedTwist
    const clampedLocal = _q().copyFrom(clampedSwing).multiplyInPlace(clampedTwist);

    return _q().copyFrom(parentWorldQ).multiplyInPlace(clampedLocal);
}

/**
 * Swing-Twist 鍒嗚В锛氭妸 q 鍒嗚В涓?swing 脳 twist锛宼wist 鏄粫鎸囧畾杞寸殑鏃嬭浆銆俓n * 鍙傝€冿細https://www.euclideanspace.com/maths/geometry/rotations/for/decomposition/
 */
function _swingTwistDecompose(q: Quaternion, twistAxis: Vector3, outTwist: Quaternion): void {
    // twist = (q路axis) / |q路axis| 鎶曞奖鍒拌酱涓奬n    // p = (dot(q.xyz, axis), normalized) 鈥?q 鐨勮酱鍚戝垎閲廫n    const dot = q.x * twistAxis.x + q.y * twistAxis.y + q.z * twistAxis.z;
    const axisLen = Math.sqrt(dot * dot + q.w * q.w);
    if (axisLen < 1e-6) {
        // q 鍑犱箮绾?swing锛堟棤 twist 鍒嗛噺锛夛紝twist = Identity
        outTwist.set(0, 0, 0, 1);
        return;
    }
    outTwist.set(
        (dot * twistAxis.x) / axisLen,
        (dot * twistAxis.y) / axisLen,
        (dot * twistAxis.z) / axisLen,
        q.w / axisLen
    );
}

/** 鑾峰彇瑙嗙嚎鐩爣鐐癸紙AR 妯″紡娌跨浉鏈烘湞鍚戞姇灏勶紝鏅€氭ā寮忕敤鐩告満浣嶇疆锛?*/
export function _getGazeTarget(cam: Camera, out: Vector3): Vector3 {
    if (isARActive()) {
        const forward = cam.getDirection(Vector3.Forward());
        out.copyFrom(cam.position);
        out.addInPlace(forward.scale(AR_GAZE_DISTANCE));
        return out;
    }
    out.copyFrom(cam.position);
    return out;
}

/**
 * [adr-071] 鍧愭爣绯诲榻愶細鎶婁笘鐣屽潗鏍囩郴涓嬬殑 gazeTarget 杞崲鍒?rootMesh 灞€閮ㄥ潗鏍囩郴銆俓n *
 * babylon-mmd 鐨勯楠?worldMatrix 鏄?rootMesh 灞€閮ㄥ潗鏍囩郴锛堜笉鍚?rootMesh 鐨?scaling/rotation/translation锛夛紝
 * 鑰岀浉鏈?position 鏄笘鐣屽潗鏍囩郴銆傝嫢妯″瀷鏈?autoScale 鎴栦綅缃亸绉伙紝涓や釜鍧愭爣绯讳笉涓€鑷达紝
 * 浼氬鑷?gaze 鏂瑰悜璁＄畻閿欒锛堝吀鍨嬬棁鐘讹細鐪肩潧鐪嬪悜瑙掕壊鍘熷姝ｅ墠鏂硅€岄潪鐩告満锛夈€俓n *
 * 姝ゅ嚱鏁板師鍦颁慨鏀?target锛屼娇鍏朵笌楠ㄩ worldMatrix 鍦ㄥ悓涓€鍧愭爣绯汇€俓n */
function _worldToLocalGazeTarget(mmdModel: MmdModelLike, target: Vector3): void {
    const getWM = mmdModel.mesh.getWorldMatrix;
    if (!getWM) {
        return;
    }
    // Babylon.js Mesh.getWorldMatrix() 杩斿洖 Matrix锛堝惈 scaling/rotation/translation锛塡n    const rootWorld = getWM.call(mmdModel.mesh) as Matrix;
    if (!rootWorld) {
        return;
    }
    const invRoot = _m().copyFrom(rootWorld).invert();
    // target = invRoot 脳 target锛堟妸涓栫晫鍧愭爣杞埌 rootMesh 灞€閮ㄥ潗鏍囷級
    Vector3.TransformCoordinatesToRef(target, invRoot, target);
}

/** 澶撮儴涓撶敤鍖呰锛堢淮鎸佸凡鏈夊洖褰掓祴璇曠鍚嶄笉鍙橈級 */
export function _clampHeadGazeTarget(
