// 鈹€鈹€ 鍏ㄥ眬"褰撳墠姹燶

source:
// [doc:adr-071] Perception Layer 鈥?瑙掕壊鎰熺煡绯荤粺锛堝懠鍚?鐪ㄧ溂/瑙嗙嚎杩借釜锛塡n// 鑱岃矗: Always-on 瀹炴椂鍙犲姞锛岀嫭绔嬩簬 VMD 鐢熷懡鍛ㄦ湡
// 妯″潡: 鍛煎惛锛堣函骞查楠兼寮﹀井鍔級銆佺湪鐪硷紙morph 鏉冮噸鑴夊啿锛夈€佸ご閮ㄨ窡闅忋€佺溂閮ㄨ窡闅廫n//
// 鏈枃浠朵负鎰熺煡灞備富鍏ュ彛锛坆arrel + 鐘舵€佺鐞?+ observer 璋冨害锛夈€俓n// 鍚勫姛鑳藉疄鐜拌 perception-*.ts 瀛愭ā鍧椼€俓n// [doc:adr-162] Phase 1: 鍗曚緥 鈫?Map<modelId, PerceptionContext>

import type { Scene } from '@babylonjs/core/scene';
import { getMotionPipeline } from './motion-pipeline';

import { modelManager, focusedModelId, triggerAutoSave } from '../scene';
// scene 瀹炰緥璧?env-impl 鐨?getScene() 寤惰繜鑾峰彇锛岄伩鍏嶄笌 scene.ts 褰㈡垚闈欐€佸惊鐜緷璧朶n// (scene.ts 鈫?proc-motion-bridge.ts 鈫?perception.ts 鈫?scene.ts)
import { getScene } from '../env/env-impl';

import {
    type Emotion,
    type PerceptionState,
    type GazeConfig,
    type PerceptionContext,
    type BalanceSwayState,
    type PerceptionTier,
