/** 娉ㄩ攢鎰熺煡灞?*/
export function deactivatePerception(): void {
    const hasPinned = Array.from(_contexts.values()).some((c) => c.isPinned && c.isActive);

    // 鏈?pinned 妯″瀷鏃朵繚鐣?observer锛屽彧娓呯悊鐒︾偣鐘舵€乗n    if (!hasPinned && perceptionObserver) {
