/** 璁剧疆鎰熺煡鐘舵€侊紙浠庡瓨鍌ㄦ仮澶嶆椂浣跨敤锛?*/
export function setPerceptionState(s: Partial<PerceptionState>): void {
    // 閽冲埗 gaze 瑙掑害鍙傛暟锛堜笌鍚勫崟椤?setter 涓€鑷达紝閬垮厤缁曡繃 clamp锛塡n    const clamped: Partial<PerceptionState> = {};
    if ('headGazeMaxYaw' in s) {
