    }
    // 闈?gaze 瀛楁鍘熸牱浼犲叆
    for (const k of Object.keys(s)) {
        if (!(k in clamped)) {
            (clamped as Record<string, unknown>)[k] = (s as Record<string, unknown>)[k];
        }
    }
    _setFocusedState(clamped);
    // 妫€娴嬭搴﹀弬鏁板彉鍖栵紝鍚屾鍒?perception-shared锛堥伩鍏嶅惊鐜緷璧栵級
    if (
