// [doc:architecture] ScenePlayback 鈥?鎾斁鎺у埗 UI 瀛愭ā鍧梊n// 鑱岃矗: 浠?scene.ts 鎷嗗嚭鐨勬挱鏀捐繘搴?UI / seek 閫昏緫 + MMD runtime observable 鍥炶皟鑱氬悎
//
// 寰幆渚濊禆澶勭悊锛歮odelManager 浠ュ弬鏁板舰寮忔敞鍏?initPlaybackObservables锛孿n// 鑰岄潪闈欐€佸鍏?`./scene`锛岄伩鍏?ES module 寰幆寮曠敤闅愭偅銆俓n
import {
    dom,
    isPlaying,
    setIsPlaying,
    autoLoop,
    seekDragging,
    formatTime,
    mmdRuntime,
} from '@/core/config';
import { isAudioPlaying, syncAudioPlayback } from '@/outfit/audio';
import { animateCameraVmd } from '../camera/camera';
import type { IMmdRuntime } from 'babylon-mmd/esm/Runtime/IMmdRuntime';
import type { ModelManager } from '../manager/model-manager';
import type { BeatDetector } from '@/motion-algos/beat-detector';
import { clamp01 } from '@/core/utils';
import { observe, type ObserverHandle } from '@/core/observer-handle';

// ======== 杈呭姪鍑芥暟 ========

/** 鑾峰彇褰撳墠鑱氱劍妯″瀷鐨勫姩鐢绘椂闀匡紝浼樺厛浣跨敤妯″瀷鑷韩鏃堕暱锛岄檷绾у埌 runtime 榛樿鍊笺€?*/
function _getDuration(runtime: IMmdRuntime, manager: ModelManager): number {
    const foc = manager.focused();
    return foc?.animationDuration ?? runtime.animationDuration;
}

/** 褰撳墠鏄惁鏈?auto-loop 鍦ㄨ繘琛屼腑锛堢敤浜庨伩鍏?UI 闂儊锛夈€?*/
let _loopPending = false;

/** Module-level ModelManager 寮曠敤锛屼緵 updatePlaybackUI 缁熶竴鑾峰彇鍔ㄧ敾鏃堕暱銆?*/
let _manager: ModelManager | null = null;

/** Dispose guard: prevents double-cleanup if dispose() called more than once. */
let _disposed = false;

// ======== Playback Callbacks Initialization ========

export interface PlaybackObservablesDispose {
    (): void;
}

export function initPlaybackObservables(
    runtime: IMmdRuntime,
    manager: ModelManager,
    updatePlaybackUI: () => void,
    updateProcMotion: () => Promise<void>,
    getProcBeatDetector: () => BeatDetector | null
): PlaybackObservablesDispose {
    _manager = manager;
    _disposed = false; // 閲嶇疆 dispose guard锛屾敮鎸佸杞?init/dispose

    const tickHandle = observe(runtime.onAnimationTickObservable, () => {
        // 姣忓抚缁熶竴鍒锋柊鑺傛媿妫€娴嬪櫒锛堜緵 LipSync + Auto Dance 鍏变韩锛塡n        const beatDetector = getProcBeatDetector();
        if (isAudioPlaying() && beatDetector) {
            beatDetector.update();
        }
        updatePlaybackUI();
        animateCameraVmd(runtime.currentTime * 30);
        // updateProcMotion 鏄?async 鍑芥暟锛屽湪鍚屾鍥炶皟涓?fire-and-forget
        // 娣诲姞 .catch 闃叉鏈鐞嗙殑 Promise 鎷掔粷瀵艰嚧闈欓粯宕╂簝
        updateProcMotion().catch((err: unknown) =>
            console.error('[playback] updateProcMotion:', err)
        );
    });

    const playHandle = observe(runtime.onPlayAnimationObservable, () => {
        setIsPlaying(true);
        updatePlaybackUI();
    });

    const pauseHandle = observe(runtime.onPauseAnimationObservable, () => {
        // NOTE: babylon-mmd fires onPause when animation reaches the end (no
        // separate onFinish event), so the auto-loop logic lives here.

        if (!_loopPending) {
            setIsPlaying(false);
        }
        if (seekDragging) {
            updatePlaybackUI();
            return;
        }
        // Auto-loop: use the focused model's animation duration
        const focModel = manager.focused();
        if (
            autoLoop &&
            focModel &&
            runtime &&
            focModel.animationDuration > 0 &&
            runtime.currentTime >= focModel.animationDuration - 0.1
        ) {
            // 璁剧疆 loopPending 鏍囧織锛岄樆姝?setIsPlaying(false) 瀵艰嚧鐨?UI 闂儊
            _loopPending = true;
            const loop = autoLoop; // 蹇収锛氶槻姝?async 闂撮殭 autoLoop 鍙樺寲瀵艰嚧鐘舵€佹紓绉籠n            runtime
                .seekAnimation(0, true)
                .then(() => {
                    if (!loop) {
                        _loopPending = false;
                        return;
                    }
                    // 妫€鏌?runtime 鍜?manager 鍦?async 闂撮殭鏄惁浠嶆湁鏁圽n                    if (!loop || !runtime || !_manager) {
                        _loopPending = false;
                        return;
                    }
                    runtime
                        .playAnimation()
                        .then(() => {
                            _loopPending = false;
                            setIsPlaying(true);
                            updatePlaybackUI();
                        })
                        .catch((err: unknown) => {
                            _loopPending = false;
                            console.error('[playback] auto-loop playAnimation failed:', err);
                        });
                })
                .catch((err: unknown) => {
                    _loopPending = false;
                    console.error('[playback] auto-loop seekAnimation failed:', err);
                });
            return;
        }
        updatePlaybackUI();
    });

    // 杩斿洖 dispose 鍑芥暟锛屼緵鍦烘櫙閿€姣佹椂娓呯悊瑙傚療鑰咃紝闃叉鍐呭瓨娉勬紡
    return () => {
        if (_disposed) {
            return;
        }
        _disposed = true;
        // 閫愪竴娓呯悊锛宑atch 寮傚父纭繚鍚庣画 handle 浠嶈兘閲婃斁锛堢瓑浠锋棫 _safeRemoveCallback 璇箟锛塡n        try {
            tickHandle.dispose();
        } catch {
            /* 鍗曚釜娓呯悊澶辫触涓嶄腑鏂暣浣?*/
        }
        try {
            playHandle.dispose();
        } catch {
            /* 鍗曚釜娓呯悊澶辫触涓嶄腑鏂暣浣?*/
        }
        try {
            pauseHandle.dispose();
        } catch {
            /* 鍗曚釜娓呯悊澶辫触涓嶄腑鏂暣浣?*/
        }
    };
}

export function updatePlaybackUI(): void {
    if (!dom.playbackBar) {
        return;
    }

    // 瀹夊叏瀹堝崼锛歴cene 閲嶅缓鏈熼棿 observer 鍙兘灏氭湭娓呭畬锛屾鏃?mmdRuntime / seekBar 涓?null銆俓n    // 鏈嚱鏁拌 onAnimationTickObservable 姣忓抚璋冪敤锛宼hrow 浼氱偢鎺夋暣甯ф覆鏌擄紝鍥犳闄嶇骇涓?warn + 璺宠繃銆俓n    if (!mmdRuntime || !dom.seekBar) {
        console.warn('[playback] updatePlaybackUI: mmdRuntime 鎴?seekBar 鏈氨缁紝璺宠繃鏈抚');
        return;
    }
    dom.playbackBar.style.display = 'flex';
    dom.btnPlayPause.textContent = isPlaying ? '鈴? : '鈻?;
    dom.btnLoopToggle.style.opacity = autoLoop ? '1' : '0.35';
    const duration = _manager ? _getDuration(mmdRuntime, _manager) : mmdRuntime.animationDuration;
    dom.timeDisplay.textContent = `${formatTime(mmdRuntime.currentTime)} / ${formatTime(duration)}`;
    if (duration > 0) {
        const pct = (mmdRuntime.currentTime / duration) * 100;
        dom.seekProgress.style.width = `${Math.min(pct, 100)}%`;
    }
}

export function seekFromEvent(e: MouseEvent | PointerEvent): void {
    if (!mmdRuntime || !dom.seekBar) {
        return;
    }
    const duration = mmdRuntime.animationDuration;
    if (duration <= 0) {
        return;
    }
    const rect = dom.seekBar.getBoundingClientRect();
    const ratio = clamp01((e.clientX - rect.left) / rect.width);
    const targetTime = ratio * duration;
    mmdRuntime.seekAnimation(targetTime, true);
    updatePlaybackUI();
    syncAudioPlayback(targetTime, isPlaying, duration);
}

// [doc:architecture] Procedural Motion 鈥?绋嬪簭鍖栧姩浣滅郴缁焅n// 瑙勮寖鏂囨。: docs/architecture.md 搂绋嬪簭鍖栧姩浣淺n// 鑱岃矗: Idle / Auto Dance VMD 鐢熸垚璋冨害銆佽妭鎷嶈仈鍔╘n// 瑙嗙嚎杩借釜宸茶縼绉昏嚦 perception.ts锛圓DR-071锛塡n//
// [refactor] 8 涓ā鍧楃骇 let 鏀跺彛涓?ProcMotionController 绫诲疄渚嬨€俓n// 鐘舵€佸皝瑁呭湪绫荤鏈夊瓧娈典腑锛屽閮ㄤ笉鍙洿鎺ヨ闂紱瀵煎嚭鍑芥暟绛惧悕涓嶅彉锛孿n// 濮旀墭鍒版ā鍧楃骇鎳掑崟渚嬶紝澶栭儴璋冪敤鏂归浂鏀瑰姩銆俓n// dispose() 涓€閿竻闆跺叏閮ㄧ姸鎬佸苟閿€姣佸崟渚嬶紝鐢熷懡鍛ㄦ湡璺?scene 缁戝畾銆俓n//
// [adr-XX per-motion] 鍙傛暟瀛樺偍浼樺厛绾э細
//   1. activeMotion.procMotion锛堥殢鍔ㄤ綔璧帮紝澶氳鑹插叡浜弬鏁帮級
//   2. _fallbackProcState锛堟棤鍔ㄤ綔鏃剁殑鏈湴榛樿鍊硷紝鍚戝悗鍏煎锛塡n// 璇诲彇鏃跺彇浼樺厛鍊硷紝鍐欏叆鏃跺啓鍏?activeMotion锛堣嫢瀛樺湪锛夊苟鍚屾 fallback銆俓n
import {
    ProcMotionState,
    ProcMotionMode,
    ProcMotionBoneCategory,
    PROC_MOTION_BONE_CATEGORIES,
    DEFAULT_PROC_STATE,
    generateIdleVmd,
    generateAutoDanceVmd,
    shouldAutoDance,
    shouldIdle,
    PROC_VMD_NAME_IDLE,
    PROC_VMD_NAME_AUTODANCE,
} from '@/motion-algos/procedural-motion';
import { BeatDetector } from '@/motion-algos/beat-detector';
import { mmdRuntime, triggerAutoSave, focusedModelId, setUIState } from '@/core/config';
import { isAudioPlaying } from '@/outfit/audio';
import { modelManager, focusedMmdModel, focusedModel, loadVMDMotion } from '../scene';
import { setGazeConfig, onPerceptionModelRemoved, activatePerception } from './perception';
import { clamp01 } from '@/core/utils';
import { logWarn } from '@/core/logger';
import { safeDispose } from '@/core/dispose-helpers';
import { getActiveMotion } from './motion-intent';
import { rebuildCompositeAnimation } from './vmd-layers';
import type { ProcMotionConfig } from '@/core/types';

/** 娓呴櫎妯″瀷涓婄殑 vmdData/vmdName锛堢函宸ュ叿鍑芥暟锛屾棤鐘舵€佷緷璧栵級銆?*/
function _clearVmdData(inst: import('../../core/config').ModelInstance | null | undefined): void {
    if (inst) {
        inst.vmdData = null;
        inst.vmdName = '';
    }
}

// 鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺怽n// ProcMotionController 鈥?绋嬪簭鍖栧姩浣滅姸鎬?+ 閫昏緫鏀跺彛
// 鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺愨晲鈺怽n
class ProcMotionController {
    // 鈹€鈹€ 绉佹湁鐘舵€侊紙鍘?8 涓ā鍧楃骇 let锛屽閮ㄤ笉鍙洿鎺ヨ闂級鈹€鈹€
    private _fallbackProcState: ProcMotionState = { ...DEFAULT_PROC_STATE };
    private _beatDetector: BeatDetector | null = null;
    private _lastBeatBpm = 120;
    private _starting = false;
    private _stopRequested = false; // await 鏈熼棿琚?stop 鏃剁疆浣嶏紝闃叉 start 瀹屾垚鍚庨噸鏂版縺娲籠n    private _regeneratePending = false;
    private _activeKind: ProcMotionMode = 'idle';
    /** [fix:P1] Set 鏀寔澶氭ā鍨嬪苟鍙戠▼搴忓寲锛屾浛浠ｅ師 procModelId 鍗曞€?*/
    private _activeModels = new Set<string>();

    // 鈹€鈹€ 鍐呴儴宸ュ叿 鈹€鈹€

    private _procVmdActive(): boolean {
        return this._activeModels.size > 0;
    }

    /** [adr-XX per-motion] 鑾峰彇褰撳墠鐢熸晥鐨勭▼搴忓寲閰嶇疆寮曠敤銆俓n     *  璇诲彇浼樺厛绾э細鏄惧紡 modelId 鐨?per-model 鐘舵€?> activeMotion > fallback銆俓n     *  [P5 per-slot] 鏄惧紡 modelId 鏃朵紭鍏堣 modelManager 涓殑 per-model 鐘舵€侊紝
     *  浣?regenerateProcMotion(modelId) 姝ｇ‘璇诲彇璇ユā鍨嬬嫭鏈夊弬鏁帮紙濡?boneToggles锛夈€俓n     *  杩斿洖鐨勬槸鍙彉寮曠敤锛屽唴閮ㄤ娇鐢紱澶栭儴璇诲彇鐢?getProcMotionState()锛堟祬鎷疯礉锛夈€?*/
    private _refProcState(modelId?: string): ProcMotionState {
        // [P5 per-slot] 鏄惧紡 modelId 鈫?璇?per-model 鐘舵€侊紙UI 鍐欏叆 modelRegistry 鐨勬簮锛塡n        if (modelId) {
            const inst = modelManager.get(modelId);
            if (inst?.procMotion) {
                return inst.procMotion as ProcMotionState;
            }
        }
        const intent = getActiveMotion();
        if (intent?.procMotion) {
            return intent.procMotion as ProcMotionState;
        }
        return this._fallbackProcState;
    }

    /** [adr-XX per-motion] 鍐欏叆绋嬪簭鍖栭厤缃細鍚屾鍐欏叆 activeMotion锛堣嫢瀛樺湪锛? fallback銆俓n     *  淇濊瘉鏃犲姩浣滄椂鐨勬湰鍦扮姸鎬佷篃涓庢渶鏂拌缃竴鑷达紝鍒囨崲鍔ㄤ綔鍚庡弬鏁颁笉涓㈠け銆?*/
    private _writeProcState(patch: Partial<ProcMotionState>): void {
        const intent = getActiveMotion();
        if (intent) {
            if (!intent.procMotion) {
                intent.procMotion = { ...DEFAULT_PROC_STATE } as ProcMotionConfig;
            }
            intent.procMotion = { ...intent.procMotion, ...patch } as ProcMotionConfig;
        }
        this._fallbackProcState = { ...this._fallbackProcState, ...patch };
    }

    /** 閫氱敤瑙嗙嚎/澶撮儴杩借釜璁惧畾锛堥噸寤鸿拷韪互搴旂敤鏂板€硷級銆?*/
    private _setGazeTrackingSetting(
        field: 'eyeTrackingEnabled' | 'headTrackingEnabled',
        value: boolean
    ): void {
        this._writeProcState({ [field]: value } as Partial<ProcMotionState>);
