    private async _startProcMotion(
        targetMode: ProcMotionMode,
        bpm?: number,
        /** [P5 per-slot] 鏄惧紡鎸囧畾鐩爣妯″瀷锛涗笉浼犳椂鍥為€€鍒扮劍鐐规ā鍨嬶紙鍚戝悗鍏煎锛夈€?*/
        modelIdOverride?: string
    ): Promise<void> {
        if (this._starting) {
            return;
        }
        this._starting = true;
        this._stopRequested = false;

        // 淇濆瓨鍔犺浇鍓嶇殑妯″瀷 ID锛岄槻姝?await 鍚庣劍鐐瑰垏鎹㈠鑷存搷浣滈敊閰嶏紙Issue #3锛塡n        // [P5 per-slot] 浼樺厛浣跨敤鏄惧紡浼犲叆鐨?modelIdOverride锛屼娇闈炵劍鐐规ā鍨嬩篃鑳介┍鍔ㄧ▼搴忓寲
        const modelAtStart =
            modelIdOverride !== undefined
                ? (modelManager.get(modelIdOverride)?.mmdModel ?? null)
                : focusedMmdModel();
        const modelIdAtStart = modelIdOverride ?? focusedModelId ?? null;
        if (!modelAtStart) {
            this._starting = false;
            return;
        }
        const morphNames = modelAtStart.morph.morphs.map((m) => m.name) ?? [];
        const boneNames = modelAtStart.runtimeBones.map((b) => b.name);
        logWarn(
            'proc-motion',
            `bones: [${boneNames.slice(0, 10).join(', ')}${boneNames.length > 10 ? '...' : ''}]`
        );
        logWarn(
            'proc-motion',
            `morphs: [${morphNames.slice(0, 5).join(', ')}${morphNames.length > 5 ? '...' : ''}]`
        );
        let buf: ArrayBuffer;

        // Issue #2: bpm 鏃犳晥鏃剁洿鎺ユ姏閿欙紝淇濇寔鐘舵€佷竴鑷碶n        const bpmValid = bpm !== null && bpm !== undefined && bpm > 0 && Number.isFinite(bpm);
        if (targetMode === 'autodance' && !bpmValid) {
            throw new Error('proc-motion: autodance 妯″紡闇€瑕佹湁鏁?BPM锛屽綋鍓?BPM 鏃犳晥');
        }
        if (targetMode === 'autodance' && bpmValid) {
            buf = generateAutoDanceVmd(
                this._refProcState(modelIdOverride),
                bpm!,
                morphNames,
                boneNames
            );
            this._lastBeatBpm = bpm!;
            this._activeKind = 'autodance';
        } else {
            buf = generateIdleVmd(this._refProcState(modelIdOverride), boneNames);
            this._activeKind = targetMode;
        }

        // [P5 per-slot] 鏄惧紡鎸囧畾鐩爣鏃惰烦杩囩劍鐐规牎楠岋細璋冪敤鏂瑰凡鍐冲畾鐩爣锛岀劍鐐瑰垏鎹笉搴斿彇娑堣妯″瀷鐨勭▼搴忓寲
        // [fix] _procVmdActive/procModelId 绉昏嚦鎴愬姛鍒嗘敮鍐呰祴鍊硷紙P1: 闃叉 early return 鍚庣姸鎬佹硠婕忥級
        const isExplicitTarget = modelIdOverride !== undefined;
        try {
            // D4: 浠呭湪鏈樉寮忔寚瀹氱洰鏍囨椂妫€鏌ョ劍鐐瑰垏鎹紝閬垮厤鏃犳剰涔夌殑 VMD 鐢熸垚
            if (!isExplicitTarget && focusedModelId !== modelIdAtStart) {
                logWarn('proc-motion', '鐒︾偣宸插湪鐢熸垚鏈熼棿鍒囨崲锛屽彇娑堟湰娆＄▼搴忓寲鍔ㄤ綔');
                this._starting = false;
                return;
            }
            const inst = modelManager.get(modelIdAtStart);
            if (!inst) {
                this._starting = false;
                return;
            }
            // [adr-XX per-motion] 绋嬪簭鍖?base 璧?vmdLayers 绠＄嚎锛氬啓鍏?vmdData + rebuild
            // 鏇夸唬鏃х殑鐩村啓 loadVMDMotion/setRuntimeAnimation锛岄伩鍏嶄笌鍥惧眰鍙犲姞鍐茬獊
            const procVmdName =
                targetMode === 'autodance' && bpmValid
                    ? PROC_VMD_NAME_AUTODANCE
                    : PROC_VMD_NAME_IDLE;
            inst.vmdData = buf;
            inst.vmdName = procVmdName;
            inst.vmdPath = null; // 绋嬪簭鍖栨棤鏂囦欢璺緞
            rebuildCompositeAnimation(modelIdAtStart);

            // 鍚屾鍐欏叆鍚庢牎楠岋細浠呭湪鏈樉寮忔寚瀹氱洰鏍囨椂妫€鏌ョ劍鐐规槸鍚︿粛鍦ㄨ妯″瀷涓奬n            const currentId = focusedModelId ?? null;
            if (!isExplicitTarget && currentId !== modelIdAtStart) {
                logWarn('proc-motion', '鐢熸垚鍚庣劍鐐瑰凡鍒囨崲锛屼涪寮冩湰娆＄▼搴忓寲鍔ㄤ綔缁撴灉');
                inst.vmdData = null;
                inst.vmdName = '';
                rebuildCompositeAnimation(modelIdAtStart);
                this._activeModels.delete(modelIdAtStart);
                this._activeKind = 'idle';
            } else if (this._stopRequested) {
                logWarn('proc-motion', '鐢熸垚瀹屾垚浣嗗凡琚?stop锛屼涪寮冪粨鏋?);
                inst.vmdData = null;
                inst.vmdName = '';
                rebuildCompositeAnimation(modelIdAtStart);
                this._activeModels.delete(modelIdAtStart);
                this._activeKind = 'idle';
            } else {
                // 鎴愬姛锛氬姞鍏ユ椿璺冮泦鍚圽n                this._activeModels.add(modelIdAtStart);
                // 鎰熺煡灞傜嫭绔嬫縺娲伙紝涓嶄緷璧栫▼搴忓寲鍔ㄤ綔鐢熷懡鍛ㄦ湡
            }
        } catch (err) {
            logWarn('proc-motion', '绋嬪簭鍖栧姩浣滅敓鎴愬け璐?', err);
            this._activeModels.delete(modelIdAtStart);
            _clearVmdData(modelManager.get(modelIdAtStart));
        } finally {
            this._starting = false;
        }

        // Re-trigger check after finally (cannot use return inside finally 鈥?no-unsafe-finally)
        if (this._regeneratePending) {
            this._regeneratePending = false;
            // 鍙栨渶鍚庝竴涓椿璺冩ā鍨嬮噸瑙﹀彂
            const lastModel = [...this._activeModels].pop();
            if (lastModel) {
                const mode =
                    this._refProcState(lastModel).mode === 'autodance' ? 'autodance' : 'idle';
                const bpm = this._beatDetector?.getBPM() ?? 120;
                void this._startProcMotion(
                    mode,
                    mode === 'autodance' ? bpm : undefined,
                    lastModel
                ).catch((e) => {
                    logWarn('proc-motion', 'Re-trigger startProcMotion 澶辫触:', e);
                });
            } else {
                logWarn('proc-motion', 'Re-trigger skipped: no active models');
            }
        }
    }

    stopProcMotion(): void {
        this._stopRequested = true;
        // 鎰熺煡灞傜嫭绔嬩簬绋嬪簭鍖栧姩浣滐紝涓嶅啀闅?stopProcMotion 娉ㄩ攢
        // gaze 鐢?perception.ts 绠＄悊锛宎lways-on
        // [fix:P1] 閬嶅巻鎵€鏈夋椿璺冩ā鍨嬶紝閫愪竴娓呯悊
        for (const modelId of this._activeModels) {
            const inst = modelManager.get(modelId);
            if (inst) {
                // [fix] 鑻ョ敤鎴峰凡鍦ㄧ▼搴忓寲鍔ㄤ綔 active 鏈熼棿鍔犺浇浜嗙湡瀹?VMD锛坴mdPath 闈炵┖锛夛紝
                // 涓嶅彲鐩茬洰娓呴櫎 vmdData 鈥斺€?鍚﹀垯浼氳鐩栫敤鎴峰垰鐐瑰嚮鐨勫姩浣溿€俓n                // 浠呭湪妯″瀷鏈寔鏈夌敤鎴风湡瀹?VMD 鏃舵墠娓呴櫎绋嬪簭鍖栨暟鎹苟 rebuild 鍒伴潤姝㈠Э銆俓n                const userVmdPresent =
                    inst.vmdPath !== null && inst.vmdPath !== undefined && inst.vmdPath !== '';
                if (!userVmdPresent) {
                    inst.vmdData = null;
                    inst.vmdName = '';
                    inst.vmdPath = null;
                    rebuildCompositeAnimation(modelId);
                }
            }
        }
        this._activeModels.clear();
    }

    onModelRemoved(id: string): void {
        this._activeModels.delete(id);
