    async updateProcMotion(): Promise<void> {
        const st = this._refProcState(focusedModelId ?? undefined);
        if (st.mode === 'off') {
            if (this._procVmdActive()) {
                this.stopProcMotion();
            }
            return;
        }

        // Issue #1: focusedModel() 鍙兘涓?null/undefined
        const model = focusedModel();
        const audioOn = isAudioPlaying();
        // [fix:adr-129/proc-slot] 绋嬪簭鍖栧姩浣滅幇宸插啓鍏?inst.vmdData锛堟浛浠ｆ棫鐩村啓 setRuntimeAnimation锛孿n        // 瑙?_startProcMotion 鍐呮敞锛夛紝鏁呬笉鑳藉啀鐢?vmdData 鍒ゅ畾"鐢ㄦ埛/鍦烘櫙 VMD 鏄惁瀛樺湪"鈥斺€擻n        // 鍚﹀垯姣忓抚 onBeforeRender 璋冪敤鐨?updateProcMotion 浼氭妸绋嬪簭鍖栨暟鎹鍒や负"鐢ㄦ埛 VMD"锛孿n        // 瑙﹀彂 stopProcMotion() 娓呯┖ vmdData锛屽鑷村姩浣?锛堝熀纭€妲戒綅锛夌▼搴忓寲鐬棿澶辨晥銆俓n        // 姝ｇ‘鍒ゅ埆渚濇嵁锛歩nst.vmdPath銆傜▼搴忓寲鍔ㄤ綔 vmdPath 鎭掍负 null锛坃startProcMotion 鏄惧紡缃┖锛夛紝
        // 鐢ㄦ埛/鍦烘櫙 VMD 鍒欏繀鏈夐潪绌?vmdPath锛坅pplyIntentToModel / loadVMDFromPath 鍐欏叆锛夈€俓n        const hasUserVmd = !!model?.vmdPath;
        const mode = st.mode;
        const wantAutoDance = shouldAutoDance(audioOn, mode);
        const wantIdle = shouldIdle(audioOn, hasUserVmd, mode);

        if (hasUserVmd && this._procVmdActive()) {
            this.stopProcMotion();
            return;
        }

        if (wantAutoDance && !hasUserVmd && this._beatDetector) {
            const bpm = this._beatDetector.getBPM() ?? 120;
            if (
                !this._procVmdActive() ||
                this._activeKind !== 'autodance' ||
                Math.abs(bpm - this._lastBeatBpm) > 10
            ) {
                await this._startProcMotion('autodance', bpm);
            }
            return;
        }

        if (wantIdle && !hasUserVmd) {
            if (!this._procVmdActive() || this._activeKind !== 'idle') {
                await this._startProcMotion('idle');
            }
            return;
        }
    }

