    regenerateProcMotion(
        /** [P5 per-slot] 鏄惧紡鎸囧畾鐩爣妯″瀷锛涗笉浼犳椂鍥為€€鍒扮劍鐐规ā鍨嬶紙鍚戝悗鍏煎锛夈€?*/
        modelId?: string
    ): void {
        const st = this._refProcState(modelId);
        // [fix] mode === 'off' 鏃剁珛鍒诲仠鎺夌▼搴忓寲锛屼笉缁х画寰€涓嬭蛋鍒?idle 閲嶅惎鍔╘n        if (st.mode === 'off') {
