        // 浠ヤ笅鎵ц regenerate锛堝喎鍚姩鎴栫儹鏇存柊鍧囪蛋姝よ矾寰勶級
        // [P5 per-slot] 浼樺厛浣跨敤浼犲叆鐨?modelId锛涘惁鍒欏洖閫€鍒扮劍鐐筡n        const targetModel = modelId
            ? (modelManager.get(modelId)?.mmdModel ?? null)
            : focusedMmdModel();
        if (!targetModel) {
            logWarn('proc-motion', 'regenerateProcMotion: 鏃犵洰鏍?MMD 妯″瀷锛岃烦杩?);
            return;
        }
        // Issue #4: 濡傛灉 regenerate 璋冪敤鏃舵鍦ㄧ敓鎴愶紝鏍囪 deferred 閲嶈窇
        if (this._starting) {
            this._regeneratePending = true;
            return;
        }
        const mode =
            this._refProcState(modelId).mode === 'autodance'
                ? ('autodance' as const)
                : ('idle' as const);
        // Issue #5: _beatDetector 鍙兘涓?null
        const bpm = this._beatDetector?.getBPM() ?? 120;
        this._startProcMotion(mode, mode === 'autodance' ? bpm : undefined, modelId);
    }

    /** 閲婃斁鍏ㄩ儴璧勬簮锛岄噸缃负鍒濆鐘舵€併€?*/
    dispose(): void {
        this.stopProcMotion();
        this._beatDetector = safeDispose(this._beatDetector);
        this._fallbackProcState = { ...DEFAULT_PROC_STATE };
        this._regeneratePending = false;
        this._stopRequested = false;
        this._starting = false;
        this._activeKind = 'idle';
        this._lastBeatBpm = 120;
    }
}

