// 缂撳瓨宸插姞杞界殑鍚屽悕浼撮煶锛岄伩鍏嶉噸澶嶅姞杞絓nconst _companionAudioCache = new Set<string>();

// Generation counter: per-model锛屾瘡娆?loadVMDMotion 璋冪敤閫掑锛宎wait 鍚庢鏌ユ槸鍚﹁繃鏈焅n// 鍏ㄥ眬鍗曚緥浼氬鑷村妯″瀷鍚屾椂鍔犺浇鏃朵簰鐩稿共鎵帮紙鎱㈢殑琚敊璇垽瀹氫负杩囨湡锛塡nconst _vmdLoadGenMap = new Map<string, number>();

// VMD 绛惧悕锛氬墠 25 瀛楄妭涓?"Vocaloid Motion Data 0002"锛屽叡 30 瀛楄妭锛堝惈 \0 濉厖锛塡nconst VMD_SIGNATURE = 'Vocaloid Motion Data 0002';
const VMD_HEADER_MIN = 50; // 30(绛惧悕+妯″瀷鍚? + 4(楠ㄩ甯ф暟) 鐨勬渶灏忓悎娉曞ご閮╘n
/** 楠岃瘉 ArrayBuffer 鏄惁涓哄悎娉?VMD 鏍煎紡锛氭鏌ョ鍚嶅墠缂€銆俓n *  绋嬪簭鍖栫敓鎴愮殑 VMD 涔熶娇鐢ㄦ绛惧悕锛坴md-writer.ts SIGNATURE 甯搁噺锛夈€?*/
function isValidVmd(data: ArrayBuffer): boolean {
    if (data.byteLength < VMD_HEADER_MIN) {
        return false;
    }
    const sig = new TextDecoder('ascii').decode(new Uint8Array(data, 0, 25));
    return sig === VMD_SIGNATURE;
}

// ======== VMD Loading ========
export async function loadVMDMotion(
    data: ArrayBuffer,
    name: string,
    targetModelId?: string,
    signal?: AbortSignal,
    vmdPath?: string
): Promise<void> {
    if (signal?.aborted) {
        throw new DOMException('Aborted', 'AbortError');
    }
    if (!isValidVmd(data)) {
        setStatus(t('scene.vmd.loadFailed'), false);
        logWarn('vmd-loader', 'Invalid VMD signature, rejected:', name);
        return;
    }
    const {
        scene,
        focusedMmdModel: _focusedMmdModel,
        isProcVmdActive,
        stopProcMotion,
        focusedModel: _focusedModel,
    } = await getScene();
    if (signal?.aborted) {
        throw new DOMException('Aborted', 'AbortError');
    }
    if (!mmdRuntime) {
        replaceDefaultMotion({ vmdPath: null, vmdName: name, vmdLayers: [], source: 'vmd' });
        setStatus(t('scene.vmd.cachedWaiting'), false);
        return;
    }
    const targetId = targetModelId || focusedModelId;
    if (!targetId) {
        setStatus(t('scene.vmd.noTargetModel'), false);
        return;
    }
    const inst = modelRegistry.get(targetId);
    if (!inst) {
        setStatus(t('scene.vmd.targetNotFound'), false);
        return;
    }
    const prevGen = _vmdLoadGenMap.get(targetId) ?? 0;
    const capturedGen = prevGen + 1;
    _vmdLoadGenMap.set(targetId, capturedGen);
    try {
        // Load VMD from buffer using VmdLoader
        const vmdLoader = new VmdLoader(scene);
        const mmdAnimation = await vmdLoader.loadFromBufferAsync(name, data);
        // babylon-mmd fork 鐨?VmdLoader 鏃犲疄渚嬬姸鎬侀渶閲婃斁锛堣В鏋愮粨鏋滃凡杞Щ鍒?mmdAnimation锛夛紝
        // 涓嶅瓨鍦?dispose() API锛沴oader 涓哄眬閮ㄥ紩鐢紝GC 鑷姩鍥炴敹锛屾棤闇€鎵嬪姩閲婃斁銆俓n
        // 妫€鏌ユ槸鍚﹀湪 await 鏈熼棿鏈夋柊鐨?loadVMDMotion 璋冪敤锛堝悓妯″瀷锛夛紝杩囨湡鍒欎涪寮僜n        if (_vmdLoadGenMap.get(targetId) !== capturedGen) {
            logWarn('vmd-loader', 'Stale loadVMDMotion result discarded:', name);
            setStatus(t('scene.vmd.loadFailed'), false);
            return;
        }

        // Create runtime animation from the loaded data
        // WASM 鐗堥渶 MmdWasmAnimation 鍖呰锛汮S 鐗堢洿鎺ョ敤 mmdAnimation锛堝疄鐜?IMmdBindableModelAnimation锛塡n        let runtimeAnimation: import('babylon-mmd/esm/Runtime/Animation/IMmdBindableAnimation').IMmdBindableModelAnimation;
        if (mmdRuntime instanceof MmdWasmRuntime) {
            runtimeAnimation = new MmdWasmAnimation(mmdAnimation, mmdRuntime.wasmInstance, scene);
        } else {
            runtimeAnimation = mmdAnimation;
        }

        // Extract camera track from VMD and apply to MmdCamera
        try {
            loadCameraVmd(mmdAnimation, '', name);
        } catch {
            // 绋嬪簭鍖栧姩浣滅殑 VMD 涓嶅惈鐩告満杞ㄩ亾锛屾澶勮烦杩囨槸姝ｅ父琛屼负
        }

        // Bind to model
        if (!inst.mmdModel) {
            // 鍔ㄧ敾宸插垱寤轰絾妯″瀷鏄?Stage锛屾棤娉曠粦瀹?鈥?娓呯悊閬垮厤娉勬紡锛堜粎 WASM 鐗堟湁璧勬簮闇€閲婃斁锛塡n            if (runtimeAnimation instanceof MmdWasmAnimation) {
                try {
                    runtimeAnimation.dispose?.();
                } catch {
                    // Intentionally empty 鈥?鑸炲彴妯″瀷鍔ㄧ敾鍙ユ焺娓呯悊澶辫触涓嶅奖鍝嶅悗缁祦绋媆n                }
            }
            setStatus(t('scene.vmd.stageNoVmd'), false);
            return;
        }
        // 閲婃斁鏃у姩鐢诲彞鏌勶紝闃叉鍒囨崲 VMD 鏃?WASM 鍐呭瓨娉勬紡
        // setRuntimeAnimation(null) 浠呰В缁戙€佷笉閲婃斁 WASM buffer锛涘繀椤绘樉寮?dispose 鏃n        // runtime animation锛堝叾鍐呴儴 onDispose 鍥炶皟瑙﹀彂 _destroyRuntimeAnimation锛屼粠
        // _animationHandleMap 鍒犻櫎骞跺洖鏀?WASM AnimCurve 璧勬簮锛夛紝鍚﹀垯姣忔鎹?VMD 閮芥硠婕忎竴浠姐€俓n        // babylon-mmd 绫诲瀷澹版槑鏈毚闇?currentAnimation 灞炴€э紙鍐呴儴瀹炵幇锛夛紝
        // 闇€瑕佸彇鍑烘棫鍔ㄧ敾鍙ユ焺鏄惧紡 dispose 浠ラ噴鏀?WASM AnimCurve 璧勬簮
        const prevAnim =
            (inst.mmdModel as { currentAnimation?: { dispose?: () => void } | null })
                .currentAnimation ?? null;
        inst.mmdModel.setRuntimeAnimation(null);
        if (prevAnim) {
            try {
                prevAnim.dispose?.();
            } catch {
                // 鏃у姩鐢诲彞鏌勬竻鐞嗗け璐ヤ笉褰卞搷鏈缁戝畾
            }
        }
        const handle = inst.mmdModel.createRuntimeAnimation(runtimeAnimation);
        inst.mmdModel.setRuntimeAnimation(handle);

        // [fix] 鍒囨崲鍔ㄤ綔鏃跺皢 runtime 鍏ㄥ眬鏃堕挓褰掗浂鍒扮 0 甯э細setRuntimeAnimation 鍙崲鍔ㄧ敾鍙ユ焺锛孿n        // 涓嶄細閲嶇疆 _currentFrameTime銆傝嫢涓婁竴鍔ㄤ綔鎾埌 50s銆佹柊鍔ㄤ綔浠?10s锛宑urrentTime 浠嶆粸鐣?50s锛孿n        // 缂╃暐鍥?renderInstanceThumbnail 鍐呴儴 rt.render() 瑙﹀彂鐨?beforePhysics 浼氬垽瀹歕n        // elapsedFrameTime(50s) > 鏂板姩浣滄椂闀?10s) 鈫?绔嬪嵆缃?_animationPaused 骞?onPause 鈫抃n        // setIsPlaying(false)锛岃〃鐜颁负銆岀偣鍑诲姩浣?0.01s 鍚庤閲嶇疆涓烘棤鍔ㄤ綔銆嶃€俓n        // seekAnimation(0, true) 鍚屾褰掗浂鏃堕挓+鎽嗗埌绗?0 甯э紝涓斾笉鏀瑰彉 _animationPaused锛堟挱鏀句腑鍒欑户缁挱銆佹殏鍋滃垯鍋滅暀锛夈€俓n        try {
            await mmdRuntime.seekAnimation(0, true);
        } catch {
            // 褰掗浂澶辫触涓嶅奖鍝嶅姩浣滅粦瀹氾紝涓嬩竴甯т富寰幆浼氱籂姝n        }

        inst.vmdData = data;
        // 鍋滄绋嬪簭鍖栧姩浣滐紙寤惰繜鍒?vmdData 璧嬪€煎悗锛岀‘淇?stopProcMotion 鍐?userVmdPresent=true锛孿n        // 涓嶄細娓呯┖鍒氱粦瀹氱殑鍔ㄧ敾鈥斺€斿惁鍒欑缉鐣ュ浘鎴抚鏃跺姩鐢诲凡琚竻绌猴紝鎴埌绌哄Э鎬侊級
        if (isProcVmdActive() && name !== PROC_VMD_NAME_IDLE && name !== PROC_VMD_NAME_AUTODANCE) {
            stopProcMotion();
        }
        _companionAudioCache.clear();
        inst.vmdName = name;
        // Convert from 30fps frames to seconds锛堝紓甯?VMD 鍏滃簳锛岄伩鍏?NaN 鏃堕暱锛塡n        const endFrame = Number(mmdAnimation.endFrame);
        inst.animationDuration = Number.isFinite(endFrame) && endFrame > 0 ? endFrame / 30 : 0;

        if (!isPlaying && autoLoop) {
            await mmdRuntime.playAnimation();
            setIsPlaying(true);
        }
        setStatus(t('scene.vmd.loaded', { name }), true);
        triggerAutoSave();
    } catch (err) {
        console.error('VMD load failed:', err);
        setStatus(t('scene.vmd.loadFailed'), false);
    }
}

export async function loadVMDFromPath(
    path: string,
    targetModelId?: string,
    signal?: AbortSignal,
    skipSceneIntent?: boolean
): Promise<void> {
    const { focusedMmdModel, focusedModel } = await getScene();
    await withLoadingIndicator('scene.loader.vmdLoading', async () => {
        try {
            const vmdBytes = await readFileBytes(path);
            if (!vmdBytes) {
                return;
            }
            const vmdData = vmdBytes.buffer as ArrayBuffer;
            const vmdName = getBaseName(path) || '';
            const vmdDisplayName = vmdName.replace(/\.vmd$/i, '');

            if (mmdRuntime && (targetModelId || focusedMmdModel())) {
                await loadVMDMotion(
                    vmdData,
                    vmdName.replace(/\.vmd$/i, ''),
                    targetModelId,
                    signal,
                    path
                );
                const foc = targetModelId ? modelRegistry.get(targetModelId) : focusedModel();
                if (foc) {
                    foc.vmdPath = path;
                }
                // 璁剧疆鍦烘櫙绾ч粯璁ゅ姩浣滐紙瀹堝崼锛氶伩鍏嶅悓璺緞閲嶅瑙﹀彂骞挎挱锛塡n                // [fix:adr-167] skipSceneIntent 鏃惰烦杩囷細per-model 搴旂敤锛坅pplyIntentToModel /
                // 绋嬪簭鍖栧垏鍥烇級涓嶅簲瑙︾鍦烘櫙搴撱€俓n                // [adr-169] 鐢?replaceDefaultMotion 鍘熶綅鏇挎崲榛樿锛氭棫榛樿琚《鏇跨Щ闄わ紝
                // 鍏朵綑涓诲姩浣滀繚鐣欙紙鍙栦唬宸插簾寮冪殑 setActiveMotion 鍗曚緥娓呭簱璇箟锛夈€俓n                if (!skipSceneIntent) {
                    const cur = getActiveMotion();
                    if (!cur || cur.vmdPath !== path) {
                        replaceDefaultMotion({
                            vmdPath: path,
                            vmdName: vmdName.replace(/\.vmd$/i, ''),
                            vmdLayers: [],
                            source: 'vmd',
                        });
                    }
                }
            } else if (!skipSceneIntent) {
                replaceDefaultMotion({
                    vmdPath: path,
                    vmdName: vmdName.replace(/\.vmd$/i, ''),
                    vmdLayers: [],
                    source: 'vmd',
                });
                setStatus(t('scene.vmd.cachedAutoApply'), false);
            }

            // 璁板綍鏈€杩戜娇鐢ㄥ姩浣淺n            addRecentMotion(path, vmdDisplayName);

            // 灏濊瘯鍔犺浇鍚岀洰褰曚笅鐨勫悓鍚嶉煶棰戞枃浠禱n            const audioTargetId = targetModelId || focusedModelId;
            await _tryLoadCompanionAudio(path, path, audioTargetId);
        } catch (err) {
            // 涓锛圓bortError锛変笉绠楀け璐ワ細loadVMDMotion 鍦?signal 涓鏃舵姏姝ら敊锛孿n            // 姝ゆ椂 vmdPath/addRecentMotion/闊抽绛夊壇浣滅敤宸茶 throw 璺宠繃锛屾棤闇€鎶ラ敊 UI
            if ((err as DOMException)?.name === 'AbortError') {
                return;
            }
            console.error('loadVMDFromPath:', err);
            setStatus(t('scene.vmd.loadFailed'), false);
        }
    });
}

/** 灏濊瘯鍔犺浇 VMD 鍚岀洰褰曚笅鐨勫悓鍚嶉煶棰戞枃浠讹紙.mp3/.wav/.ogg/.flac锛夈€?*/
async function _tryLoadCompanionAudio(
    vmdPath: string,
    vmdUrl: string,
    targetModelId?: string
): Promise<void> {
    if (!isAutoLoadCompanionAudioEnabled()) {
        return;
    }
    // [doc:adr-057] vmdUrl 褰㈠ http://127.0.0.1:port/?f=<base64>
    // 鎻愬彇 origin+port 浣滀负闊抽鎺㈤拡鐨勫熀鍦板潃锛屾枃浠跺悕閫氳繃 ?f= 鏌ヨ鍙傛暟浼犻€抃n    const urlObj = new URL(vmdUrl);
    const baseOrigin = `${urlObj.protocol}//${urlObj.host}`;
    const basePath = vmdPath.replace(/\.vmd$/i, '');
    if (_companionAudioCache.has(basePath)) {
        return;
    }

    // 璁板綍鍔犺浇鍓嶇殑 generation 鍊硷紝鍔犺浇瀹屾垚鍚庢牎楠屾槸鍚﹁繃鏈焅n    // 锛堢敤鎴峰湪鍔犺浇鏈熼棿鍒囨崲浜?VMD 鍒欎涪寮冩湰娆′即闊崇粨鏋滐級
    const genBefore = _vmdLoadGenMap.get(targetModelId || '') ?? 0;

    const exts = ['.mp3', '.wav', '.ogg', '.flac', '.wma'];

    // 骞惰 HEAD 鎺㈤拡锛屽彇棣栦釜鎴愬姛鐨勬墿灞曞悕锛圥romise.any 鍙彇鏈€蹇殑鎴愬姛缁撴灉锛塡n    const probes = exts.map(async (ext) => {
        const audioPath = basePath + ext;
        const audioName = getBaseName(audioPath) || '';
        const probeUrl = `${baseOrigin}/?f=${encodeFileRef(audioName)}`;
        const resp = await fetch(probeUrl, { method: 'HEAD' });
        if (!resp.ok) {
