// 鈹€鈹€ 渚濊禆娉ㄥ叆锛氭墦鐮?wasm-layers-blender 鈫?scene.ts 鐨勯潤鎬佸惊鐜緷璧?鈹€鈹€
// vmd-layers.ts 鍦ㄨ皟鐢?setupWasmLayersBlender 鍓嶅繀椤昏皟鐢?initWasmLayersBlender銆俓n// 鎵€鏈夊紩鐢?scene.ts 鐨勫嚱鏁伴€氳繃 _requireDeps() 鑾峰彇锛岃€岄潪闈欐€?import銆俓n
interface BlenderDeps {
    scene: Scene;
    modelManager: ModelManager;
    loadVMDMotion: (data: ArrayBuffer, name: string, modelId?: string) => Promise<void>;
}

let _deps: BlenderDeps | null = null;

function _requireDeps(): BlenderDeps {
    if (!_deps) {
        throw new Error(
            'WASM layers blender not initialized 鈥?call initWasmLayersBlender before setupWasmLayersBlender'
        );
    }
    return _deps;
}

/** 鍒濆鍖?blender 鐨勫満鏅骇渚濊禆锛堝繀椤诲湪 setupWasmLayersBlender 涔嬪墠璋冪敤锛夈€俓n *  姝ゅ嚱鏁版墦鐮?wasm-layers-blender 鈫?scene.ts 鐨勫惊鐜緷璧栭摼銆?*/
export function initWasmLayersBlender(deps: BlenderDeps): void {
    _deps = deps;
}

export { DEFAULT_LAYER_BONE_FILTER } from './wasm-layers-config';

export interface WasmLayerConfig {
    id: string;
    data: ArrayBuffer;
    weight: number;
    boneFilter?: string[];
    name?: string;
}

interface WasmLayerEntry {
    evaluator: VmdEvaluator;
    weight: number;
    boneFilter: string[];
    name: string;
}

interface BlenderState {
    modelId: string;
    layers: Map<string, WasmLayerEntry>;
    enabled: boolean;
    baseAnimationName: string;
    animationFrame: number;
}

const _blenderStates = new Map<string, BlenderState>();

const VMD_FPS = 30;

// 鈹€鈹€ Pipeline vmd-layers 灞?鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
// 娉ㄥ唽涓€娆★紝鍦?bone-override 涔嬪墠鎵ц鎵€鏈夋椿璺冩ā鍨嬬殑 WASM 鍥惧眰娣峰悎銆俓nlet _vmdLayersRegistered = false;

function _ensureVmdLayersLayer(): void {
    if (_vmdLayersRegistered) {
        return;
    }
    _vmdLayersRegistered = true;
    getMotionPipeline().register({
        id: 'wasm-vmd-layers',
        stage: 'vmd-layers',
        order: 0,
        run: () => {
            for (const [modelId, state] of _blenderStates) {
                if (!state.enabled) {
                    continue;
                }
                const dt = _requireDeps().scene.deltaTime || 16.67;
                state.animationFrame += (dt / 1000) * VMD_FPS;
                _applyLayersBlending(modelId);
            }
        },
    });
}

// 鈹€鈹€ 鍏紑 API 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

export async function setupWasmLayersBlender(
    modelId: string,
    baseData: ArrayBuffer,
    baseName: string
): Promise<void> {
    teardownWasmLayersBlender(modelId);

    const inst = _requireDeps().modelManager.get(modelId);
    if (!inst?.mmdModel) {
        throw new Error(`Model ${modelId} not found`);
    }

    // 纭繚 vmd-layers 绠＄嚎娈靛凡娉ㄥ唽锛堝箓绛夛級
    _ensureVmdLayersLayer();

    _blenderStates.set(modelId, {
        modelId,
        layers: new Map(),
        enabled: true,
        baseAnimationName: baseName,
        animationFrame: 0,
    });

    await _requireDeps().loadVMDMotion(baseData, baseName, modelId);
}

export function teardownWasmLayersBlender(modelId: string): void {
    const state = _blenderStates.get(modelId);
    if (!state) {
        return;
    }

    // 鏃犵嫭绔?observer 闇€ dispose 鈥?鐢?Pipeline vmd-layers 灞傜粺涓€璋冨害
    for (const [, layer] of state.layers) {
        layer.evaluator.dispose();
    }
    state.layers.clear();

    _blenderStates.delete(modelId);
}

export function isWasmLayersBlenderActive(modelId: string): boolean {
    return _blenderStates.has(modelId) && _blenderStates.get(modelId)!.enabled;
}

export async function addWasmLayer(modelId: string, config: WasmLayerConfig): Promise<void> {
    const state = _blenderStates.get(modelId);
    if (!state) {
        throw new Error(`Blender not setup for model ${modelId}`);
    }

    if (state.layers.has(config.id)) {
        removeWasmLayer(modelId, config.id);
    }

    const evaluator = await createVmdEvaluator(config.data);
    state.layers.set(config.id, {
        evaluator,
        weight: config.weight,
        boneFilter: config.boneFilter ?? DEFAULT_LAYER_BONE_FILTER,
        name: config.name ?? config.id,
    });
}

export function removeWasmLayer(modelId: string, layerId: string): void {
    const state = _blenderStates.get(modelId);
    if (!state) {
        return;
    }

    const layer = state.layers.get(layerId);
    if (layer) {
        layer.evaluator.dispose();
        state.layers.delete(layerId);
    }
}

export function updateWasmLayerWeight(modelId: string, layerId: string, weight: number): void {
    const state = _blenderStates.get(modelId);
    if (!state) {
        return;
    }

    const layer = state.layers.get(layerId);
    if (layer) {
        layer.weight = clamp01(weight);
    }
}

// 鈹€鈹€ 鍐呴儴瀹炵幇 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

function _applyLayersBlending(modelId: string): void {
    const state = _blenderStates.get(modelId);
    if (!state || state.layers.size === 0) {
        return;
    }

    const inst = _requireDeps().modelManager.get(modelId);
    if (!inst?.mmdModel) {
        return;
    }

    const bones = inst.mmdModel.runtimeBones;
    if (!bones || bones.length === 0) {
        return;
    }

    const frame = state.animationFrame;

    const allFrames = new Map<string, Array<{ frame: any; weight: number }>>();

    for (const [, layer] of state.layers) {
        const frameMap = layer.evaluator.evalAllBones(frame);
        for (const [boneName, frameData] of frameMap) {
            if (!layer.boneFilter.includes('*') && !layer.boneFilter.includes(boneName)) {
                continue;
            }
            if (!allFrames.has(boneName)) {
                allFrames.set(boneName, []);
            }
            allFrames.get(boneName)!.push({ frame: frameData, weight: layer.weight });
        }
    }

    for (const [boneName, entries] of allFrames) {
        const bone = bones.find((b: IMmdRuntimeBone) => b.name === boneName);
        if (!bone || !_isWasmRuntime(bone)) {
            continue;
        }

        const totalWeight = entries.reduce((sum, e) => sum + e.weight, 0);
        if (totalWeight <= 0) {
            continue;
        }

        let blendedRot: Quaternion | null = null;
        let blendedPos: Vector3 | null = null;

        // 鏉冮噸娣峰悎锛氫娇鐢ㄧ疮绉潈閲?Slerp锛岄伩鍏嶉€愭 Slerp 鍋忓悜棣栧眰銆俓n        // 绗?i 灞傜殑 effectiveWeight = weight_i / totalWeight锛孿n        // 绱Н鏉冮噸 cumWeight 鐢ㄤ簬 Slerp 鐨勬彃鍊煎洜瀛?= effectiveWeight / (宸茬疮绉潈閲?銆俓n        let cumWeight = 0;
        for (const entry of entries) {
            const effectiveWeight = entry.weight / totalWeight;
            cumWeight += effectiveWeight;
            const { rotation, position } = entry.frame;

            if (blendedRot === null) {
                blendedRot = rotation.clone();
            } else {
                // 鎻掑€煎洜瀛?= 鏈眰鏉冮噸 / 绱Н鏉冮噸锛屼繚璇佸姞鏉冨钩鍧囪涔塡n                const t = effectiveWeight / cumWeight;
                blendedRot = Quaternion.Slerp(blendedRot, rotation, t);
            }

            if (position !== null) {
                if (blendedPos === null) {
                    blendedPos = position.clone();
                } else {
                    const t = effectiveWeight / cumWeight;
                    blendedPos.x += (position.x - blendedPos.x) * t;
                    blendedPos.y += (position.y - blendedPos.y) * t;
                    blendedPos.z += (position.z - blendedPos.z) * t;
                }
            }
        }

        if (blendedRot !== null) {
            const oldMat = Matrix.FromArray(bone.worldMatrix as Float32Array);

            const newMat = new Matrix();
            if (blendedPos !== null) {
                newMat.copyFrom(Matrix.Compose(Vector3.One(), blendedRot, blendedPos));
            } else {
                const pos = oldMat.getTranslation();
                newMat.copyFrom(Matrix.Compose(Vector3.One(), blendedRot, pos));
            }

            // perception.ts 鎵╁睍浜?MmdRuntimeBone 娣诲姞 worldMatrix 灞炴€э紝
            // babylon-mmd 绫诲瀷澹版槑鏈寘鍚鎵╁睍锛岄渶绫诲瀷鏂█
            const buf = (bone as MmdRuntimeBoneExtended).worldMatrix;
            _writeMatToBuffer(buf, newMat);

            _propagateChildrenWasm(bone, oldMat, newMat);
        }
    }
}

// [doc:architecture] Light Cone 鈥?鐪熷疄鍏夐敟缃戞牸 + ShaderMaterial锛堟浛浠?ADR-152 鐨勫睆骞曞悗澶勭悊鍋囦綋绉厜锛塡n// 鑱岃矗: 涓?SpotLight 鐢熸垚鍙閿ュ舰鍏夋煴锛岄檮鍔?blending + fresnel 杈圭紭杈夊厜
// 鍘熺悊: 閿ヤ綋 Mesh + 鑷畾涔?Shader锛坅dditive blending, 璺濈琛板噺 + 瑙嗚杈圭紭澧炲己锛塡n
import { MeshBuilder } from '@babylonjs/core/Meshes/meshBuilder';
import type { Mesh } from '@babylonjs/core/Meshes/mesh';
import { ShaderMaterial } from '@babylonjs/core/Materials/shaderMaterial';
import { Constants } from '@babylonjs/core/Engines/constants';
import { Vector3, Quaternion, Matrix } from '@babylonjs/core/Maths/math.vector';
import { Color3 } from '@babylonjs/core/Maths/math.color';
import type { Scene } from '@babylonjs/core/scene';
import type { SpotLight } from '@babylonjs/core/Lights/spotLight';
import { safeDispose } from '@/core/dispose-helpers';

// ======== Shader Sources ========

const CONE_VERT = /* glsl */ `
precision highp float;

attribute vec3 position;
attribute vec3 normal;

uniform mat4 world;
uniform mat4 worldViewProjection;

varying vec3 vWorldPos;
varying vec3 vNormal;

void main() {
    vec4 wp = world * vec4(position, 1.0);
    vWorldPos = wp.xyz;
    vNormal = normalize(mat3(world) * normal);
    gl_Position = worldViewProjection * vec4(position, 1.0);
}
`;

const CONE_FRAG = /* glsl */ `
precision highp float;

varying vec3 vWorldPos;
varying vec3 vNormal;

uniform vec3 u_color;
uniform float u_intensity;
uniform float u_softness;
uniform float u_coneLength;
uniform vec3 u_apexPos;
uniform vec3 u_cameraPos;

void main() {
    // 璺濋敟椤惰窛绂?鈫?褰掍竴鍖?t (0=椤剁偣, 1=搴曢潰)
    float dist = length(vWorldPos - u_apexPos);
    float t = clamp(dist / max(u_coneLength, 0.01), 0.0, 1.0);

    // 璺濈琛板噺锛氶潬杩戝厜婧愪寒锛岃繙绂绘笎闅怽n    float distFade = pow(1.0 - t, 1.5);

    // Fresnel 杈圭紭杈夊厜锛氳绾夸笌娉曠嚎瓒婂瀭鐩达紙杈圭紭锛夛紝瓒婁寒
    vec3 viewDir = normalize(u_cameraPos - vWorldPos);
    vec3 n = normalize(vNormal);
    float NdotV = abs(dot(n, viewDir));
    float fresnel = pow(1.0 - NdotV, 1.0 + u_softness * 2.0);

    // 鍚堟垚锛氬熀纭€鍙搴?+ 杈圭紭澧炲己
    float alpha = u_intensity * distFade * (0.12 + 0.88 * fresnel);
    alpha = clamp(alpha, 0.0, 1.0);

    gl_FragColor = vec4(u_color * alpha, alpha);
}
`;

// ======== Types ========

export interface LightConeEntry {
    mesh: Mesh;
    material: ShaderMaterial;
    /** 褰撳墠鍑犱綍瀵瑰簲鐨勯敟闀匡紙鍙樺寲鏃堕渶閲嶅缓鍑犱綍锛?*/
    geoLength: number;
    /** 褰撳墠鍑犱綍瀵瑰簲鐨勯敟瑙掞紙鍙樺寲鏃堕渶閲嶅缓鍑犱綍锛?*/
    geoAngle: number;
}

// ======== Geometry ========

/** 鍒涘缓閿ヤ綋缃戞牸锛氶《鐐瑰湪鍘熺偣锛屾部 +Y 寤朵几 */
function _createConeMesh(scene: Scene, coneLength: number, halfAngle: number): Mesh {
    const baseRadius = Math.tan(halfAngle) * coneLength;
    const cone = MeshBuilder.CreateCylinder(
        'lightCone',
        {
            height: coneLength,
            diameterTop: baseRadius * 2,
            diameterBottom: 0, // 閿ラ《鍦ㄥ簳閮╘n            tessellation: 48,
            subdivisions: 4,
        },
        scene
    );
    // 灏嗛敟椤讹紙鍘?y=-h/2锛夊钩绉诲埌鍘熺偣
    cone.bakeTransformIntoVertices(Matrix.Translation(0, coneLength / 2, 0));
    cone.isPickable = false;
    cone.renderingGroupId = 1; // 鍦ㄩ€忔槑鐗╀綋涔嬪悗娓叉煋
    return cone;
}

// ======== Material ========

function _createConeMaterial(scene: Scene): ShaderMaterial {
    const mat = new ShaderMaterial(
        'lightConeMat',
        scene,
        { vertexSource: CONE_VERT, fragmentSource: CONE_FRAG },
        {
            attributes: ['position', 'normal'],
            uniforms: [
                'world',
                'worldViewProjection',
                'u_color',
                'u_intensity',
                'u_softness',
                'u_coneLength',
                'u_apexPos',
                'u_cameraPos',
            ],
            needAlphaBlending: true,
        }
    );
    mat.alphaMode = Constants.ALPHA_ADD;
    mat.backFaceCulling = false; // 鍙岄潰娓叉煋 鈫?浣撶Н鎰焅n    mat.disableDepthWrite = true; // 涓嶅啓娣卞害锛堥伩鍏嶉伄鎸″叾浠栭€忔槑鐗╀綋锛塡n    return mat;
}

// ======== Orientation ========

/** 璁＄畻灏?+Y 瀵归綈鍒?dir 鐨勫洓鍏冩暟 */
function _alignYToDir(dir: Vector3): Quaternion {
    const up = Vector3.Up();
    const d = Vector3.Dot(up, dir);
    if (d > 0.9999) {
        return Quaternion.Identity();
    }
    if (d < -0.9999) {
        return Quaternion.RotationAxis(new Vector3(1, 0, 0), Math.PI);
    }
    const axis = Vector3.Cross(up, dir).normalize();
    const angle = Math.acos(Math.min(1, Math.max(-1, d)));
    return Quaternion.RotationAxis(axis, angle);
}

// ======== Public API ========

/**
 * 涓鸿仛鍏夌伅鍒涘缓鍏夐敟銆俓n * @param scene Babylon 鍦烘櫙
 * @param light 鑱氬厜鐏疄渚媆n * @param color 鍏夎壊
 * @param intensity 鍏夐敟浜害 (0-2)
 * @param coneLength 閿ラ暱
 * @param softness 杈圭紭鏌斿拰搴?(0-1)
 */
export function createLightCone(
    scene: Scene,
    light: SpotLight,
    color: Color3,
    intensity: number,
    coneLength: number,
    softness: number
): LightConeEntry {
    const halfAngle = light.angle / 2;
    const mesh = _createConeMesh(scene, coneLength, halfAngle);
    const material = _createConeMaterial(scene);
    mesh.material = material;

    // 鍒濆 transform
    _applyTransform(mesh, light);

    // 鍒濆 uniforms
    material.setColor3('u_color', color);
    material.setFloat('u_intensity', intensity);
    material.setFloat('u_softness', softness);
    material.setFloat('u_coneLength', coneLength);
    material.setVector3('u_apexPos', light.position.clone());

    return { mesh, material, geoLength: coneLength, geoAngle: light.angle };
}

/** 鏇存柊鍏夐敟鐨?transform锛堜綅缃?鏈濆悜锛夛紝姣忓抚鎴栫伅鍏夌Щ鍔ㄦ椂璋冪敤 */
export function updateLightConeTransform(
    entry: LightConeEntry,
    light: SpotLight,
    coneLength: number
): void {
    _applyTransform(entry.mesh, light);
    // 澶嶇敤妯″潡绾у璞★紝閬垮厤姣忓抚 clone 浜х敓 GC 鍘嬪姏
    _tmpApex.x = light.position.x;
    _tmpApex.y = light.position.y;
    _tmpApex.z = light.position.z;
    entry.material.setVector3('u_apexPos', _tmpApex);
}

/** 鏇存柊鍏夐敟鐨?shader uniforms锛堥鑹?浜害/鏌斿拰搴︼級 */
export function updateLightConeUniforms(
    entry: LightConeEntry,
    color: Color3,
    intensity: number,
    softness: number,
    coneLength: number
): void {
    entry.material.setColor3('u_color', color);
    entry.material.setFloat('u_intensity', intensity);
    entry.material.setFloat('u_softness', softness);
    entry.material.setFloat('u_coneLength', coneLength);
}

/** 閿ラ暱/閿ヨ鍙樺寲鏃堕噸寤哄嚑浣?*/
export function rebuildLightConeGeometry(
    entry: LightConeEntry,
    scene: Scene,
    light: SpotLight,
    coneLength: number
): void {
    const halfAngle = light.angle / 2;
    // 浠呭湪鍙傛暟瀹為檯鍙樺寲鏃堕噸寤篭n    if (
        Math.abs(entry.geoLength - coneLength) < 0.01 &&
        Math.abs(entry.geoAngle - light.angle) < 0.001
    ) {
        return;
    }
    // 閲嶅缓鍑犱綍锛堜繚鐣欐潗璐級
    const oldMesh = entry.mesh;
    const newMesh = _createConeMesh(scene, coneLength, halfAngle);
    newMesh.material = entry.material;
    newMesh.setEnabled(oldMesh.isEnabled());
    safeDispose(oldMesh);
    entry.mesh = newMesh;
    entry.geoLength = coneLength;
    entry.geoAngle = light.angle;
    _applyTransform(newMesh, light);
}

/** 璁剧疆鍏夐敟鍙鎬?*/
export function setLightConeEnabled(entry: LightConeEntry, enabled: boolean): void {
    entry.mesh.setEnabled(enabled);
}

/** 閲婃斁鍏夐敟璧勬簮锛堝厛 mesh 鍚?material锛岄伩鍏?mesh.dispose 鍐呴儴寮曠敤宸查噴鏀炬潗璐級 */
export function disposeLightCone(entry: LightConeEntry): void {
    safeDispose(entry.mesh);
    safeDispose(entry.material);
}

// ======== Internal ========

/** 妯″潡绾т复鏃跺悜閲忥紙閬垮厤 updateLightConeTransform 姣忓抚 clone 浜х敓 GC 鍘嬪姏锛?*/
const _tmpApex = { x: 0, y: 0, z: 0 };

function _applyTransform(mesh: Mesh, light: SpotLight): void {
    mesh.position.copyFrom(light.position);
    // SpotLight.direction 宸插綊涓€鍖栵紝鐩存帴瀵归綈
    const dir = light.direction.normalize();
    mesh.rotationQuaternion = _alignYToDir(dir);
}

