                }
                return { primary };
            })(),
            // [fix:material-persist] 钀界洏鏉愯川鐘舵€侊紙浠呴潪 null 鎵嶅啓锛岄伩鍏嶉粯璁ゅ€煎櫔澹帮級
            ...(() => {
                const ms = getMatState(inst.id);
                if (!ms) {
                    return {};
                }
                return {
