                activeMotionId,
            };
        })(),
        // [doc:adr-108] 搴忓垪鍖栧綋鍓嶆椿璺冪殑 retarget 鍔ㄧ敾鐘舵€乗n        retarget: (() => {
            const state = getRetargetPlayState();
            if (!state) {
