    modelManager.onRemoveModel = (id) => {
        // 绋嬪簭鍖栧姩浣滄竻鐞嗭紙瑙嗙嚎杩借釜 observer 鎷嗛櫎锛夊繀椤绘棭浜?destroyMmdModel
        // 鍚﹀垯涓嬩竴甯?observer 鍚屾椂璇诲埌 _procVmdActive=true + mmdModel 宸查攢姣?鈫?skeleton null 鈫?TypeError
        // 瑙?proc-motion-bridge.ts onModelRemoved
        onModelRemoved(id);

        // [doc:adr-168] 閲婃斁瑙掕壊涓撳睘涓汉鐏痋n        detachPersonalLight(id);

        // 鍚屾閿€姣?MMD 妯″瀷锛氬繀椤诲湪缃戞牸閲婃斁 / modelRegistry.delete 涔嬪墠鎵ц
        // 锛堣 model-manager.ts remove() 鐨勮皟鐢ㄩ『搴忥級锛屼笖蹇呴』鏃╀簬涓嬫柟涓変釜 fire-and-forget 娓呯悊銆俓n        // 涓嬫柟鍔ㄦ€?import 浠呫€岃皟搴︺€峆romise锛屽叾 .then 浣撳湪寰换鍔′腑浜庢湰鍚屾鍧楃粨鏉熷悗銆佸嵆 destroyMmdModel 涔嬪悗鎵嶈繍琛屻€俓n        const inst = modelRegistry.get(id);
        if (inst?.mmdModel && mmdRuntime) {
            try {
                mmdRuntime.destroyMmdModel(inst.mmdModel);
            } catch (e) {
                logWarn('scene', 'removeModel: destroyMmdModel failed', e);
            }
        }

        // 涓変釜娓呯悊鍧囦负 fire-and-forget锛氬湪 destroyMmdModel 涔嬪悗锛堝井浠诲姟锛夋墠鐪熸鎵ц銆俓n        // 鏄惧紡濂戠害锛氬畠浠彧鎿嶄綔鍚勮嚜鐙珛鐨?registry锛坃blenderStates / propRegistry / controllers锛夛紝
        // 缁濅笉璁块棶宸查攢姣佺殑 mmdModel 鎴?modelRegistry.get(id)銆俓n        // 鑻ユ湭鏉ヤ慨鏀逛换涓€瀹炵幇銆佹柊澧炲妯″瀷鐨勮闂紝蹇呴』鍏堝姞 modelRegistry.get(id) 瀹堝崼銆俓n        // WASM 鍥惧眰娣峰悎鍣?teardown锛坥bserver + evaluator 娓呯悊锛塡n        swallowError(
            import('./motion/wasm-layers-blender').then(({ teardownWasmLayersBlender }) => {
                if (scene.isDisposed) {
                    return;
                }
                teardownWasmLayersBlender(id);
            })
        );

        // 瑙ｉ櫎姝ゆā鍨嬩笂鐨勬墍鏈夐楠奸敋瀹氶亾鍏穃n        swallowError(
            import('./env/accessory').then(({ detachModelAccessories }) => {
                if (scene.isDisposed) {
                    return;
                }
                detachModelAccessories(id);
            })
        );

        // ADR-084 P3b: 妯″瀷鍗歌浇鏃堕噴鏀捐妯″瀷鐨勮櫄鎷熻楠ㄦ帶鍒跺櫒锛岄伩鍏?dispose 娉勬紡銆俓n        // 缁忓姩鎬?import锛坢otion-cloth-levels 鍐呴儴浠嶄互 await import 鍔犺浇 virtual-skirt锛夛紝
        // 涓嶇牬鍧?ADR-081/084 鐨?virtual-skirt 闈?eager 瀵煎叆绾︽潫銆俓n        swallowError(
            import('../menus/motion-cloth-levels').then(({ disposeVirtualSkirtForModel }) => {
                if (scene.isDisposed) {
                    return;
                }
                disposeVirtualSkirtForModel(id);
            })
        );
    };
    setModelRegistry(modelManager.modelRegistry);
    setTriggerAutoSave(triggerAutoSaveImpl);

    // 5. 娉ㄥ叆鍥炶皟瑙ｈ€︼細model-loader / model-manager 涓嶅啀鐩存帴鍔ㄦ€佸鍏?renderer / proc-motion-bridge
    setOnMeshesReady((meshes) => onModelMeshesReady(meshes));
    const procMotionMod = await import('./motion/proc-motion-bridge');
    const { activatePerception } = await import('./motion/perception');
    modelManager.onModelFocused = () => procMotionMod.activateGazeTracking();
    setOnModelLoaded((id) => {
        procMotionMod.activateGazeTracking();
        // [doc:adr-164] 鏂版ā鍨嬪姞杞芥椂鑷姩婵€娲绘劅鐭ュ眰锛堝叏鍛樻劅鐭ユā寮忎笅婵€娲绘墍鏈夋ā鍨嬶級
        activatePerception(id);
        // [doc:adr-168] 瑙掕壊妯″瀷鑷姩鑾峰緱涓撳睘涓汉鐏痋n        const inst = modelRegistry.get(id);
        if (inst?.kind === 'actor') {
            attachPersonalLight(id);
        }
    });

    // 6. Loader锛堝繀椤诲湪 modelManager + setTriggerAutoSave 涔嬪悗锛塡n    // 鐮撮櫎寰幆渚濊禆锛歴cene.ts 涓嶅啀闈欐€?import outfit / model-preset锛孿n    // 鏀瑰湪 initScene(async) 鍐呭姩鎬?import锛堝悓 scene.ts:187锛宎dr-053/adr-064锛夈€俓n    const outfitMod = await import('../outfit/outfit');
    const presetMod = await import('../menus/model-preset');
    initLoader(
        scene,
        runtime,
        modelManager,
        refreshWaterRenderList,
        presetMod.tryAutoApplyPreset,
        (id: string) => outfitMod.loadOutfits(id).then(() => {}),
        rebuildOutlineState
    );
    _disposePlaybackObservables = initPlaybackObservables(
        runtime,
        modelManager,
        updatePlaybackUI,
        updateProcMotion,
        getProcBeatDetector
    );

    // 6. 搴旂敤鍒濆鐜鐘舵€乗n    applyEnvState(envState);
    _updateSunDisc();

    // 鏃?VMD 鏃朵篃鑳介┍鍔ㄧ▼搴忓寲鍔ㄤ綔鍜屽彛鍨嬪悓姝?鈥?宸茬敱 onAnimationTickObservable 椹卞姩锛坧layback.ts锛夛紝
    // 姝ゅ涓嶅啀閲嶅娉ㄥ唽锛岄伩鍏嶆瘡甯т袱娆?updateProcMotion 瀵艰嚧绔炴€侊紙startProcMotion 鍙嶅閲嶈浇锛夈€俓n    // scene.onBeforeRenderObservable.add(() => {
    //     swallowError(updateProcMotion());
    // });

    // 鐐瑰嚮姘撮潰 鈫?鐢熸垚娑熸吉
    scene.onPointerObservable.add((info) => {
        if (info.type !== PointerEventTypes.POINTERDOWN) {
            return;
        }
        if (!envState.waterEnabled) {
            return;
        }
        if (info.pickInfo.hit) {
            return;
        }
        const ray = info.pickInfo.ray;
        if (!ray || ray.direction.y >= 0) {
            return;
        }
        const waterY = envState.waterLevel;
        const camY = scene.activeCamera.globalPosition.y;
        if (camY === undefined || camY <= waterY) {
            return;
        }
        const t = (waterY - ray.origin.y) / ray.direction.y;
        if (t <= 0) {
            return;
        }
        const hit = ray.origin.add(ray.direction.scale(t));
        const half = envState.waterSize / 2;
        if (Math.abs(hit.x) > half || Math.abs(hit.z) > half) {
            return;
        }
        addRipple(hit, 5, 0.6, 2, 2.5);
    }, PointerEventTypes.POINTERDOWN);

    // [doc:adr-171] 鍦烘櫙绾ф嫋鎷芥ā寮忥細鐐瑰嚮鐗╀綋 鈫?闄勫姞 Gizmo
    let _dragModePointerDownX = 0;
    let _dragModePointerDownY = 0;
    scene.onPointerObservable.add((info) => {
        if (!isDragModeEnabled()) {
            return;
        }
        if (info.type === PointerEventTypes.POINTERDOWN) {
            _dragModePointerDownX = info.event.clientX;
            _dragModePointerDownY = info.event.clientY;
            return;
        }
        if (info.type !== PointerEventTypes.POINTERUP) {
            return;
        }
        if (isGizmoDragging()) {
            return;
        }
        const dx = info.event.clientX - _dragModePointerDownX;
        const dy = info.event.clientY - _dragModePointerDownY;
        if (dx * dx + dy * dy > 25) {
            return;
        }
        tryAttachGizmoFromPick(scene, scene.pointerX, scene.pointerY);
    }, PointerEventTypes.POINTERDOWN | PointerEventTypes.POINTERUP);

    // 7. 鑴氶儴璋冩暣绯荤粺鍚姩锛圓DR-085锛塡n    // 娉ㄥ唽涓?Pipeline bone-override 灞傦紙order=5锛夛紝鍦ㄥ抚閽╁瓙锛圧IDING=10锛変箣鍓嶆墽琛孿n    const { startFeetAdjustment } = await import('./motion/feet-adjustment');
    startFeetAdjustment(
        (): { id: string; feet: FeetState; runtimeBones: readonly IMmdRuntimeBone[] }[] => {
            const out: { id: string; feet: FeetState; runtimeBones: readonly IMmdRuntimeBone[] }[] =
                [];
            for (const inst of modelRegistry.values()) {
                const bones = inst.mmdModel?.runtimeBones;
                if (bones && bones.length > 0) {
                    out.push({ id: inst.id, feet: inst.feet, runtimeBones: bones });
                }
            }
            return out;
        }
    );

    // 7.5 鑴氭澹扮郴缁熷惎鍔紙ADR-088锛夛細娑堣垂 feet-adjustment 钀藉湴浜嬩欢鍙戝０
    // 蹇呴』鍦?startFeetAdjustment 涔嬪悗娉ㄥ唽锛堣惤鍦颁簨浠剁敱鑴氶儴璺熼殢浜х敓锛塡n    const { startFootstep } = await import('./motion/footstep');
    startFootstep(scene);

    // 8. Bone Override 绯荤粺鍚姩
    // 娉ㄥ唽 onBeforeRenderObservable 鍥炶皟锛屽湪鍔ㄧ敾搴旂敤鍚庨€愰楠艰鐩朶n    const { startBoneOverride } = await import('./motion/bone-override');
    startBoneOverride(() => {
        const id = focusedModelId;
        if (!id) {
            return [];
        }
        const inst = modelRegistry.get(id);
        return inst?.mmdModel?.runtimeBones ?? [];
    }, scene);

    // [doc:adr-116] 9. Motion Override Modules 娉ㄥ唽锛堜富鍒濆鍖栬矾寰勶級
    // 蹇呴』鍦?focusModel 鍙兘琚皟鐢ㄤ箣鍓嶅畬鎴愶紱registry 鍐?setTargetModel/createModule 涔熸湁骞傜瓑鍏滃簳
    const { initMotionModules } = await import('./motion/motion-modules/registry');
    initMotionModules();

    // [ADR-159 P3-A] 娉ㄥ叆娓叉煋妗ユ帴锛氬崟鍚戜緷璧?scene 鈫?performance锛孿n    // 娑堥櫎 performance.ts 瀵?scene.ts 鐨勯潤鎬?import锛堟祴璇曞彲鐙珛 mock bridge锛夈€俓n    // 椤诲湪棣栧抚 updatePerformance() 鍓嶆敞鍐岋紱HMR 閲嶅叆鏃?engine 宸查噸寤猴紝姝ゅ閲嶆柊娉ㄥ叆鏈€鏂板紩鐢ㄣ€俓n    registerRenderBridge({ engine, setLightState, setRenderState, getLightState, getRenderState });

    // 鏍囪棣栨鍒濆鍖栧畬鎴愶紝HMR 閲嶅叆鏃惰Е鍙?disposeScene() + 閲嶅缓璺緞
    _sceneInitialized = true;

    setTriggerAutoSave(triggerAutoSaveImpl);
}

// ======== 蹇嵎 getter ========
export function getScene(): Scene {
    return scene;
}

// ======== AR Camera Mode (delegated to ar/ar-scene.ts) ========
export { setARMode, takeARScreenshot, isARModeActive } from './ar/ar-scene';

// Re-exports from extracted sub-modules (zero-change for consumers)
export {
    loadVMDMotion,
    loadVMDFromPath,
    loadCameraVmdFromPath,
    loadVPDPose,
} from './motion/vmd-loader';
export { updatePlaybackUI, seekFromEvent, initPlaybackObservables } from './motion/playback';
export {
    dom,
    setStatus,
    formatTime,
    setMmdRuntime,
    mmdRuntime,
    modelRegistry,
    focusedModelId,
    setFocusedModelId,
    isPlaying,
    setIsPlaying,
    autoLoop,
    setAutoLoop,
    seekDragging,
    setSeekDragging,
    setModelRegistry,
    propRegistry,
    envState,
    triggerAutoSave,
    setTriggerAutoSave,
} from '../core/config';
export type { EnvState, ModelInstance, PropInstance } from '../core/config';
export { resolveFileUrl, normPath } from '../core/fileservice';
export {
    pushUndoSnapshot,
    popUndoSnapshot,
    restoreUndoSnapshot,
    offerSceneUndo,
    offerSceneUndoAndRefresh,
    canUndo,
} from './scene-serialize';
export { applyEnvState } from './env/env';
export * from './motion/proc-motion-bridge';
export * from './motion/lipsync-bridge';
export * from './env/props';
export * from './scene-serialize';
export * from './env/env-bridge';
export * from './render/lighting';
export * from './render/renderer';
export * from './manager/model-ops';
export { loadPMXFile, captureThumbnail, initLoader } from './manager/model-loader';
export {
    initCameraSystem,
    autoFrame,
    getCameraState,
    setCameraState,
    animateCameraVmd,
    loadCameraVmd,
    clearCameraVmd,
    hasCameraVmd,
    getCameraVmdName,
    getCameraVmdPath,
    switchCameraMode,
    getCameraMode,
} from './camera/camera';
export type { CameraState } from './camera/camera';
export {
    syncAudioPlayback,
    loadAudioFile,
    attachBeatDetector,
    disposeAudio,
    isAudioPlaying,
} from '../outfit/audio';
export { SaveThumbnail, SaveLastScene, LoadLastScene, SetEnvState } from '../core/wails-bindings';
export type { LightState, StageLightState } from './render/lighting';
export type { RenderState } from './render/renderer';

