/**
 * MikuMikuAR 鈥?Web Loader 鍘熷瀷
 * 绾祻瑙堝櫒绔?PMX 鍔犺浇鍣紝闆跺悗绔緷璧栥€俓n *
 * 鐢ㄦ硶锛歯pm run dev 鈫?鎵撳紑 http://127.0.0.1:5173/web-loader.html
 * 鎷栨嫿 .pmx 鎴?.zip 鏂囦欢鍗冲彲鍔犺浇銆俓n */

// ======== Babylon.js 鏍稿績 ========
import { Engine } from '@babylonjs/core/Engines/engine';
import { Scene } from '@babylonjs/core/scene';
import { ArcRotateCamera } from '@babylonjs/core/Cameras/arcRotateCamera';
import { HemisphericLight } from '@babylonjs/core/Lights/hemisphericLight';
import { DirectionalLight } from '@babylonjs/core/Lights/directionalLight';
import { Vector3 } from '@babylonjs/core/Maths/math.vector';
import { Color3, Color4 } from '@babylonjs/core/Maths/math.color';
import { ImportMeshAsync } from '@babylonjs/core/Loading/sceneLoader';
import { CreateGround } from '@babylonjs/core/Meshes/Builders/groundBuilder';
import { Mesh } from '@babylonjs/core/Meshes/mesh';
import type { AbstractMesh } from '@babylonjs/core/Meshes/abstractMesh';
import '@babylonjs/core/Loading/loadingScreen';

// ======== 娉ㄥ唽 babylon-mmd PMX 鍔犺浇鍣?+ 榛樿鏉愯川鏋勫缓鍣?========
// 娉ㄦ剰锛氬繀椤诲厛璁?SharedMaterialBuilder锛屽啀鍒涘缓鍏ㄥ眬 PmxLoader
import 'babylon-mmd/esm/Loader/mmdModelLoader.default';
import 'babylon-mmd/esm/Loader/pmxLoader';

// ======== ADR-117 澶氳瑷€閿欒缈昏瘧锛坱ranslateGoError锛?========
import { translateGoError } from '../core/i18n/goerr';

// ======== JSZip锛堟祻瑙堝櫒绔?zip 瑙ｅ帇锛?========
import * as JSZip from 'jszip';

// ======== DOM 寮曠敤 ========
const canvas = document.getElementById('renderCanvas') as HTMLCanvasElement;
const dropZone = document.getElementById('dropZone') as HTMLDivElement;
const statusBar = document.getElementById('statusBar') as HTMLDivElement;
const modelNameEl = document.getElementById('modelName') as HTMLDivElement;
const modelStatsEl = document.getElementById('modelStats') as HTMLDivElement;
const fileInput = document.getElementById('fileInput') as HTMLInputElement;

// ======== IArrayBufferFile 绫诲瀷锛坆abylon-mmd 鍐呴儴鎺ュ彛锛屾澶勯噸澶嶅畾涔夐伩鍏?import 姝т箟锛?========
interface IArrayBufferFile {
    readonly relativePath: string;
    readonly mimeType: string | undefined;
    readonly data: ArrayBuffer;
}

// ======== 鍦烘櫙鐘舵€?========
let engine: Engine;
let scene: Scene;
let _loadedMeshes: AbstractMesh[] = [];

// ======== 鍒濆鍖栧満鏅?========
function initScene(): void {
    engine = new Engine(canvas, true, {
        preserveDrawingBuffer: true,
        stencil: true,
    });

    scene = new Scene(engine);
    scene.clearColor = new Color4(0.08, 0.08, 0.12, 1.0);

    // 鎽勫儚鏈篭n    const camera = new ArcRotateCamera(
        'camera',
        -Math.PI / 2,
        Math.PI / 3,
        8,
        Vector3.Zero(),
        scene
    );
    camera.lowerRadiusLimit = 1.5;
    camera.upperRadiusLimit = 50;
    camera.attachControl(canvas, true);

    // 鐏厜
    const hemi = new HemisphericLight('hemi', new Vector3(0, 1, 0), scene);
    hemi.intensity = 0.5;
    hemi.diffuse = new Color3(0.8, 0.85, 1.0);
    hemi.groundColor = new Color3(0.3, 0.3, 0.4);

    const dir = new DirectionalLight('dir', new Vector3(0.5, -1, 0.3), scene);
    dir.intensity = 0.9;
    dir.diffuse = new Color3(1, 0.98, 0.95);

    // 鍦伴潰锛堜笉鍙锛屼粎浣滃弬鑰冪郴锛塡n    const ground = CreateGround('ground', { width: 20, height: 20, subdivisions: 2 }, scene);
    ground.position.y = 0;
    ground.isVisible = false;

    engine.runRenderLoop(() => scene.render());
    window.addEventListener('resize', () => engine.resize());

    setStatus('灏辩华锛屾嫋鎷芥枃浠跺紑濮?);
}

// ======== 娓呯悊鏃фā鍨?========
function clearScene(): void {
    for (const m of _loadedMeshes) {
        try {
            m.dispose(false, true);
        } catch {
            // ignore
        }
    }
    _loadedMeshes = [];
    modelNameEl.textContent = '鈥?;
    modelStatsEl.textContent = '绛夊緟鍔犺浇鈥?;
}

// ======== 鍔犺浇 PMX ========
async function loadModel(
    pmxBuffer: ArrayBuffer,
    textures: IArrayBufferFile[],
    modelName: string
): Promise<void> {
    if (!scene) {
        return;
    }

    setStatus('姝ｅ湪鍔犺浇妯″瀷鈥?);
    clearScene();

    try {
        // 鐩存帴浼?ArrayBufferView + referenceFiles 缁?ImportMeshAsync
        // babylon-mmd 鐨?PmxLoader 璇嗗埆 ArrayBufferView 鍚庝笉璧?HTTP 璇锋眰
        const view = new Uint8Array(pmxBuffer);
        const result = await (ImportMeshAsync as any)(view, scene, {
            pluginExtension: '.pmx',
            pluginOptions: {
                mmdmodel: {
                    referenceFiles: textures as unknown as File[],
                },
            },
        });

        const meshes = result.meshes.filter((m): m is Mesh => m instanceof Mesh);
        _loadedMeshes = meshes;

        if (meshes.length === 0) {
            setStatus('妯″瀷鍔犺浇瀹屾垚锛屼絾鏈敓鎴愮綉鏍?);
            return;
        }

        // 鎵炬牴 mesh
        let rootMesh: Mesh | null = null;
        for (const m of meshes) {
            if ((m.metadata as any)?.isMmdModel) {
                rootMesh = m;
                break;
            }
        }
        if (!rootMesh) {
            rootMesh = meshes[0];
        }

        // 灞呬腑 + 璐村湴
        const bb = rootMesh.getHierarchyBoundingVectors(true);
        const size = bb.max.subtract(bb.min);
        const center = bb.max.add(bb.min).scale(0.5);

        rootMesh.position.x = -center.x;
        rootMesh.position.z = -center.z;
        rootMesh.position.y = -bb.min.y;

        // 鑷姩缂╂斁锛氱洰鏍囬珮搴?12 鍗曚綅
        const h = size.y;
        if (h > 0.01 && h < 50) {
            rootMesh.scaling = new Vector3(12 / h, 12 / h, 12 / h);
        }

        // 鏇存柊淇℃伅
        const displayName = modelName.replace(/\.pmx$/i, '');
        modelNameEl.textContent = displayName;
        modelStatsEl.textContent = `${meshes.length} 涓綉鏍?路 ${textures.length} 涓汗鐞哷;

        setStatus(`鉁?鍔犺浇瀹屾垚锛?{displayName}`);
    } catch (err) {
        console.error('loadModel failed:', err);
        setStatus(`鉂?鍔犺浇澶辫触锛?{translateGoError(err)}`);
    }
}

// ======== 澶勭悊鏂囦欢 ========

/** 浠?FileSystemDirectoryEntry 閫掑綊璇诲彇鎵€鏈夋枃浠?*/
async function readDirRecursive(entry: FileSystemDirectoryEntry, pathPrefix = ''): Promise<File[]> {
    const reader = entry.createReader();
    const files: File[] = [];
    // readEntries 闇€澶氭璋冪敤鐩村埌杩斿洖绌烘暟缁刓n    let entries: FileSystemEntry[];
    do {
        entries = await new Promise((resolve, reject) => reader.readEntries(resolve, reject));
        for (const e of entries) {
            if (e.isFile) {
                const fe = e as FileSystemFileEntry;
                const file = await new Promise<File>((resolve, reject) => fe.file(resolve, reject));
                // 鐢ㄧ浉瀵硅矾寰勯噸鍐欐枃浠跺悕锛屼緵 ReferenceFileResolver 鍖归厤
                const relativeName = pathPrefix + e.name;
                // 娉細File 鏋勯€犲櫒涓嶆敮鎸佹敼 webkitRelativePath锛屾垜浠敤 IArrayBufferFile 浼犻€掕矾寰刓n                // 浣嗚繖閲屼繚鐣?File 瀵硅薄渚夸簬绫诲瀷鍏煎锛屽悗缁?handleRawFiles 浼氱敤瀹為檯璺緞
                Object.defineProperty(file, 'webkitRelativePath', { value: relativeName });
                files.push(file);
            } else if (e.isDirectory) {
                const subFiles = await readDirRecursive(
                    e as FileSystemDirectoryEntry,
                    pathPrefix + e.name + '/'
                );
                files.push(...subFiles);
            }
        }
    } while (entries.length > 0);
    return files;
}

/** 浠?File 鎴?File[] 涓彁鍙?PMX + 绾圭悊锛岃皟鐢?loadModel */
async function handleRawFiles(rawFiles: File[]): Promise<void> {
    let pmxBuffer: ArrayBuffer | null = null;
    let pmxName = '';
    const textures: IArrayBufferFile[] = [];

    // 鍏堟壘 .pmx锛屽啀鏀堕泦绾圭悊鈥斺€旈兘鐢?webkitRelativePath 鎴?name 浣滀负鐩稿璺緞
    for (const file of rawFiles) {
        const relPath = (file as any).webkitRelativePath || file.name;
        if (/\.pmx$/i.test(relPath)) {
            pmxBuffer = await file.arrayBuffer();
            pmxName = relPath;
            break;
        }
    }
    if (!pmxBuffer) {
        setStatus('鉂?鏈壘鍒?.pmx 鏂囦欢');
        return;
    }

    for (const file of rawFiles) {
        const relPath = (file as any).webkitRelativePath || file.name;
        if (/\.(png|jpg|jpeg|bmp|tga|dds|tif|tiff)$/i.test(relPath)) {
            textures.push({
                relativePath: relPath,
                mimeType: getMimeType(relPath),
                data: await file.arrayBuffer(),
            });
        }
    }

    setStatus(`鎵惧埌 ${pmxName}锛?{textures.length} 涓汗鐞嗭紝鍔犺浇涓€);
    await loadModel(pmxBuffer, textures, pmxName);
}

async function handleFile(file: File): Promise<void> {
    if (file.name.endsWith('.pmx')) {
        // 鍗?PMX 鏂囦欢锛氱汗鐞嗘棤娉曞姞杞斤紙鏃犲搴斿浘鐗囨枃浠讹級
        const buffer = await file.arrayBuffer();
        await loadModel(buffer, [], file.name);
    } else if (file.name.endsWith('.zip')) {
        setStatus('姝ｅ湪瑙ｅ帇 ZIP鈥?);
        const zip = await JSZip.loadAsync(file);

        let pmxBuffer: ArrayBuffer | null = null;
        let pmxName = '';
        const textures: IArrayBufferFile[] = [];

        const files = zip.files as Record<
            string,
            { dir: boolean; async: (t: 'arraybuffer') => Promise<ArrayBuffer> }
        >;
        const allNames = Object.keys(files);

        // 浼樺厛鎵?.pmx
        for (const name of allNames) {
            const entry = files[name];
            if (entry.dir) {
                continue;
            }
            if (/\.pmx$/i.test(name)) {
                pmxBuffer = await entry.async('arraybuffer');
                pmxName = name;
                break;
            }
        }
        if (!pmxBuffer) {
            setStatus('鉂?ZIP 涓湭鎵惧埌 .pmx 鏂囦欢');
            return;
        }

        // 鏀堕泦绾圭悊
        for (const name of allNames) {
            const entry = files[name];
            if (entry.dir) {
                continue;
            }
            if (/\.(png|jpg|jpeg|bmp|tga|dds|tif|tiff)$/i.test(name)) {
                textures.push({
                    relativePath: name,
                    mimeType: getMimeType(name),
                    data: await entry.async('arraybuffer'),
                });
            }
        }

        setStatus(`鎵惧埌 ${pmxName}锛?{textures.length} 涓汗鐞嗭紝鍔犺浇涓€);
        await loadModel(pmxBuffer, textures, pmxName);
    } else {
        setStatus('鈿狅笍 璇锋嫋鎷?.pmx 鎴?.zip 鏂囦欢');
    }
}

function getMimeType(name: string): string {
    const ext = name.split('.').pop()?.toLowerCase();
    const map: Record<string, string | undefined> = {
        png: 'image/png',
        jpg: 'image/jpeg',
        jpeg: 'image/jpeg',
        bmp: 'image/bmp',
        tga: 'image/x-tga',
        dds: 'image/vnd-ms.dds',
        tif: 'image/tiff',
        tiff: 'image/tiff',
    };
    return map[ext ?? ''] ?? 'application/octet-stream';
}

// ======== UI 鐘舵€?========
function setStatus(msg: string): void {
    statusBar.textContent = `[${new Date().toLocaleTimeString()}] ${msg}`;
}

function showDropZone(show: boolean): void {
    dropZone.classList.toggle('hidden', !show);
}

// ======== 鎷栨嫿浜嬩欢 ========
dropZone.addEventListener('dragover', (e) => {
    e.preventDefault();
    dropZone.classList.add('dragover');
});
dropZone.addEventListener('dragleave', () => {
    dropZone.classList.remove('dragover');
});
dropZone.addEventListener('drop', async (e) => {
    e.preventDefault();
    dropZone.classList.remove('dragover');

    const items = e.dataTransfer?.items;
    const files = e.dataTransfer?.files;

    // 浼樺厛鐢?items API 妫€娴嬫枃浠跺す
    if (items?.length) {
        const item = items[0];
        const entry = item.webkitGetAsEntry?.();
        if (entry?.isDirectory) {
            setStatus('姝ｅ湪璇诲彇鏂囦欢澶光€?);
            const rawFiles = await readDirRecursive(entry as FileSystemDirectoryEntry);
            if (rawFiles.length > 0) {
                await handleRawFiles(rawFiles);
                showDropZone(false);
            }
            return;
        }
    }

    // 鏅€氭枃浠禱n    const file = files?.[0];
    if (file) {
        void handleFile(file);
        showDropZone(false);
    }
});

// 鐐瑰嚮閫夋嫨鏂囦欢锛堜粎鏂囦欢锛屼笉鏀寔鏂囦欢澶癸級
dropZone.addEventListener('click', () => {
    fileInput.click();
});
fileInput.addEventListener('change', () => {
    const file = fileInput.files?.[0];
    if (file) {
        void handleFile(file);
        showDropZone(false);
    }
    fileInput.value = '';
});

